{
  "name": "LocalityMind - Strategic Market Intelligence",
  "description": "AI-powered market feasibility tool for estimating store revenue, footfall, and demographic per capita income based on spatial and socioeconomic data.",
  "requestFramePermissions": [
    "camera",
    "geolocation"
  ]
}

export interface RevenueProjections {
  monthly: number;
  quarterly: number;
  yearly: number;
  currency: string;
}

export interface AreaDemographics {
  perCapitaIncome: number;
  socioeconomicTier: 'High' | 'Upper-Mid' | 'Mid' | 'Lower-Mid' | 'Economic';
  dominantCarTypes: string[];
  populationDensity: string;
  residentType: 'Residential' | 'Corporate' | 'Tourist' | 'Mixed';
}

export interface LocalityMetrics {
  footfallEstimate: {
    hourly: number;
    daily: number;
    peakTimes: string[];
  };
  nearbyPOIs: {
    schools: number;
    premiumSchools: number;
    placesOfWorship: number;
    hotels: {
      luxury: number;
      midTier: number;
      budget: number;
    };
  };
  tourismProfile: string;
  storeCompetition: {
    type: string;
    avgPricePoint: string;
    count: number;
  }[];
}

export interface AnalysisResult {
  localityName: string;
  demographics: AreaDemographics;
  metrics: LocalityMetrics;
  revenueProjections: RevenueProjections;
  strategicAdvice: string[];
  groundingSources: { title: string; uri: string }[];
}

export interface StoreInput {
  location: string;
  storeType: string;
  dimensions: string; // e.g. "1500 sq ft"
  targetSegment: string;
}

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { StoreInput, AnalysisResult } from "../types";

export class GeminiService {
  private static getAi() {
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  static async analyzeMarket(input: StoreInput): Promise<AnalysisResult> {
    const ai = this.getAi();

    // 1. Gather Spatial Data using Gemini 2.5 Flash with Google Maps Grounding
    const mapsResponse = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: `Identify detailed points of interest, traffic patterns, and local businesses around ${input.location}. 
      Specifically look for: schools (premium vs regular), places of worship (temples, mosques, etc.), hotels (luxury, mid, low), and types of retail stores. 
      Estimate the typical crowd type (residents vs tourists).`,
      config: {
        tools: [{ googleMaps: {} }],
      },
    });

    const groundingChunks = mapsResponse.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const sources = groundingChunks
      .filter(chunk => chunk.maps)
      .map(chunk => ({
        title: chunk.maps?.title || 'Map Source',
        uri: chunk.maps?.uri || ''
      }));

    // 2. Gather Socioeconomic data using Gemini 3 Flash with Search Grounding
    const searchResponse = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Search for recent real estate pricing, per capita income statistics, and popular car ownership trends in the ${input.location} district. 
      Is this area known for high-end luxury vehicles (Mercedes, BMW) or budget/mid-tier cars (Swift, Maruti)? 
      What are the current commercial rental rates in this area?`,
      config: {
        tools: [{ googleSearch: {} }],
      },
    });

    const searchSources = (searchResponse.candidates?.[0]?.groundingMetadata?.groundingChunks || [])
      .filter(chunk => chunk.web)
      .map(chunk => ({
        title: chunk.web?.title || 'Search Source',
        uri: chunk.web?.uri || ''
      }));

    // 3. Complex Reasoning and Revenue Estimation using Gemini 3 Pro with Thinking
    const proResponse = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: `Perform a deep market feasibility analysis for a ${input.storeType} of ${input.dimensions} located in ${input.location}.

      INPUT DATA GATHERED:
      Maps Analysis: ${mapsResponse.text}
      Search/Wealth Data: ${searchResponse.text}

      GOALS:
      1. Estimate hourly and daily footfall using proxies like POIs and traffic reports.
      2. Determine the per capita income of this locality.
      3. Predict Revenue for: 1 Month, 1 Quarter, 1 Year.
      4. Break down the area into segments (Residential/Corporate/Tourist).
      5. Analyze competition (Kirana vs Malls vs Craftsmanship stores).

      Provide the output in valid JSON format only, matching this structure:
      {
        "localityName": string,
        "demographics": { "perCapitaIncome": number, "socioeconomicTier": string, "dominantCarTypes": string[], "populationDensity": string, "residentType": string },
        "metrics": { 
          "footfallEstimate": { "hourly": number, "daily": number, "peakTimes": string[] },
          "nearbyPOIs": { "schools": number, "premiumSchools": number, "placesOfWorship": number, "hotels": { "luxury": number, "midTier": number, "budget": number } },
          "tourismProfile": string,
          "storeCompetition": [ { "type": string, "avgPricePoint": string, "count": number } ]
        },
        "revenueProjections": { "monthly": number, "quarterly": number, "yearly": number, "currency": string },
        "strategicAdvice": string[]
      }`,
      config: {
        thinkingConfig: { thinkingBudget: 32768 },
        responseMimeType: "application/json",
      },
    });

    try {
      const result: AnalysisResult = JSON.parse(proResponse.text);
      return {
        ...result,
        groundingSources: [...sources, ...searchSources]
      };
    } catch (e) {
      console.error("JSON Parse Error", e);
      throw new Error("Failed to parse market intelligence data.");
    }
  }

  static async editVisualReport(imageBytes: string, prompt: string): Promise<string> {
    const ai = this.getAi();
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          { inlineData: { data: imageBytes, mimeType: 'image/png' } },
          { text: prompt }
        ]
      },
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    throw new Error("No image generated.");
  }
}

import React from 'react';

interface MetricCardProps {
