import React from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';
import { RevenueProjections } from '../types';

interface RevenueChartProps {
  projections: RevenueProjections;
}

export const RevenueChart: React.FC<RevenueChartProps> = ({ projections }) => {
  const data = [
    { name: 'Monthly', value: projections.monthly, color: '#6366f1' },
    { name: 'Quarterly', value: projections.quarterly, color: '#8b5cf6' },
    { name: 'Yearly', value: projections.yearly, color: '#ec4899' },
  ];

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('en-IN', {
      style: 'currency',
      currency: projections.currency || 'INR',
      maximumFractionDigits: 0,
    }).format(val);
  };

  return (
    <div className="h-80 w-full bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
      <h3 className="text-lg font-semibold mb-6 text-slate-800">Revenue Forecast</h3>
      <ResponsiveContainer width="100%" height="100%">
        <BarChart data={data}>
          <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
          <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fill: '#64748b', fontSize: 12 }} />
          <YAxis 
            axisLine={false} 
            tickLine={false} 
            tickFormatter={(val) => `₹${val >= 100000 ? (val/100000).toFixed(1)+'L' : val}`}
            tick={{ fill: '#64748b', fontSize: 12 }}
          />
          <Tooltip 
            formatter={(value: number) => formatCurrency(value)}
            contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }}
          />
          <Bar dataKey="value" radius={[8, 8, 0, 0]}>
            {data.map((entry, index) => (
              <Cell key={`cell-${index}`} fill={entry.color} />
            ))}
          </Bar>
        </BarChart>
      </ResponsiveContainer>
    </div>
  );
};

