import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { StoreInput, AnalysisResult } from "../types";

export class GeminiService {
  private static getAi() {
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  static async analyzeMarket(input: StoreInput): Promise<AnalysisResult> {
    const ai = this.getAi();
    const totalArea = input.length * input.breadth * input.floors;

    // 1. Gather Spatial Data using Gemini 3 Flash with Google Search Grounding (replacing unsupported googleMaps)
    const mapsResponse = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Perform a detailed spatial and infrastructure analysis for the area around ${input.location} (approx coords: ${input.coordinates?.lat || 'unknown'}, ${input.coordinates?.lng || 'unknown'}). 
      Search for: schools (premium vs regular), places of worship, hotels (luxury vs budget), and public transport hubs in this exact vicinity. 
      Identify typical traffic patterns and pedestrian density. Determine if this is a high-street location, a residential pocket, or a corporate hub.`,
      config: {
        tools: [{ googleSearch: {} }],
      },
    });

    const mapsGroundingChunks = mapsResponse.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const mapsSources = mapsGroundingChunks
      .filter(chunk => chunk.web || chunk.maps)
      .map(chunk => ({
        title: (chunk.web?.title || chunk.maps?.title || 'Map/Local Source'),
        uri: (chunk.web?.uri || chunk.maps?.uri || '')
      }));

    // 2. Gather Socioeconomic data using Gemini 3 Flash with Search Grounding
    const searchResponse = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Search for socioeconomic data in ${input.location}. Focus on:
      - Average per capita income for residents.
      - Real estate pricing for commercial spaces like ${input.category}.
      - Vehicle demographics: what kind of cars are dominant (e.g., luxury brands vs budget brands)?
      - Recent commercial developments or mall openings in this locality.`,
      config: {
        tools: [{ googleSearch: {} }],
      },
    });

    const searchGroundingChunks = searchResponse.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const searchSources = searchGroundingChunks
      .filter(chunk => chunk.web)
      .map(chunk => ({
        title: chunk.web?.title || 'Economic Source',
        uri: chunk.web?.uri || ''
      }));

    // 3. Complex Reasoning using Gemini 3 Pro with Thinking
    const proResponse = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: `Synthesize a business feasibility report for:
      BUSINESS: ${input.category}
      LOCATION: ${input.location}
      SPECS: ${input.length}x${input.breadth} ft footprint, ${input.floors} floors, ${input.heightPerFloor}ft height per floor.
      TOTAL AREA: ${totalArea} sq ft.
      TARGET SEGMENT: ${input.targetSegment}

      GATHERED CONTEXT (GROUNDED DATA):
      Location Details: ${mapsResponse.text}
      Economic Details: ${searchResponse.text}

      TASK:
      1. Estimate daily/hourly footfall based on traffic proxies and nearby POIs.
      2. Calculate Per Capita Income (PCI) based on vehicle demographics (Mercedes/BMW vs Maruti/Swift) and property values.
      3. Project Revenue for: 1 Month, 1 Quarter, 1 Year.
      4. Provide 3-5 strategic AI-driven pieces of advice for this store's layout or operations.

      Respond in valid JSON format:
      {
        "localityName": string,
        "demographics": { "perCapitaIncome": number, "socioeconomicTier": "High" | "Upper-Mid" | "Mid" | "Lower-Mid" | "Economic", "dominantCarTypes": string[], "populationDensity": string, "residentType": "Residential" | "Corporate" | "Tourist" | "Mixed" },
        "metrics": { 
          "footfallEstimate": { "hourly": number, "daily": number, "peakTimes": string[] },
          "nearbyPOIs": { "schools": number, "premiumSchools": number, "placesOfWorship": number, "hotels": { "luxury": number, "midTier": number, "budget": number } },
          "tourismProfile": string,
          "storeCompetition": [ { "type": string, "avgPricePoint": string, "count": number } ]
        },
        "revenueProjections": { "monthly": number, "quarterly": number, "yearly": number, "currency": "INR" },
        "strategicAdvice": string[]
      }`,
      config: {
        thinkingConfig: { thinkingBudget: 32768 },
        responseMimeType: "application/json",
      },
    });

    try {
      const resultText = proResponse.text || "{}";
      const result: AnalysisResult = JSON.parse(resultText);
      return {
        ...result,
        groundingSources: [...mapsSources, ...searchSources].filter((v, i, a) => a.findIndex(t => t.uri === v.uri) === i) // Deduplicate
      };
    } catch (e) {
      console.error("Analysis Parsing Error", e);
      throw new Error("Critical analysis failure. The model could not structure the market data. Please refine your search or try again.");
    }
  }
}

