  'High Net-worth Individuals (HNIs)',
  'Corporate Employees / Tech Workers',
  'Gen-Z Trendsetters',
  'Millennials',
  'Elderly / Retirees',
  'Expatriates',
  'Local Residents',
  'Religious Pilgrims',
  'Fitness Enthusiasts'
];

const INITIAL_POS = { lat: 19.0596, lng: 72.8295 }; // Bandra West, Mumbai

const MapEventHandler = ({ onLocationChange }: { onLocationChange: (lat: number, lng: number) => void }) => {
  const map = useMap();
  useMapEvents({
    click(e) {
      onLocationChange(e.latlng.lat, e.latlng.lng);
    },
    moveend(e) {
        // If user drags map, update coordinates to center point for precision
        const center = e.target.getCenter();
        onLocationChange(center.lat, center.lng);
    },
    dblclick(e) {
      map.zoomIn();
    }
  });
  return null;
};

const MapController = ({ center }: { center: [number, number] }) => {
  const map = useMap();
  useEffect(() => {
    map.flyTo(center, 19, {
        duration: 1.5,
        easeLinearity: 0.25
    });
  }, [center, map]);
  return null;
};

const App: React.FC = () => {
  const [loading, setLoading] = useState(false);
  const [mapPos, setMapPos] = useState<[number, number]>([INITIAL_POS.lat, INITIAL_POS.lng]);
  const [is3D, setIs3D] = useState(false);
  const [mapType, setMapType] = useState<'hybrid' | 'street'>('hybrid');

  const [input, setInput] = useState<StoreInput>({
    location: 'Bandra West, Mumbai',
    coordinates: INITIAL_POS,
    category: 'Premium Cafe (e.g., Starbucks)',
    length: 40,
    breadth: 50,
    floors: 1,
    heightPerFloor: 12,
    targetSegment: 'Gen-Z & High-income Professionals'
  });

  const [result, setResult] = useState<AnalysisResult | null>(null);
  const resultsRef = useRef<HTMLDivElement>(null);

  const resetMap = () => {
    setMapPos([INITIAL_POS.lat, INITIAL_POS.lng]);
    setInput(prev => ({ ...prev, coordinates: INITIAL_POS, location: 'Bandra West, Mumbai' }));
  };

  const handleSearchSync = async () => {
    if (!input.location.trim()) return;
    try {
      const response = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(input.location)}`);
      const data = await response.json();
      if (data && data.length > 0) {
        const lat = parseFloat(data[0].lat);
        const lng = parseFloat(data[0].lon);
        setMapPos([lat, lng]);
        setInput(prev => ({ ...prev, coordinates: { lat, lng } }));
      }
    } catch (e) {
      console.warn("Geocoding failed", e);
    }
  };

  const onMapPinMove = useCallback((lat: number, lng: number) => {
    setMapPos([lat, lng]);
    setInput(prev => ({ ...prev, coordinates: { lat, lng } }));
  }, []);

  const handleAnalyze = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setTimeout(() => {
        resultsRef.current?.scrollIntoView({ behavior: 'smooth' });
    }, 100);

    try {
      const data = await GeminiService.analyzeMarket(input);
      setResult(data);
    } catch (err: any) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('en-IN', {
