          <MapContainer 
            center={mapPos} 
            zoom={19} 
            zoomControl={false}
            scrollWheelZoom={true} 
            doubleClickZoom={false}
            style={{ height: '100%', width: '100%' }}
          >
            {mapType === 'hybrid' ? (
              <>
                <TileLayer
                  url="https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}"
                  attribution='&copy; Esri'
                />
                <TileLayer
                  url="https://stamen-tiles-{s}.a.ssl.fastly.net/toner-labels/{z}/{x}/{y}{r}.png"
                  attribution='&copy; Stamen'
                  opacity={0.7}
                />
              </>
            ) : (
              <TileLayer
                url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
                attribution='&copy; OSM'
              />
            )}
            <MapController center={mapPos} />
            <MapEventHandler onLocationChange={onMapPinMove} />
            <Marker position={mapPos} />
          </MapContainer>
        </div>

        {/* Center Crosshair for Precise Placement */}
        <div className="map-crosshair flex flex-col items-center justify-center opacity-60">
            <div className="crosshair-line-v absolute"></div>
            <div className="crosshair-line-h absolute"></div>
            <div className="crosshair-circle absolute"></div>
        </div>

        {/* Floating Controls Overlay */}
        <div className="absolute top-6 right-6 z-[1001] flex flex-col gap-3">
            <button 
                onClick={() => setIs3D(!is3D)}
                title="Toggle 3D Perspective"
                className={`p-4 rounded-2xl border transition-all shadow-2xl flex items-center justify-center gap-3 font-black text-[10px] uppercase tracking-widest ${is3D ? 'bg-indigo-600 text-white border-indigo-400' : 'bg-white/80 backdrop-blur-xl text-slate-800 border-white/40'}`}
