                <Box size={18} /> {is3D ? 'Disable 3D' : 'Enable 3D'}
            </button>
            <button 
                onClick={() => setMapType(mapType === 'hybrid' ? 'street' : 'hybrid')}
                title="Toggle Satellite View"
                className="p-4 bg-white/80 backdrop-blur-xl rounded-2xl border border-white/40 shadow-2xl flex items-center justify-center gap-3 font-black text-[10px] uppercase tracking-widest text-slate-800"
            >
                {mapType === 'hybrid' ? <MapIcon size={18} /> : <Globe size={18} />}
                {mapType === 'hybrid' ? 'Street Map' : 'Satellite View'}
            </button>
            <button 
                onClick={resetMap}
                title="Reset Map to Initial View"
                className="p-4 bg-white/80 backdrop-blur-xl rounded-2xl border border-white/40 shadow-2xl flex items-center justify-center gap-3 font-black text-[10px] uppercase tracking-widest text-slate-800 hover:bg-white transition-all"
            >
                <Home size={18} /> Reset View
            </button>
        </div>

