const MapEventHandler = ({ onLocationChange }: { onLocationChange: (lat: number, lng: number) => void }) => {
  const map = useMap();
  useMapEvents({
    click(e) {
      onLocationChange(e.latlng.lat, e.latlng.lng);
    },
    moveend(e) {
        // We only want to update state if the movement was user-initiated drag
        // However, to keep it simple and responsive to the crosshair:
        const center = e.target.getCenter();
        onLocationChange(center.lat, center.lng);
    },
    dblclick(e) {
      map.zoomIn();
    }
  });
  return null;
};

const MapController = ({ center, is3D }: { center: [number, number], is3D: boolean }) => {
  const map = useMap();
  const lastCenter = useRef<[number, number]>(center);

  useEffect(() => {
    // Only fly if coordinates actually changed significantly to avoid jitter
    const dist = Math.sqrt(Math.pow(center[0] - lastCenter.current[0], 2) + Math.pow(center[1] - lastCenter.current[1], 2));
    if (dist > 0.0001) {
        map.flyTo(center, 18, {
            duration: 1.5,
            easeLinearity: 0.25
        });
        lastCenter.current = center;
    }
  }, [center, map]);

  useEffect(() => {
    // When 3D mode toggles, the container transform changes. 
    // We must invalidate size to let Leaflet recalculate internal bounds.
    const timer = setTimeout(() => {
        map.invalidateSize();
    }, 850);
    return () => clearTimeout(timer);
  }, [is3D, map]);

  return null;
};

