const MapEventHandler = ({ onLocationChange }: { onLocationChange: (lat: number, lng: number) => void }) => {
  const map = useMap();
  useMapEvents({
    click(e) {
      onLocationChange(e.latlng.lat, e.latlng.lng);
    },
    moveend(e) {
        const center = e.target.getCenter();
        onLocationChange(center.lat, center.lng);
    },
    dblclick(e) {
      map.zoomIn();
    }
  });
  return null;
};

const MapController = ({ center, is3D }: { center: [number, number], is3D: boolean }) => {
  const map = useMap();
  const lastCenter = useRef<[number, number]>(center);

  useEffect(() => {
    const dist = Math.sqrt(Math.pow(center[0] - lastCenter.current[0], 2) + Math.pow(center[1] - lastCenter.current[1], 2));
    if (dist > 0.0001) {
        map.flyTo(center, 18, {
            duration: 1.5,
            easeLinearity: 0.25
        });
        lastCenter.current = center;
    }
  }, [center, map]);

  useEffect(() => {
    const timer = setTimeout(() => {
        map.invalidateSize();
    }, 850);
    return () => clearTimeout(timer);
  }, [is3D, map]);

  return null;
};

const App: React.FC = () => {
  const [loading, setLoading] = useState(false);
  const [mapPos, setMapPos] = useState<[number, number]>([INITIAL_POS.lat, INITIAL_POS.lng]);
  const [is3D, setIs3D] = useState(false);
  const [mapType, setMapType] = useState<'hybrid' | 'street'>('hybrid');
  const [isCategoryOpen, setIsCategoryOpen] = useState(false);
  const [isSegmentOpen, setIsSegmentOpen] = useState(false);
  const [customSegment, setCustomSegment] = useState('');
  const categoryRef = useRef<HTMLDivElement>(null);
  const segmentRef = useRef<HTMLDivElement>(null);
  const [errors, setErrors] = useState<ValidationErrors>({});

  const [input, setInput] = useState<StoreInput>({
    location: 'Bandra West, Mumbai',
    coordinates: INITIAL_POS,
    category: 'Premium Cafe (e.g., Starbucks)',
    length: 40,
    breadth: 50,
    floors: 1,
    heightPerFloor: 12,
    targetSegment: ['Gen-Z Trendsetters', 'Young Professionals']
  });

  const [result, setResult] = useState<AnalysisResult | null>(null);
  const resultsRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (categoryRef.current && !categoryRef.current.contains(event.target as Node)) {
        setIsCategoryOpen(false);
      }
      if (segmentRef.current && !segmentRef.current.contains(event.target as Node)) {
        setIsSegmentOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const validate = (name: keyof ValidationErrors, value: number) => {
    let error = '';
    switch (name) {
      case 'length':
      case 'breadth':
        if (value <= 0) error = 'Must be > 0';
        else if (value > 5000) error = 'Max 5000ft';
        break;
      case 'floors':
        if (value < 1) error = 'Min 1 floor';
        else if (value > 163) error = 'Max 163 floors';
        break;
      case 'heightPerFloor':
        if (value < 5) error = 'Min 5ft';
        else if (value > 100) error = 'Max 100ft';
        break;
    }
    setErrors(prev => ({ ...prev, [name]: error }));
    return error === '';
  };

  const handleInputChange = (name: keyof StoreInput, value: any) => {
    setInput(prev => ({ ...prev, [name]: value }));
    if (['length', 'breadth', 'floors', 'heightPerFloor'].includes(name)) {
      validate(name as keyof ValidationErrors, Number(value));
    }
  };

  const addSegment = (seg: string) => {
    if (!seg.trim()) return;
    if (!input.targetSegment.includes(seg)) {
      setInput(prev => ({ ...prev, targetSegment: [...prev.targetSegment, seg] }));
    }
    setCustomSegment('');
  };

  const removeSegment = (seg: string) => {
    setInput(prev => ({ ...prev, targetSegment: prev.targetSegment.filter(s => s !== seg) }));
  };

  const resetMap = () => {
    const pos: [number, number] = [INITIAL_POS.lat, INITIAL_POS.lng];
    setMapPos(pos);
    setErrors({});
    setInput({ 
      location: 'Bandra West, Mumbai',
      coordinates: INITIAL_POS,
      category: 'Premium Cafe (e.g., Starbucks)',
      length: 40,
      breadth: 50,
      floors: 1,
      heightPerFloor: 12,
      targetSegment: ['Gen-Z Trendsetters', 'Young Professionals']
    });
  };

  const handleSearchSync = async () => {
    if (!input.location.trim()) return;
    try {
      const response = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(input.location)}`);
      const data = await response.json();
      if (data && data.length > 0) {
        const lat = parseFloat(data[0].lat);
        const lng = parseFloat(data[0].lon);
        setMapPos([lat, lng]);
        setInput(prev => ({ ...prev, coordinates: { lat, lng } }));
      }
    } catch (e) {
      console.warn("Geocoding failed", e);
    }
  };

  const onMapPinMove = useCallback((lat: number, lng: number) => {
    setMapPos(prev => {
        if (Math.abs(prev[0] - lat) < 0.00001 && Math.abs(prev[1] - lng) < 0.00001) return prev;
        return [lat, lng];
    });
    setInput(prev => ({ ...prev, coordinates: { lat, lng } }));
  }, []);

  const handleAnalyze = async (e: React.FormEvent) => {
    e.preventDefault();

    const v1 = validate('length', input.length);
    const v2 = validate('breadth', input.breadth);
    const v3 = validate('floors', input.floors);
    const v4 = validate('heightPerFloor', input.heightPerFloor);

    if (!v1 || !v2 || !v3 || !v4) {
      return;
    }

    setLoading(true);
    setResult(null);

    setTimeout(() => {
        resultsRef.current?.scrollIntoView({ behavior: 'smooth' });
    }, 100);

    try {
      const data = await GeminiService.analyzeMarket(input);
      setResult(data);
    } catch (err: any) {
      console.error(err);
      alert("Analysis failed. Spatial intelligence engine encountered an error. Please refine parameters.");
    } finally {
      setLoading(false);
    }
  };

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('en-IN', {
