export default App;

export interface RevenueProjections {
  monthly: number;
  quarterly: number;
  yearly: number;
  currency: string;
}

export interface AreaDemographics {
  perCapitaIncome: number;
  socioeconomicTier: 'High' | 'Upper-Mid' | 'Mid' | 'Lower-Mid' | 'Economic';
  dominantCarTypes: string[];
  populationDensity: string;
  residentType: 'Residential' | 'Corporate' | 'Tourist' | 'Mixed';
}

export interface LocalityMetrics {
  footfallEstimate: {
    hourly: number;
    daily: number;
    peakTimes: string[];
    hourlyDistribution: { hour: number; traffic: number }[];
  };
  nearbyPOIs: {
    schools: number;
    premiumSchools: number;
    placesOfWorship: number;
    hotels: {
      luxury: number;
      midTier: number;
      budget: number;
    };
  };
  tourismProfile: string;
  storeCompetition: {
    type: string;
    avgPricePoint: string;
    count: number;
    description: string;
  }[];
}

export interface AnalysisResult {
  localityName: string;
  demographics: AreaDemographics;
  metrics: LocalityMetrics;
  revenueProjections: RevenueProjections;
  strategicAdvice: string[];
  groundingSources: { title: string; uri: string }[];
}

export type StoreCategory = 
  | 'Premium Cafe (e.g., Starbucks)' 
  | 'Large Attraction (e.g., Zoo / Theme Park)' 
  | 'Supermarket (e.g., Reliance Fresh / DMart)' 
  | 'Luxury Fashion / Boutique' 
  | 'Pharmacy / Wellness' 
  | 'Fine Dining Restaurant' 
  | 'Workspace / Coworking' 
  | 'Quick Service Restaurant (QSR)';

export interface StoreInput {
  location: string;
  coordinates?: { lat: number; lng: number };
  category: StoreCategory;
  length: number; // in ft
  breadth: number; // in ft
  floors: number;
  heightPerFloor: number; // in ft
  targetSegment: string[];
}

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { StoreInput, AnalysisResult } from "../types";

export class GeminiService {
  private static getAi() {
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  static async analyzeMarket(input: StoreInput): Promise<AnalysisResult> {
    const ai = this.getAi();
    const totalArea = input.length * input.breadth * input.floors;

    // 1. Gather Spatial Data
    const mapsResponse = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Perform a detailed spatial analysis for the area around ${input.location}. 
      Identify: schools (premium/regular), places of worship, hotels (luxury/budget), and existing retail nodes. 
      Focus on identifying specific commercial categories like local kirana stores, luxury boutiques, or shopping malls within a 2km radius.`,
      config: {
        tools: [{ googleSearch: {} }],
      },
    });

    const mapsSources = (mapsResponse.candidates?.[0]?.groundingMetadata?.groundingChunks || [])
      .filter(chunk => chunk.web || chunk.maps)
      .map(chunk => ({
        title: (chunk.web?.title || chunk.maps?.title || 'Local Node Mapping'),
        uri: (chunk.web?.uri || chunk.maps?.uri || '')
      }));

    // 2. Gather Socioeconomic data
    const searchResponse = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Search for economic indicators in ${input.location}. 
      What are the dominant car brands seen here (luxury vs entry-level)? 
      What are the prevailing retail price points in existing shops? 
      Identify high-density residential complexes vs corporate parks nearby.`,
      config: {
        tools: [{ googleSearch: {} }],
      },
    });

    const searchSources = (searchResponse.candidates?.[0]?.groundingMetadata?.groundingChunks || [])
      .filter(chunk => chunk.web)
      .map(chunk => ({
        title: chunk.web?.title || 'Economic Dataset',
        uri: chunk.web?.uri || ''
      }));

    // 3. Synthesis using Pro Model
    const proResponse = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: `Synthesize a precision market report for:
      BUSINESS: ${input.category}
      LOCATION: ${input.location}
      SPECS: ${input.length}x${input.breadth} ft, ${input.floors} floors.
      TARGET AUDIENCE: ${input.targetSegment.join(', ')}

      CONTEXT:
      Spatial: ${mapsResponse.text}
      Economic: ${searchResponse.text}

      TASK:
      1. Estimate PCI and Tier.
      2. Project 1m, 3m, 1y Revenue.
      3. Create a DETAILED storeCompetition array. Categorize by formats like 'Kirana/Provision', 'Luxury Mall', 'High-street Boutique', 'QSR Chain', etc.
      4. For each competition type, estimate their average price point (e.g., 'Budget', 'Premium', 'Ultra-Luxury') and count.
      5. GENERATE a 24-hour footfall distribution (hourlyDistribution) array where 'traffic' is the number of pedestrians/customers expected at each hour (0 to 23).

      Respond in JSON:
      {
        "localityName": string,
        "demographics": { "perCapitaIncome": number, "socioeconomicTier": "High" | "Upper-Mid" | "Mid" | "Lower-Mid" | "Economic", "dominantCarTypes": string[], "populationDensity": string, "residentType": "Residential" | "Corporate" | "Tourist" | "Mixed" },
        "metrics": { 
          "footfallEstimate": { 
            "hourly": number, 
            "daily": number, 
            "peakTimes": string[],
            "hourlyDistribution": [ { "hour": number, "traffic": number } ]
          },
          "nearbyPOIs": { "schools": number, "premiumSchools": number, "placesOfWorship": number, "hotels": { "luxury": number, "midTier": number, "budget": number } },
          "tourismProfile": string,
          "storeCompetition": [ 
            { "type": string, "avgPricePoint": string, "count": number, "description": string } 
          ]
        },
        "revenueProjections": { "monthly": number, "quarterly": number, "yearly": number, "currency": "INR" },
        "strategicAdvice": string[]
      }`,
      config: {
        thinkingConfig: { thinkingBudget: 32768 },
        responseMimeType: "application/json",
      },
    });

    try {
      const result: AnalysisResult = JSON.parse(proResponse.text || "{}");
      return {
        ...result,
        groundingSources: [...mapsSources, ...searchSources].filter((v, i, a) => a.findIndex(t => t.uri === v.uri) === i)
      };
    } catch (e) {
      throw new Error("Analysis synthesis failed.");
    }
  }
}

