import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { StoreInput, AnalysisResult } from "../types";

export class GeminiService {
  private static getAi() {
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  static async analyzeMarket(input: StoreInput): Promise<AnalysisResult> {
    const ai = this.getAi();
    const totalArea = input.length * input.breadth * input.floors;

    // 1. Gather Multi-Source Spatial Data
    // We explicitly ask the model to synthesize data from various ecosystems.
    const mapsResponse = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Perform a comprehensive multi-platform spatial analysis for the area around ${input.location}. 
      Cross-reference data points from Apple Maps, OpenStreetMap (OSM), and Google Search for:
      - Schools (differentiate premium vs. regular)
      - Places of worship and cultural landmarks
      - Hotel tiers (luxury vs. mid-tier vs. budget)
      - Existing retail competition (malls, kirana stores, boutiques)
      Note any discrepancies between map platforms to ensure data fusion accuracy.`,
      config: {
        tools: [{ googleSearch: {} }],
      },
    });

    const mapsSources = (mapsResponse.candidates?.[0]?.groundingMetadata?.groundingChunks || [])
      .filter(chunk => chunk.web || chunk.maps)
      .map(chunk => ({
        title: (chunk.web?.title || chunk.maps?.title || 'Spatial Dataset Node'),
        uri: (chunk.web?.uri || chunk.maps?.uri || '')
      }));

    // 2. Gather Socioeconomic & Multi-Source Traffic Data
    const searchResponse = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Search for socioeconomic and traffic indicators in ${input.location} using public records and map-derived metadata. 
      Identify:
      - Dominant vehicle demographics (luxury vs. budget brands) as seen in local traffic data.
      - Estimated per capita income based on residential real estate listings and nearby high-end infrastructure.
      - Public transport hub density and pedestrian hotspots mentioned in urban planning or open map datasets.`,
      config: {
        tools: [{ googleSearch: {} }],
      },
    });

    const searchSources = (searchResponse.candidates?.[0]?.groundingMetadata?.groundingChunks || [])
      .filter(chunk => chunk.web)
      .map(chunk => ({
        title: chunk.web?.title || 'Urban Economic Dataset',
        uri: chunk.web?.uri || ''
      }));

    // 3. Synthesis using Pro Model with High Thinking Budget
    const proResponse = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: `Synthesize a high-precision market report for a new ${input.category} at ${input.location}.
      TOTAL STORE AREA: ${totalArea} sq ft.
      TARGET SEGMENTS: ${input.targetSegment.join(', ')}

      CONTEXT SYNTHESIS (Fused from Apple Maps, Google, and OSM data):
      Spatial Findings: ${mapsResponse.text}
      Economic Findings: ${searchResponse.text}

      CRITICAL TASKS:
      1. Logic-check footfall proxies based on the combined density of POIs from all map sources.
      2. Provide a 24-hour traffic distribution (hourlyDistribution) reflecting local morning/evening/night shifts.
      3. Categorize competition into precise tiers (Budget to Ultra-Luxury).
      4. Estimate Per Capita Income based on the "Vehicle Proxy" logic (Mercedes vs. Maruti).

      Respond in strict JSON:
      {
        "localityName": string,
        "demographics": { "perCapitaIncome": number, "socioeconomicTier": "High" | "Upper-Mid" | "Mid" | "Lower-Mid" | "Economic", "dominantCarTypes": string[], "populationDensity": string, "residentType": "Residential" | "Corporate" | "Tourist" | "Mixed" },
        "metrics": { 
          "footfallEstimate": { 
            "hourly": number, 
            "daily": number, 
            "peakTimes": string[],
            "hourlyDistribution": [ { "hour": number, "traffic": number } ]
          },
          "nearbyPOIs": { "schools": number, "premiumSchools": number, "placesOfWorship": number, "hotels": { "luxury": number, "midTier": number, "budget": number } },
          "tourismProfile": string,
          "storeCompetition": [ 
            { "type": string, "avgPricePoint": string, "count": number, "description": string } 
          ]
        },
        "revenueProjections": { "monthly": number, "quarterly": number, "yearly": number, "currency": "INR" },
        "strategicAdvice": string[]
      }`,
      config: {
        thinkingConfig: { thinkingBudget: 32768 },
        responseMimeType: "application/json",
      },
    });

    try {
      const result: AnalysisResult = JSON.parse(proResponse.text || "{}");
      return {
        ...result,
        groundingSources: [...mapsSources, ...searchSources].filter((v, i, a) => a.findIndex(t => t.uri === v.uri) === i)
      };
    } catch (e) {
      throw new Error("Multi-source analysis synthesis failed.");
    }
  }
}

