                        <div className="bg-white/10 backdrop-blur-3xl p-10 rounded-[3rem] border border-white/20 shadow-2xl group hover:bg-white/20 transition-all">
                            <div className="text-indigo-300 text-[11px] font-black uppercase mb-3 tracking-[0.3em]">Neighborhood Type</div>
