                          className={`px-6 py-2 rounded-full text-[10px] font-black uppercase tracking-widest transition-all border whitespace-nowrap ${competitionFilter === type ? 'bg-indigo-600 text-white border-indigo-600 shadow-lg shadow-indigo-600/20' : 'bg-white text-slate-600 border-slate-200 hover:border-indigo-400 hover:text-indigo-600'}`}
                        >
                          {type}
                        </button>
                      ))}
                    </div>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 transition-all duration-500">
                    {filteredCompetition.length > 0 ? (
                      filteredCompetition.map((comp, idx) => (
                        <div key={idx} className="bg-white p-8 rounded-[3rem] border border-slate-100 shadow-sm hover:shadow-xl hover:-translate-y-1 transition-all group overflow-hidden relative animate-in fade-in zoom-in-95 duration-500">
                          <div className="absolute -top-10 -right-10 opacity-[0.03] group-hover:scale-110 transition-transform">
                            <ShoppingBag size={120} />
                          </div>
                          <div className="flex items-start justify-between mb-6">
                            <div>
                              <div className="text-[10px] font-black text-indigo-600 uppercase tracking-[0.2em] mb-1">{comp.avgPricePoint} Tier</div>
                              <h4 className="text-lg font-black text-slate-900 tracking-tight">{comp.type}</h4>
                            </div>
                            <div className="bg-indigo-50 px-4 py-2 rounded-2xl text-indigo-700 text-xs font-black uppercase">
                              x{comp.count}
                            </div>
                          </div>
                          <p className="text-slate-500 text-sm font-semibold leading-relaxed">
                            {comp.description}
                          </p>
                        </div>
                      ))
                    ) : (
                      <div className="col-span-full py-20 bg-white rounded-[4rem] border border-slate-100 text-center flex flex-col items-center justify-center space-y-4">
                        <ShoppingBag size={48} className="text-slate-200" />
                        <p className="text-slate-400 font-black text-xs uppercase tracking-[0.2em]">No competitors found for this filter</p>
                      </div>
                    )}
                  </div>
                </div>

                {/* Charts & Advice */}
                <div className="grid grid-cols-1 lg:grid-cols-3 gap-12">
                    <div className="lg:col-span-2">
                        <RevenueChart projections={result.revenueProjections} />
                    </div>

                    <div className="bg-slate-950 text-white p-12 rounded-[4rem] shadow-3xl relative overflow-hidden flex flex-col justify-between">
                        <div className="absolute top-0 right-0 p-12 opacity-5">
                            <Sparkles size={160} />
                        </div>
                        <div>
                            <h3 className="text-xs font-black text-indigo-500 uppercase tracking-[0.5em] mb-12 flex items-center gap-4">
                                Strategic AI Directives
                            </h3>
                            <div className="space-y-8">
                                {result.strategicAdvice.map((advice, i) => (
                                <div key={i} className="flex gap-6 group">
                                    <div className="flex-shrink-0 w-10 h-10 rounded-2xl bg-indigo-600 flex items-center justify-center font-black text-sm text-white shadow-xl shadow-indigo-600/30 group-hover:rotate-12 transition-transform">
                                    {i + 1}
                                    </div>
                                    <p className="text-slate-400 text-base leading-relaxed font-semibold group-hover:text-white transition-colors">
                                    {advice}
                                    </p>
                                </div>
                                ))}
                            </div>
                        </div>
                        <div className="mt-12 pt-8 border-t border-white/10">
                             <div className="text-[10px] font-black text-indigo-500 uppercase tracking-widest mb-2">Algorithm Confidence</div>
                             <div className="w-full h-1 bg-white/5 rounded-full overflow-hidden">
                                <div className="h-full bg-indigo-500 w-[94%]"></div>
                             </div>
                        </div>
                    </div>
                </div>

                {/* Grounding Data */}
                <div className="pt-20 border-t border-slate-200">
                    <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.6em] mb-12 text-center">Data Grounding Citations</h4>
                    <div className="flex flex-wrap justify-center gap-6">
                        {result.groundingSources.map((source, i) => (
                            <a 
                                key={i} 
                                href={source.uri} 
                                target="_blank" 
                                rel="noopener noreferrer"
                                className="flex items-center gap-4 px-8 py-4 bg-white border border-slate-200 rounded-[2rem] text-[11px] font-black uppercase tracking-widest text-slate-700 hover:border-indigo-600 hover:text-indigo-700 hover:shadow-2xl hover:-translate-y-2 transition-all group"
                            >
                                <ExternalLink size={14} className="group-hover:scale-125 transition-transform" />
                                {source.title.length > 40 ? source.title.substring(0, 40) + '...' : source.title}
                            </a>
                        ))}
                    </div>
                </div>
              </div>
            )}
        </div>
      </section>

      <footer className="py-20 text-center text-slate-500 text-[10px] font-black uppercase tracking-[0.6em] bg-slate-50">
        <p>© 2024 LocalityMind Spatial Intelligence • Precision Market Analysis</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef, useMemo } from 'react';
import { 
  MapPin, Store, TrendingUp, Users, Car, Search, 
  Loader2, ExternalLink, Sparkles, Layers, 
  CircleDollarSign, ChevronDown, Building2, BoxSelect,
  RotateCcw, Target, MousePointer2, Info,
  Box, Globe, Home, ChevronUp, Check, AlertCircle,
  X, Plus, Briefcase, ShoppingBag, Landmark, Activity,
  Shuffle, Filter, MousePointer, Compass
} from 'lucide-react';
import maplibregl from 'maplibre-gl';
import { StoreInput, AnalysisResult, StoreCategory } from './types';
import { GeminiService } from './services/geminiService';
import { MetricCard } from './components/MetricCard';
import { RevenueChart } from './components/RevenueChart';
import { TrafficLandscape } from './components/TrafficLandscape';

const STORE_CATEGORIES: StoreCategory[] = [
  'Premium Cafe (e.g., Starbucks)',
  'Large Attraction (e.g., Zoo / Theme Park)',
  'Supermarket (e.g., Reliance Fresh / DMart)',
  'Luxury Fashion / Boutique',
  'Pharmacy / Wellness',
  'Fine Dining Restaurant',
  'Workspace / Coworking',
  'Quick Service Restaurant (QSR)'
];

const SUGGESTED_TARGET_SEGMENTS = [
  'Young Professionals',
  'Families with Children',
  'University Students',
  'International Tourists',
  'High Net-worth Individuals (HNIs)',
  'Corporate Employees',
  'Gen-Z Trendsetters',
  'Millennials',
  'Elderly / Retirees',
  'Expatriates',
  'Local Residents',
  'Religious Pilgrims',
  'Fitness Enthusiasts'
];

const INITIAL_POS = { lat: 19.0596, lng: 72.8295 }; // Bandra West, Mumbai

interface ValidationErrors {
  length?: string;
  breadth?: string;
  floors?: string;
  heightPerFloor?: string;
}

const App: React.FC = () => {
  const mapContainer = useRef<HTMLDivElement>(null);
  const map = useRef<maplibregl.Map | null>(null);
  const [loading, setLoading] = useState(false);
  const [searching, setSearching] = useState(false);
  const [is3D, setIs3D] = useState(true);
  const [isCategoryOpen, setIsCategoryOpen] = useState(false);
  const [isSegmentOpen, setIsSegmentOpen] = useState(false);
  const [customSegment, setCustomSegment] = useState('');
  const categoryRef = useRef<HTMLDivElement>(null);
  const segmentRef = useRef<HTMLDivElement>(null);
  const [errors, setErrors] = useState<ValidationErrors>({});

  const [input, setInput] = useState<StoreInput>({
    location: 'Bandra West, Mumbai',
    coordinates: INITIAL_POS,
    category: 'Premium Cafe (e.g., Starbucks)',
    length: 40,
    breadth: 50,
    floors: 1,
    heightPerFloor: 12,
    targetSegment: ['Gen-Z Trendsetters', 'Young Professionals']
  });

  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [competitionFilter, setCompetitionFilter] = useState<string>('All');
  const resultsRef = useRef<HTMLDivElement>(null);

  // Initialize MapLibre
  useEffect(() => {
    if (!mapContainer.current) return;

    map.current = new maplibregl.Map({
      container: mapContainer.current,
      style: 'https://tiles.basemaps.cartocdn.com/gl/dark-matter-gl-style/style.json',
      center: [INITIAL_POS.lng, INITIAL_POS.lat],
      zoom: 17,
      pitch: 60,
      bearing: -15,
      antialias: true
    });

    map.current.on('load', () => {
      if (!map.current) return;

      // Add 3D building layer
      const layers = map.current.getStyle().layers;
      let labelLayerId;
      if (layers) {
          for (let i = 0; i < layers.length; i++) {
              if (layers[i].type === 'symbol' && (layers[i].layout as any)?.['text-field']) {
                  labelLayerId = layers[i].id;
                  break;
              }
          }
      }

      map.current.addLayer({
          'id': '3d-buildings',
          'source': 'openmaptiles',
          'source-layer': 'building',
          'type': 'fill-extrusion',
          'minzoom': 15,
          'paint': {
              'fill-extrusion-color': '#4f46e5',
              'fill-extrusion-height': ['get', 'render_height'],
              'fill-extrusion-base': ['get', 'render_min_height'],
              'fill-extrusion-opacity': 0.6
          }
      }, labelLayerId);
    });

    map.current.on('move', () => {
      if (!map.current) return;
      const center = map.current.getCenter();
      setInput(prev => ({
        ...prev,
        coordinates: { lat: center.lat, lng: center.lng }
      }));
    });

    return () => map.current?.remove();
  }, []);

  const toggle3D = () => {
    if (!map.current) return;
    const new3D = !is3D;
    setIs3D(new3D);
    map.current.easeTo({
      pitch: new3D ? 60 : 0,
      duration: 1000
    });
  };

  const resetMap = () => {
    if (!map.current) return;
    map.current.flyTo({
      center: [INITIAL_POS.lng, INITIAL_POS.lat],
      zoom: 17,
      pitch: 60,
      bearing: -15,
      duration: 2000
    });
    setErrors({});
    setInput({ 
      location: 'Bandra West, Mumbai',
      coordinates: INITIAL_POS,
      category: 'Premium Cafe (e.g., Starbucks)',
      length: 40,
      breadth: 50,
      floors: 1,
      heightPerFloor: 12,
      targetSegment: ['Gen-Z Trendsetters', 'Young Professionals']
    });
  };

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (categoryRef.current && !categoryRef.current.contains(event.target as Node)) {
        setIsCategoryOpen(false);
      }
      if (segmentRef.current && !segmentRef.current.contains(event.target as Node)) {
        setIsSegmentOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const validate = (name: keyof ValidationErrors, value: number) => {
    let error = '';
    switch (name) {
      case 'length':
      case 'breadth':
        if (value <= 0) error = 'Must be > 0';
        else if (value > 5000) error = 'Max 5000ft';
        break;
      case 'floors':
        if (value < 1) error = 'Min 1 floor';
        else if (value > 163) error = 'Max 163 floors';
        break;
      case 'heightPerFloor':
        if (value < 5) error = 'Min 5ft';
        else if (value > 100) error = 'Max 100ft';
        break;
    }
    setErrors(prev => ({ ...prev, [name]: error }));
    return error === '';
  };

  const handleInputChange = (name: keyof StoreInput, value: any) => {
    setInput(prev => ({ ...prev, [name]: value }));
    if (['length', 'breadth', 'floors', 'heightPerFloor'].includes(name)) {
      validate(name as keyof ValidationErrors, Number(value));
    }
  };

  const addSegment = (seg: string) => {
    if (!seg.trim()) return;
    if (!input.targetSegment.includes(seg)) {
      setInput(prev => ({ ...prev, targetSegment: [...prev.targetSegment, seg] }));
    }
    setCustomSegment('');
  };

  const removeSegment = (seg: string) => {
    setInput(prev => ({ ...prev, targetSegment: prev.targetSegment.filter(s => s !== seg) }));
  };

  const handleSearchSync = async () => {
    if (!input.location.trim()) return;
    setSearching(true);
    try {
      const response = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(input.location)}`);
      const data = await response.json();
      if (data && data.length > 0) {
        const lat = parseFloat(data[0].lat);
        const lng = parseFloat(data[0].lon);
        map.current?.flyTo({
          center: [lng, lat],
          zoom: 18,
          essential: true,
          duration: 3000
        });
      }
    } catch (e) {
      console.warn("Geocoding failed", e);
    } finally {
      setSearching(false);
    }
  };

  const handleAnalyze = async (e: React.FormEvent) => {
    e.preventDefault();
    const v1 = validate('length', input.length);
    const v2 = validate('breadth', input.breadth);
    const v3 = validate('floors', input.floors);
    const v4 = validate('heightPerFloor', input.heightPerFloor);
    if (!v1 || !v2 || !v3 || !v4) return;

    setLoading(true);
    setResult(null);
    setCompetitionFilter('All');

    setTimeout(() => {
        resultsRef.current?.scrollIntoView({ behavior: 'smooth' });
    }, 100);

    try {
      const data = await GeminiService.analyzeMarket(input);
      setResult(data);
    } catch (err: any) {
      console.error(err);
      alert("Analysis failed. Spatial intelligence engine encountered an error.");
    } finally {
      setLoading(false);
    }
  };

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('en-IN', {
      style: 'currency',
      currency: result?.revenueProjections.currency || 'INR',
      maximumFractionDigits: 0,
    }).format(val);
  };

  const filteredCompetition = useMemo(() => {
    if (!result) return [];
    if (competitionFilter === 'All') return result.metrics.storeCompetition;
    return result.metrics.storeCompetition.filter(c => c.type === competitionFilter);
  }, [result, competitionFilter]);

  const competitionTypes = useMemo(() => {
    if (!result) return [];
    const types = Array.from(new Set(result.metrics.storeCompetition.map(c => c.type)));
    return ['All', ...types];
  }, [result]);

  return (
    <div className="relative min-h-screen bg-slate-950">
      {/* SECTION 1: INTERACTIVE 3D MAP */}
      <section className="relative h-screen w-full overflow-hidden">

        {/* Map Container */}
        <div ref={mapContainer} className="absolute inset-0 z-0 bg-slate-900" />

        {/* Center Crosshair (Precision Pointing) */}
        <div className="map-crosshair">
            <div className="crosshair-ring" />
            <div className="crosshair-dot" />
            <div className="absolute -bottom-10 flex flex-col items-center">
               <span className="text-[9px] font-black text-white bg-indigo-600 px-3 py-1 rounded-full uppercase tracking-widest shadow-2xl">
                 Analysis Target
               </span>
               <div className="text-[8px] font-bold text-slate-400 mt-1 drop-shadow-lg">
                 {input.coordinates?.lat.toFixed(5)}, {input.coordinates?.lng.toFixed(5)}
               </div>
            </div>
        </div>

        {/* Floating Map Controls */}
        <div className="absolute top-6 right-6 z-[1001] flex flex-col gap-3">
            <button 
                onClick={toggle3D}
                className={`p-4 rounded-2xl border transition-all shadow-2xl flex items-center justify-center gap-3 font-black text-[10px] uppercase tracking-widest ${is3D ? 'bg-indigo-600 text-white border-indigo-400' : 'bg-white/90 backdrop-blur-xl text-slate-800 border-white/40'}`}
            >
                <Box size={18} /> {is3D ? 'Flatten View' : 'Enable 3D'}
            </button>
            <div className="flex flex-col gap-1">
                <button 
                    onClick={() => map.current?.easeTo({ bearing: 0, duration: 800 })}
                    className="p-4 bg-white/90 backdrop-blur-xl rounded-2xl border border-white/40 shadow-2xl flex items-center justify-center gap-3 font-black text-[10px] uppercase tracking-widest text-slate-800 hover:bg-white transition-all"
                >
                    <Compass size={18} /> Reset North
                </button>
                <button 
                    onClick={resetMap}
                    className="p-4 bg-white/90 backdrop-blur-xl rounded-2xl border border-white/40 shadow-2xl flex items-center justify-center gap-3 font-black text-[10px] uppercase tracking-widest text-slate-800 hover:bg-white transition-all"
                >
                    <Home size={18} /> Origin
                </button>
            </div>
            <div className="p-4 bg-indigo-950/80 backdrop-blur-xl rounded-2xl border border-indigo-500/30 text-white/70 text-[8px] font-black uppercase tracking-widest space-y-2 max-w-[120px]">
               <div className="flex items-center gap-2">
                 <MousePointer size={10} className="text-indigo-400" /> Right-click to rotate
               </div>
               <div className="flex items-center gap-2">
                 <MousePointer size={10} className="text-indigo-400" /> Scroll to zoom
               </div>
            </div>
        </div>

        {/* Floating Header */}
        <header className="absolute top-6 left-6 z-[1001] pointer-events-none">
            <div className="flex items-center space-x-2 pointer-events-auto bg-white/80 backdrop-blur-2xl px-6 py-4 rounded-2xl border border-white/40 shadow-2xl">
              <div className="bg-indigo-600 p-2.5 rounded-xl shadow-lg shadow-indigo-200">
                <Sparkles className="text-white w-5 h-5" />
              </div>
