  'Large Attraction (e.g., Zoo / Theme Park)',
  'Supermarket (e.g., Reliance Fresh / DMart)',
  'Luxury Fashion / Boutique',
  'Pharmacy / Wellness',
  'Fine Dining Restaurant',
  'Workspace / Coworking',
  'Quick Service Restaurant (QSR)'
];

const INITIAL_POS = { lat: 19.0596, lng: 72.8295 }; // Bandra West, Mumbai

interface ValidationErrors {
  length?: string;
  breadth?: string;
  floors?: string;
  heightPerFloor?: string;
}

const App: React.FC = () => {
  const mapContainer = useRef<HTMLDivElement>(null);
  const map = useRef<maplibregl.Map | null>(null);
  const [loading, setLoading] = useState(false);
  const [searching, setSearching] = useState(false);
  const [is3D, setIs3D] = useState(true);
  const [isCategoryOpen, setIsCategoryOpen] = useState(false);
  const categoryRef = useRef<HTMLDivElement>(null);
  const [errors, setErrors] = useState<ValidationErrors>({});

  const [input, setInput] = useState<StoreInput>({
    location: 'Bandra West, Mumbai',
    coordinates: { ...INITIAL_POS },
    category: 'Premium Cafe (e.g., Starbucks)',
    length: 40,
    breadth: 50,
    floors: 1,
    heightPerFloor: 12,
    targetSegment: ['Gen-Z Trendsetters', 'Young Professionals']
  });

  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [competitionFilter, setCompetitionFilter] = useState<string>('All');
  const resultsRef = useRef<HTMLDivElement>(null);

  // Initialize MapLibre
  useEffect(() => {
    if (!mapContainer.current) return;

    try {
      // In some environments, worker-based loading fails. Setting workerCount to 1 often helps.
      (maplibregl as any).workerCount = 1;

      map.current = new maplibregl.Map({
        container: mapContainer.current,
        style: 'https://tiles.basemaps.cartocdn.com/gl/dark-matter-gl-style/style.json',
        center: [INITIAL_POS.lng, INITIAL_POS.lat],
        zoom: 17,
        pitch: 60,
        bearing: -15,
        antialias: true,
        attributionControl: false,
        transformRequest: (url) => {
          if (url.startsWith('./') || url.startsWith('../')) {
            return { url: new URL(url, window.location.href).href };
          }
          return { url };
        }
      });

      map.current.on('load', () => {
        if (!map.current) return;

        const layers = map.current.getStyle().layers;
        let labelLayerId;
        if (layers) {
            for (let i = 0; i < layers.length; i++) {
                if (layers[i].type === 'symbol' && (layers[i].layout as any)?.['text-field']) {
                    labelLayerId = layers[i].id;
                    break;
                }
            }
        }

        map.current.addLayer({
            'id': '3d-buildings',
            'source': 'openmaptiles',
            'source-layer': 'building',
            'type': 'fill-extrusion',
            'minzoom': 15,
            'paint': {
                'fill-extrusion-color': '#4f46e5',
                'fill-extrusion-height': ['get', 'render_height'],
                'fill-extrusion-base': ['get', 'render_min_height'],
                'fill-extrusion-opacity': 0.6
            }
        }, labelLayerId);
      });

      map.current.on('move', () => {
        if (!map.current) return;
        const center = map.current.getCenter();
        setInput(prev => ({
          ...prev,
          coordinates: { lat: center.lat, lng: center.lng }
        }));
      });

      map.current.on('error', (e) => {
        console.debug('Handled map instance error silently.');
      });

    } catch (err) {
      console.error('Critical MapLibre failure: Initialization error caught.');
    }

    return () => map.current?.remove();
  }, []);

  const toggle3D = () => {
    if (!map.current) return;
    const new3D = !is3D;
    setIs3D(new3D);
    map.current.easeTo({
      pitch: new3D ? 60 : 0,
      duration: 1000
    });
  };

  const resetMap = () => {
    if (!map.current) return;
    map.current.flyTo({
      center: [INITIAL_POS.lng, INITIAL_POS.lat],
      zoom: 17,
      pitch: 60,
      bearing: -15,
      duration: 2000
    });
    setErrors({});
    setInput({ 
      location: 'Bandra West, Mumbai',
      coordinates: { ...INITIAL_POS },
      category: 'Premium Cafe (e.g., Starbucks)',
      length: 40,
      breadth: 50,
      floors: 1,
      heightPerFloor: 12,
      targetSegment: ['Gen-Z Trendsetters', 'Young Professionals']
    });
  };

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (categoryRef.current && !categoryRef.current.contains(event.target as Node)) {
        setIsCategoryOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const validate = (name: keyof ValidationErrors, value: number) => {
    let error = '';
    switch (name) {
      case 'length':
      case 'breadth':
        if (value <= 0) error = 'Must be > 0';
        else if (value > 5000) error = 'Max 5000ft';
        break;
      case 'floors':
        if (value < 1) error = 'Min 1 floor';
        else if (value > 163) error = 'Max 163 floors';
        break;
      case 'heightPerFloor':
        if (value < 5) error = 'Min 5ft';
        else if (value > 100) error = 'Max 100ft';
        break;
    }
    setErrors(prev => ({ ...prev, [name]: error }));
    return error === '';
  };

  const handleInputChange = (name: keyof StoreInput, value: any) => {
    setInput(prev => ({ ...prev, [name]: value }));
    if (['length', 'breadth', 'floors', 'heightPerFloor'].includes(name)) {
      validate(name as keyof ValidationErrors, Number(value));
    }
  };

  const handleSearchSync = async () => {
    if (!input.location.trim()) return;
    setSearching(true);
    try {
      const response = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(input.location)}`);
      const data = await response.json();
      if (data && data.length > 0) {
        const lat = parseFloat(data[0].lat);
        const lng = parseFloat(data[0].lon);
        map.current?.flyTo({
          center: [lng, lat],
          zoom: 18,
          essential: true,
          duration: 3000
        });
      }
    } catch (e) {
      console.warn("Geocoding service unavailable.");
    } finally {
      setSearching(false);
    }
  };

  const handleAnalyze = async (e: React.FormEvent) => {
    e.preventDefault();
    const v1 = validate('length', input.length);
    const v2 = validate('breadth', input.breadth);
    const v3 = validate('floors', input.floors);
    const v4 = validate('heightPerFloor', input.heightPerFloor);
    if (!v1 || !v2 || !v3 || !v4) return;

    setLoading(true);
    setResult(null);
    setCompetitionFilter('All');

    setTimeout(() => {
        resultsRef.current?.scrollIntoView({ behavior: 'smooth' });
    }, 100);

    try {
      // Clean clone input to avoid any hidden circular references from React state trackers
      const cleanedInput = JSON.parse(JSON.stringify(input));
      const data = await GeminiService.analyzeMarket(cleanedInput);
      setResult(data);
    } catch (err: any) {
      console.error('Market analysis synthesis failed.');
      alert("Analysis failed. Spatial intelligence engine encountered an error.");
    } finally {
      setLoading(false);
    }
  };

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('en-IN', {
      style: 'currency',
      currency: result?.revenueProjections.currency || 'INR',
      maximumFractionDigits: 0,
    }).format(val);
  };

  const filteredCompetition = useMemo(() => {
    if (!result) return [];
    if (competitionFilter === 'All') return result.metrics.storeCompetition;
    return result.metrics.storeCompetition.filter(c => c.type === competitionFilter);
  }, [result, competitionFilter]);

  const competitionTypes = useMemo(() => {
    if (!result) return [];
    const types = Array.from(new Set(result.metrics.storeCompetition.map(c => c.type)));
    return ['All', ...types];
  }, [result]);

  return (
    <div className="relative min-h-screen bg-slate-950">
      <section className="relative h-screen w-full overflow-hidden">
        <div ref={mapContainer} className="absolute inset-0 z-0 bg-slate-900" />

        <div className="map-crosshair">
            <div className="crosshair-ring" />
            <div className="crosshair-dot" />
            <div className="absolute -bottom-10 flex flex-col items-center">
               <span className="text-[9px] font-black text-white bg-indigo-600 px-3 py-1 rounded-full uppercase tracking-widest shadow-2xl">
                 Analysis Target
               </span>
               <div className="text-[8px] font-bold text-slate-400 mt-1 drop-shadow-lg">
                 {input.coordinates?.lat.toFixed(5)}, {input.coordinates?.lng.toFixed(5)}
               </div>
            </div>
        </div>

        <div className="absolute top-6 right-6 z-[1001] flex flex-col gap-3">
            <button 
                onClick={toggle3D}
                className={`p-4 rounded-2xl border transition-all shadow-2xl flex items-center justify-center gap-3 font-black text-[10px] uppercase tracking-widest ${is3D ? 'bg-indigo-600 text-white border-indigo-400' : 'bg-white/90 backdrop-blur-xl text-slate-800 border-white/40'}`}
            >
                <Box size={18} /> {is3D ? 'Flatten View' : 'Enable 3D'}
            </button>
            <div className="flex flex-col gap-1">
                <button 
                    onClick={() => map.current?.easeTo({ bearing: 0, duration: 800 })}
                    className="p-4 bg-white/90 backdrop-blur-xl rounded-2xl border border-white/40 shadow-2xl flex items-center justify-center gap-3 font-black text-[10px] uppercase tracking-widest text-slate-800 hover:bg-white transition-all"
                >
                    <Compass size={18} /> Reset North
                </button>
                <button 
                    onClick={resetMap}
                    className="p-4 bg-white/90 backdrop-blur-xl rounded-2xl border border-white/40 shadow-2xl flex items-center justify-center gap-3 font-black text-[10px] uppercase tracking-widest text-slate-800 hover:bg-white transition-all"
                >
                    <Home size={18} /> Origin
                </button>
            </div>
        </div>

        <header className="absolute top-6 left-6 z-[1001] pointer-events-none">
            <div className="flex items-center space-x-2 pointer-events-auto bg-white/80 backdrop-blur-2xl px-6 py-4 rounded-2xl border border-white/40 shadow-2xl">
              <div className="bg-indigo-600 p-2.5 rounded-xl shadow-lg shadow-indigo-200">
                <Sparkles className="text-white w-5 h-5" />
              </div>
              <div className="flex flex-col">
                <span className="text-xl font-black bg-clip-text text-transparent bg-gradient-to-r from-indigo-600 to-violet-600 tracking-tight leading-none">
                  LocalityMind
                </span>
                <span className="text-[8px] font-black uppercase tracking-[0.3em] text-slate-400 mt-1">3D Spatial Recon</span>
              </div>
            </div>
        </header>

        <div className="absolute top-1/2 -translate-y-1/2 left-6 z-[1001] w-full max-w-md pointer-events-none">
            <div className="pointer-events-auto glass-panel p-8 rounded-[3rem] shadow-[0_32px_80px_-20px_rgba(0,0,0,0.4)] space-y-6 border border-white/40">
                <div className="flex items-center justify-between">
                    <h3 className="text-xs font-black text-slate-900 uppercase tracking-[0.2em] flex items-center gap-2">
                        <Building2 className="w-4 h-4 text-indigo-700" />
                        Target Parameters
                    </h3>
                </div>

                <div className="space-y-4">
                    <div className="relative group">
                        <MapPin className="absolute left-4 top-1/2 -translate-y-1/2 text-indigo-800 w-4 h-4" />
                        <input
                            type="text"
                            placeholder="Locality Name..."
                            className="w-full pl-11 pr-12 py-4 bg-white/60 border border-white/80 rounded-2xl focus:ring-2 focus:ring-indigo-600 outline-none text-sm font-black text-slate-900 transition-all placeholder:text-slate-500 shadow-inner"
                            value={input.location}
                            onChange={(e) => handleInputChange('location', e.target.value)}
                            onKeyDown={(e) => e.key === 'Enter' && handleSearchSync()}
                        />
                        <button 
                            onClick={handleSearchSync}
                            disabled={searching}
                            className="absolute right-3 top-1/2 -translate-y-1/2 p-2 hover:bg-indigo-100 rounded-xl transition-colors text-indigo-600 disabled:opacity-50"
                        >
                            {searching ? <Loader2 size={18} className="animate-spin" /> : <Search size={18} />}
                        </button>
                    </div>

                    <div className="relative" ref={categoryRef}>
                        <button
                            type="button"
                            onClick={() => setIsCategoryOpen(!isCategoryOpen)}
                            className="w-full pl-11 pr-10 py-4 bg-white/60 border border-white/80 rounded-2xl text-left focus:ring-2 focus:ring-indigo-600 outline-none text-sm font-black text-slate-900 transition-all cursor-pointer shadow-inner relative"
                        >
                            <Store className="absolute left-4 top-1/2 -translate-y-1/2 text-indigo-800 w-4 h-4" />
                            <span className="block truncate">{input.category}</span>
                            <ChevronDown className={`absolute right-4 top-1/2 -translate-y-1/2 text-slate-900 w-4 h-4 transition-transform duration-300 ${isCategoryOpen ? 'rotate-180' : ''}`} />
                        </button>

                        {isCategoryOpen && (
                            <div className="absolute z-[1002] mt-2 w-full bg-white/95 backdrop-blur-3xl border border-white/60 rounded-3xl shadow-[0_20px_50px_-10px_rgba(0,0,0,0.3)] overflow-hidden animate-in fade-in zoom-in-95 duration-200">
                                <div className="max-h-[260px] overflow-y-auto custom-scrollbar">
                                    {STORE_CATEGORIES.map((cat) => (
                                        <button
                                            key={cat}
                                            type="button"
                                            onClick={() => {
                                                handleInputChange('category', cat);
                                                setIsCategoryOpen(false);
                                            }}
                                            className={`w-full px-6 py-4 text-left text-xs font-black uppercase tracking-widest transition-all flex items-center justify-between group ${input.category === cat ? 'bg-indigo-600 text-white' : 'text-slate-800 hover:bg-indigo-50 hover:text-indigo-700'}`}
                                        >
                                            {cat}
                                            {input.category === cat && <Check size={14} className="text-white" />}
                                        </button>
                                    ))}
                                </div>
                            </div>
                        )}
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                        <div className="relative group">
                            <BoxSelect className={`absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 transition-colors ${errors.length ? 'text-red-500' : 'text-indigo-800'}`} />
                            <input
                                type="number"
                                className={`w-full pl-11 pr-12 py-4 bg-white/60 border rounded-2xl text-xs font-black text-slate-900 focus:ring-2 transition-all shadow-inner ${errors.length ? 'border-red-400 focus:ring-red-400' : 'border-white/80 focus:ring-indigo-600'}`}
                                value={input.length}
                                onChange={(e) => handleInputChange('length', Number(e.target.value))}
                            />
                            <span className="absolute right-4 top-1/2 -translate-y-1/2 text-[10px] font-black text-indigo-800/60 uppercase tracking-tighter">W(FT)</span>
                        </div>
                        <div className="relative group">
                            <BoxSelect className={`absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 transition-colors ${errors.breadth ? 'text-red-500' : 'text-indigo-800'}`} />
                            <input
                                type="number"
                                className={`w-full pl-11 pr-12 py-4 bg-white/60 border rounded-2xl text-xs font-black text-slate-900 focus:ring-2 transition-all shadow-inner ${errors.breadth ? 'border-red-400 focus:ring-red-400' : 'border-white/80 focus:ring-indigo-600'}`}
                                value={input.breadth}
                                onChange={(e) => handleInputChange('breadth', Number(e.target.value))}
                            />
                            <span className="absolute right-4 top-1/2 -translate-y-1/2 text-[10px] font-black text-indigo-800/60 uppercase tracking-tighter">D(FT)</span>
                        </div>
                    </div>

                    <button
                        onClick={handleAnalyze}
                        disabled={loading || Object.values(errors).some(e => e !== '')}
                        className="w-full h-16 bg-indigo-600 hover:bg-indigo-700 text-white rounded-[2rem] font-black text-xs uppercase tracking-[0.3em] flex items-center justify-center gap-4 transition-all disabled:opacity-50 disabled:cursor-not-allowed shadow-2xl shadow-indigo-600/40 active:scale-[0.98]"
                    >
                        {loading ? <Loader2 className="animate-spin" /> : <><TrendingUp size={20} /> Deep Market Scan</>}
                    </button>
                </div>
            </div>
        </div>

        <div className="absolute bottom-8 left-1/2 -translate-x-1/2 z-[1001] flex flex-col items-center gap-2 pointer-events-none">
            <span className="text-[10px] font-black text-white uppercase tracking-[0.4em] drop-shadow-lg opacity-80">View Intelligence</span>
            <ChevronDown className="text-white drop-shadow-lg animate-bounce" />
        </div>
      </section>

      <section ref={resultsRef} className="relative z-[10] bg-slate-50 min-h-screen py-32 px-6 sm:px-12 border-t border-slate-200">
        <div className="max-w-7xl mx-auto">
            {!result && !loading && (
                <div className="max-w-3xl mx-auto flex flex-col items-center text-center space-y-12 py-32">
                    <div className="relative p-12 bg-white rounded-[4rem] shadow-2xl border border-slate-100">
                        <CircleDollarSign size={100} className="text-slate-200" />
                    </div>
                    <div className="space-y-6">
                        <h3 className="text-5xl font-black text-slate-900 tracking-tighter uppercase tracking-widest">Awaiting Analysis</h3>
                        <p className="text-slate-500 text-xl font-medium leading-relaxed max-w-xl mx-auto">
                            Point the crosshair at a commercial node to trigger 3D spatial market intelligence synthesis.
                        </p>
                    </div>
                </div>
            )}

            {loading && (
               <div className="max-w-5xl mx-auto flex flex-col items-center justify-center p-24 text-center bg-white border border-slate-100 rounded-[5rem] shadow-2xl relative overflow-hidden">
                 <div className="relative mb-16 scale-110">
                    <div className="w-48 h-48 border-[16px] border-indigo-50 rounded-full animate-pulse"></div>
                    <div className="absolute inset-0 border-t-[16px] border-indigo-600 rounded-full animate-spin"></div>
                    <div className="absolute inset-0 flex items-center justify-center">
                       <Sparkles className="w-16 h-16 text-indigo-600" />
                    </div>
                 </div>
                 <h3 className="text-4xl font-black text-slate-900 mb-4 uppercase tracking-tighter">Locality Fusion Active</h3>
               </div>
            )}

            {result && (
              <div className="space-y-16 animate-in fade-in slide-in-from-bottom-20 duration-1000">
                <div className="bg-gradient-to-br from-indigo-800 to-violet-950 text-white p-16 rounded-[5rem] shadow-[0_50px_100px_-20px_rgba(79,70,229,0.3)] relative overflow-hidden">
                  <div className="relative z-10 flex flex-col lg:flex-row gap-16 items-start justify-between">
                    <div className="space-y-8">
                        <div className="inline-flex items-center gap-3 px-6 py-2.5 bg-white/10 backdrop-blur-3xl rounded-full text-xs font-black uppercase tracking-[0.4em] border border-white/20">
                            <Shuffle size={14} className="text-indigo-300" /> 3D Spatial Insights
                        </div>
                        <h2 className="text-7xl font-black tracking-tighter leading-none">{result.localityName}</h2>
                        <div className="flex flex-wrap items-center gap-8">
                            <div className="flex items-center gap-3 text-indigo-200 text-sm font-black tracking-widest uppercase">
                                <MapPin size={20} /> {input.coordinates?.lat.toFixed(5)}, {input.coordinates?.lng.toFixed(5)}
                            </div>
                        </div>
                    </div>

                    <div className="flex flex-col gap-6 min-w-[360px] w-full lg:w-auto">
                        <div className="bg-white/10 backdrop-blur-3xl p-10 rounded-[3rem] border border-white/20 shadow-2xl">
                            <div className="text-indigo-300 text-[11px] font-black uppercase mb-3 tracking-[0.3em]">Estimated Avg PCI</div>
                            <div className="text-5xl font-black">{formatCurrency(result.demographics.perCapitaIncome)}</div>
                        </div>
                        <div className="bg-white/10 backdrop-blur-3xl p-10 rounded-[3rem] border border-white/20 shadow-2xl">
                            <div className="text-indigo-300 text-[11px] font-black uppercase mb-3 tracking-[0.3em]">Neighborhood Type</div>
                            <div className="text-4xl font-black">{result.demographics.residentType} Hub</div>
                        </div>
                    </div>
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
                    <MetricCard 
                        title="Daily Footfall" 
                        value={result.metrics.footfallEstimate.daily.toLocaleString()} 
                        Icon={Users}
                        colorClass="bg-white p-10 rounded-[4rem] border-2 border-indigo-50 shadow-xl"
                    />
                    <MetricCard 
                        title="Dominant Vehicles" 
                        value={result.demographics.dominantCarTypes[0] || 'N/A'} 
                        Icon={Car}
                        subtitle={`${result.demographics.socioeconomicTier} Tier Indicator`}
                        colorClass="bg-white p-10 rounded-[4rem] border-2 border-indigo-50 shadow-xl"
                    />
                    <MetricCard 
                        title="Peak Hourly Traffic" 
                        value={result.metrics.footfallEstimate.hourly.toLocaleString()} 
                        Icon={MousePointer2}
                        colorClass="bg-white p-10 rounded-[4rem] border-2 border-indigo-50 shadow-xl"
                    />
                    <MetricCard 
                        title="Retail Density" 
                        value={`x${result.metrics.storeCompetition.reduce((acc, curr) => acc + curr.count, 0)}`} 
                        Icon={Layers}
                        subtitle="Identified Competitors"
                        colorClass="bg-white p-10 rounded-[4rem] border-2 border-indigo-50 shadow-xl"
                    />
                </div>

                <div className="space-y-8">
                  <div className="flex items-center gap-4">
                    <div className="bg-indigo-600 p-2 rounded-xl text-white shadow-lg shadow-indigo-200">
                      <Activity size={20} />
                    </div>
                    <h3 className="text-xl font-black text-slate-900 tracking-tight uppercase tracking-widest">Traffic Landscape</h3>
                  </div>
                  <TrafficLandscape data={JSON.parse(JSON.stringify(result.metrics.footfallEstimate.hourlyDistribution))} />
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-3 gap-12">
                    <div className="lg:col-span-2">
                        <RevenueChart projections={{...result.revenueProjections}} />
                    </div>

                    <div className="bg-slate-950 text-white p-12 rounded-[4rem] shadow-3xl relative overflow-hidden flex flex-col justify-between">
                        <div>
                            <h3 className="text-xs font-black text-indigo-500 uppercase tracking-[0.5em] mb-12">Strategic AI Directives</h3>
                            <div className="space-y-8">
                                {result.strategicAdvice.map((advice, i) => (
                                <div key={i} className="flex gap-6 group">
                                    <div className="flex-shrink-0 w-10 h-10 rounded-2xl bg-indigo-600 flex items-center justify-center font-black text-sm text-white shadow-xl shadow-indigo-600/30">
                                    {i + 1}
                                    </div>
                                    <p className="text-slate-400 text-base leading-relaxed font-semibold">
                                    {advice}
                                    </p>
                                </div>
                                ))}
                            </div>
                        </div>
                    </div>
                </div>
              </div>
            )}
        </div>
      </section>

      <footer className="py-20 text-center text-slate-500 text-[10px] font-black uppercase tracking-[0.6em] bg-slate-50">
        <p>© 2024 LocalityMind 3D Spatial Intelligence • Precision Market Analysis</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef, useMemo } from 'react';
import { 
  MapPin, Store, TrendingUp, Users, Car, Search, 
  Loader2, ExternalLink, Sparkles, Layers, 
  CircleDollarSign, ChevronDown, Building2, BoxSelect,
  RotateCcw, Target, MousePointer2, Info,
  Box, Globe, Home, ChevronUp, Check, AlertCircle,
  X, Plus, Briefcase, ShoppingBag, Landmark, Activity,
  Shuffle, Filter, MousePointer, Compass
} from 'lucide-react';
import maplibregl from 'maplibre-gl';
import { StoreInput, AnalysisResult, StoreCategory } from './types';
import { GeminiService } from './services/geminiService';
import { MetricCard } from './components/MetricCard';
import { RevenueChart } from './components/RevenueChart';
import { TrafficLandscape } from './components/TrafficLandscape';

const STORE_CATEGORIES: StoreCategory[] = [
  'Premium Cafe (e.g., Starbucks)',
  'Large Attraction (e.g., Zoo / Theme Park)',
  'Supermarket (e.g., Reliance Fresh / DMart)',
  'Luxury Fashion / Boutique',
  'Pharmacy / Wellness',
  'Fine Dining Restaurant',
  'Workspace / Coworking',
  'Quick Service Restaurant (QSR)'
];

const INITIAL_POS = { lat: 19.0596, lng: 72.8295 }; // Bandra West, Mumbai

interface ValidationErrors {
  length?: string;
  breadth?: string;
  floors?: string;
  heightPerFloor?: string;
}

const App: React.FC = () => {
  const mapContainer = useRef<HTMLDivElement>(null);
  const map = useRef<maplibregl.Map | null>(null);
  const [loading, setLoading] = useState(false);
  const [searching, setSearching] = useState(false);
  const [is3D, setIs3D] = useState(true);
  const [isCategoryOpen, setIsCategoryOpen] = useState(false);
  const categoryRef = useRef<HTMLDivElement>(null);
  const [errors, setErrors] = useState<ValidationErrors>({});

  const [input, setInput] = useState<StoreInput>({
    location: 'Bandra West, Mumbai',
    coordinates: { ...INITIAL_POS },
    category: 'Premium Cafe (e.g., Starbucks)',
    length: 40,
    breadth: 50,
    floors: 1,
    heightPerFloor: 12,
    targetSegment: ['Gen-Z Trendsetters', 'Young Professionals']
  });

  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [competitionFilter, setCompetitionFilter] = useState<string>('All');
  const resultsRef = useRef<HTMLDivElement>(null);

  // Initialize MapLibre
  useEffect(() => {
    if (!mapContainer.current) return;

    const initMap = () => {
        try {
          // Check for WebGL support
          const canvas = document.createElement('canvas');
          const gl = canvas.getContext('webgl') || canvas.getContext('experimental-webgl');
          if (!gl) {
            console.warn('WebGL not supported - map may fail to render.');
          }

          // Use workerCount = 1 to minimize background threads in restrictive environments
          (maplibregl as any).workerCount = 1;

          map.current = new maplibregl.Map({
            container: mapContainer.current!,
            style: 'https://tiles.basemaps.cartocdn.com/gl/dark-matter-gl-style/style.json',
            center: [INITIAL_POS.lng, INITIAL_POS.lat],
            zoom: 17,
            pitch: 60,
            bearing: -15,
            antialias: true,
            attributionControl: false,
            // Force external resolution to be absolute to avoid location resolution issues
            transformRequest: (url) => {
                if (url.startsWith('//')) return { url: 'https:' + url };
                return { url };
            }
          });

          map.current.on('load', () => {
            if (!map.current) return;

            const layers = map.current.getStyle().layers;
            let labelLayerId;
            if (layers) {
                for (let i = 0; i < layers.length; i++) {
                    if (layers[i].type === 'symbol' && (layers[i].layout as any)?.['text-field']) {
                        labelLayerId = layers[i].id;
                        break;
                    }
                }
            }

            map.current.addLayer({
                'id': '3d-buildings',
                'source': 'openmaptiles',
                'source-layer': 'building',
                'type': 'fill-extrusion',
                'minzoom': 15,
                'paint': {
                    'fill-extrusion-color': '#4f46e5',
                    'fill-extrusion-height': ['get', 'render_height'],
                    'fill-extrusion-base': ['get', 'render_min_height'],
                    'fill-extrusion-opacity': 0.6
                }
            }, labelLayerId);
          });

          map.current.on('move', () => {
            if (!map.current) return;
            const center = map.current.getCenter();
            setInput(prev => ({
              ...prev,
              coordinates: { lat: center.lat, lng: center.lng }
            }));
          });

          map.current.on('error', (e) => {
            // Silently handle map state errors
          });

        } catch (err) {
          console.error('MapLibre failed to initialize:', err);
        }
    };

    // Delay slightly to ensure DOM dimensions are ready
    const timer = setTimeout(initMap, 100);

    return () => {
        clearTimeout(timer);
        map.current?.remove();
    };
  }, []);

  const toggle3D = () => {
    if (!map.current) return;
    const new3D = !is3D;
    setIs3D(new3D);
    map.current.easeTo({
      pitch: new3D ? 60 : 0,
      duration: 1000
    });
  };

  const resetMap = () => {
    if (!map.current) return;
    map.current.flyTo({
      center: [INITIAL_POS.lng, INITIAL_POS.lat],
      zoom: 17,
      pitch: 60,
      bearing: -15,
      duration: 2000
    });
    setErrors({});
    setInput({ 
      location: 'Bandra West, Mumbai',
      coordinates: { ...INITIAL_POS },
      category: 'Premium Cafe (e.g., Starbucks)',
      length: 40,
      breadth: 50,
      floors: 1,
      heightPerFloor: 12,
      targetSegment: ['Gen-Z Trendsetters', 'Young Professionals']
    });
  };

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (categoryRef.current && !categoryRef.current.contains(event.target as Node)) {
        setIsCategoryOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const validate = (name: keyof ValidationErrors, value: number) => {
    let error = '';
    switch (name) {
      case 'length':
      case 'breadth':
        if (value <= 0) error = 'Must be > 0';
        else if (value > 5000) error = 'Max 5000ft';
        break;
      case 'floors':
        if (value < 1) error = 'Min 1 floor';
        else if (value > 163) error = 'Max 163 floors';
        break;
      case 'heightPerFloor':
        if (value < 5) error = 'Min 5ft';
        else if (value > 100) error = 'Max 100ft';
        break;
    }
    setErrors(prev => ({ ...prev, [name]: error }));
    return error === '';
  };

  const handleInputChange = (name: keyof StoreInput, value: any) => {
    setInput(prev => ({ ...prev, [name]: value }));
    if (['length', 'breadth', 'floors', 'heightPerFloor'].includes(name)) {
      validate(name as keyof ValidationErrors, Number(value));
    }
  };

  const handleSearchSync = async () => {
    if (!input.location.trim()) return;
    setSearching(true);
    try {
      const response = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(input.location)}`);
      const data = await response.json();
      if (data && data.length > 0) {
        const lat = parseFloat(data[0].lat);
        const lng = parseFloat(data[0].lon);
        map.current?.flyTo({
          center: [lng, lat],
          zoom: 18,
          essential: true,
          duration: 3000
        });
      }
    } catch (e) {
      console.warn("Geocoding service unavailable.");
    } finally {
      setSearching(false);
    }
  };

  const handleAnalyze = async (e: React.FormEvent) => {
    e.preventDefault();
    const v1 = validate('length', input.length);
    const v2 = validate('breadth', input.breadth);
    const v3 = validate('floors', input.floors);
    const v4 = validate('heightPerFloor', input.heightPerFloor);
    if (!v1 || !v2 || !v3 || !v4) return;

    setLoading(true);
    setResult(null);
    setCompetitionFilter('All');

    setTimeout(() => {
        resultsRef.current?.scrollIntoView({ behavior: 'smooth' });
    }, 100);

    try {
      // Direct pass without JSON stringify to prevent circular reference errors
      const data = await GeminiService.analyzeMarket(input);
      setResult(data);
    } catch (err: any) {
      console.error('Market analysis synthesis failed:', err);
      alert("Analysis failed. Spatial intelligence engine encountered an error.");
    } finally {
      setLoading(false);
    }
  };

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('en-IN', {
      style: 'currency',
      currency: result?.revenueProjections.currency || 'INR',
      maximumFractionDigits: 0,
    }).format(val);
  };

  const filteredCompetition = useMemo(() => {
    if (!result) return [];
    if (competitionFilter === 'All') return result.metrics.storeCompetition;
    return result.metrics.storeCompetition.filter(c => c.type === competitionFilter);
  }, [result, competitionFilter]);

  const competitionTypes = useMemo(() => {
    if (!result) return [];
    const types = Array.from(new Set(result.metrics.storeCompetition.map(c => c.type)));
    return ['All', ...types];
  }, [result]);

  return (
    <div className="relative min-h-screen bg-slate-950">
      <section className="relative h-screen w-full overflow-hidden">
        <div ref={mapContainer} className="absolute inset-0 z-0 bg-slate-900" />

        <div className="map-crosshair">
            <div className="crosshair-ring" />
            <div className="crosshair-dot" />
            <div className="absolute -bottom-10 flex flex-col items-center">
               <span className="text-[9px] font-black text-white bg-indigo-600 px-3 py-1 rounded-full uppercase tracking-widest shadow-2xl">
                 Analysis Target
               </span>
               <div className="text-[8px] font-bold text-slate-400 mt-1 drop-shadow-lg">
                 {input.coordinates?.lat.toFixed(5)}, {input.coordinates?.lng.toFixed(5)}
               </div>
            </div>
        </div>

        <div className="absolute top-6 right-6 z-[1001] flex flex-col gap-3">
            <button 
                onClick={toggle3D}
                className={`p-4 rounded-2xl border transition-all shadow-2xl flex items-center justify-center gap-3 font-black text-[10px] uppercase tracking-widest ${is3D ? 'bg-indigo-600 text-white border-indigo-400' : 'bg-white/90 backdrop-blur-xl text-slate-800 border-white/40'}`}
            >
                <Box size={18} /> {is3D ? 'Flatten View' : 'Enable 3D'}
            </button>
            <div className="flex flex-col gap-1">
                <button 
                    onClick={() => map.current?.easeTo({ bearing: 0, duration: 800 })}
                    className="p-4 bg-white/90 backdrop-blur-xl rounded-2xl border border-white/40 shadow-2xl flex items-center justify-center gap-3 font-black text-[10px] uppercase tracking-widest text-slate-800 hover:bg-white transition-all"
                >
                    <Compass size={18} /> Reset North
                </button>
                <button 
                    onClick={resetMap}
                    className="p-4 bg-white/90 backdrop-blur-xl rounded-2xl border border-white/40 shadow-2xl flex items-center justify-center gap-3 font-black text-[10px] uppercase tracking-widest text-slate-800 hover:bg-white transition-all"
                >
                    <Home size={18} /> Origin
                </button>
            </div>
        </div>

        <header className="absolute top-6 left-6 z-[1001] pointer-events-none">
            <div className="flex items-center space-x-2 pointer-events-auto bg-white/80 backdrop-blur-2xl px-6 py-4 rounded-2xl border border-white/40 shadow-2xl">
              <div className="bg-indigo-600 p-2.5 rounded-xl shadow-lg shadow-indigo-200">
                <Sparkles className="text-white w-5 h-5" />
              </div>
              <div className="flex flex-col">
                <span className="text-xl font-black bg-clip-text text-transparent bg-gradient-to-r from-indigo-600 to-violet-600 tracking-tight leading-none">
                  LocalityMind
                </span>
                <span className="text-[8px] font-black uppercase tracking-[0.3em] text-slate-400 mt-1">3D Spatial Recon</span>
              </div>
            </div>
        </header>

        <div className="absolute top-1/2 -translate-y-1/2 left-6 z-[1001] w-full max-w-md pointer-events-none">
            <div className="pointer-events-auto glass-panel p-8 rounded-[3rem] shadow-[0_32px_80px_-20px_rgba(0,0,0,0.4)] space-y-6 border border-white/40">
                <div className="flex items-center justify-between">
                    <h3 className="text-xs font-black text-slate-900 uppercase tracking-[0.2em] flex items-center gap-2">
                        <Building2 className="w-4 h-4 text-indigo-700" />
                        Target Parameters
                    </h3>
                </div>

                <div className="space-y-4">
                    <div className="relative group">
                        <MapPin className="absolute left-4 top-1/2 -translate-y-1/2 text-indigo-800 w-4 h-4" />
                        <input
                            type="text"
                            placeholder="Locality Name..."
                            className="w-full pl-11 pr-12 py-4 bg-white/60 border border-white/80 rounded-2xl focus:ring-2 focus:ring-indigo-600 outline-none text-sm font-black text-slate-900 transition-all placeholder:text-slate-500 shadow-inner"
                            value={input.location}
                            onChange={(e) => handleInputChange('location', e.target.value)}
                            onKeyDown={(e) => e.key === 'Enter' && handleSearchSync()}
                        />
                        <button 
                            onClick={handleSearchSync}
                            disabled={searching}
                            className="absolute right-3 top-1/2 -translate-y-1/2 p-2 hover:bg-indigo-100 rounded-xl transition-colors text-indigo-600 disabled:opacity-50"
                        >
                            {searching ? <Loader2 size={18} className="animate-spin" /> : <Search size={18} />}
                        </button>
                    </div>

                    <div className="relative" ref={categoryRef}>
                        <button
                            type="button"
                            onClick={() => setIsCategoryOpen(!isCategoryOpen)}
                            className="w-full pl-11 pr-10 py-4 bg-white/60 border border-white/80 rounded-2xl text-left focus:ring-2 focus:ring-indigo-600 outline-none text-sm font-black text-slate-900 transition-all cursor-pointer shadow-inner relative"
                        >
                            <Store className="absolute left-4 top-1/2 -translate-y-1/2 text-indigo-800 w-4 h-4" />
                            <span className="block truncate">{input.category}</span>
                            <ChevronDown className={`absolute right-4 top-1/2 -translate-y-1/2 text-slate-900 w-4 h-4 transition-transform duration-300 ${isCategoryOpen ? 'rotate-180' : ''}`} />
                        </button>

                        {isCategoryOpen && (
                            <div className="absolute z-[1002] mt-2 w-full bg-white/95 backdrop-blur-3xl border border-white/60 rounded-3xl shadow-[0_20px_50px_-10px_rgba(0,0,0,0.3)] overflow-hidden animate-in fade-in zoom-in-95 duration-200">
                                <div className="max-h-[260px] overflow-y-auto custom-scrollbar">
                                    {STORE_CATEGORIES.map((cat) => (
                                        <button
                                            key={cat}
                                            type="button"
                                            onClick={() => {
                                                handleInputChange('category', cat);
                                                setIsCategoryOpen(false);
                                            }}
                                            className={`w-full px-6 py-4 text-left text-xs font-black uppercase tracking-widest transition-all flex items-center justify-between group ${input.category === cat ? 'bg-indigo-600 text-white' : 'text-slate-800 hover:bg-indigo-50 hover:text-indigo-700'}`}
                                        >
                                            {cat}
                                            {input.category === cat && <Check size={14} className="text-white" />}
                                        </button>
                                    ))}
                                </div>
                            </div>
                        )}
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                        <div className="relative group">
                            <BoxSelect className={`absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 transition-colors ${errors.length ? 'text-red-500' : 'text-indigo-800'}`} />
                            <input
                                type="number"
                                className={`w-full pl-11 pr-12 py-4 bg-white/60 border rounded-2xl text-xs font-black text-slate-900 focus:ring-2 transition-all shadow-inner ${errors.length ? 'border-red-400 focus:ring-red-400' : 'border-white/80 focus:ring-indigo-600'}`}
                                value={input.length}
                                onChange={(e) => handleInputChange('length', Number(e.target.value))}
                            />
                            <span className="absolute right-4 top-1/2 -translate-y-1/2 text-[10px] font-black text-indigo-800/60 uppercase tracking-tighter">W(FT)</span>
                        </div>
                        <div className="relative group">
                            <BoxSelect className={`absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 transition-colors ${errors.breadth ? 'text-red-500' : 'text-indigo-800'}`} />
                            <input
                                type="number"
                                className={`w-full pl-11 pr-12 py-4 bg-white/60 border rounded-2xl text-xs font-black text-slate-900 focus:ring-2 transition-all shadow-inner ${errors.breadth ? 'border-red-400 focus:ring-red-400' : 'border-white/80 focus:ring-indigo-600'}`}
                                value={input.breadth}
                                onChange={(e) => handleInputChange('breadth', Number(e.target.value))}
                            />
                            <span className="absolute right-4 top-1/2 -translate-y-1/2 text-[10px] font-black text-indigo-800/60 uppercase tracking-tighter">D(FT)</span>
                        </div>
                    </div>

                    <button
                        onClick={handleAnalyze}
                        disabled={loading || Object.values(errors).some(e => e !== '')}
                        className="w-full h-16 bg-indigo-600 hover:bg-indigo-700 text-white rounded-[2rem] font-black text-xs uppercase tracking-[0.3em] flex items-center justify-center gap-4 transition-all disabled:opacity-50 disabled:cursor-not-allowed shadow-2xl shadow-indigo-600/40 active:scale-[0.98]"
                    >
                        {loading ? <Loader2 className="animate-spin" /> : <><TrendingUp size={20} /> Deep Market Scan</>}
                    </button>
                </div>
            </div>
        </div>

        <div className="absolute bottom-8 left-1/2 -translate-x-1/2 z-[1001] flex flex-col items-center gap-2 pointer-events-none">
            <span className="text-[10px] font-black text-white uppercase tracking-[0.4em] drop-shadow-lg opacity-80">View Intelligence</span>
            <ChevronDown className="text-white drop-shadow-lg animate-bounce" />
        </div>
      </section>

      <section ref={resultsRef} className="relative z-[10] bg-slate-50 min-h-screen py-32 px-6 sm:px-12 border-t border-slate-200">
        <div className="max-w-7xl mx-auto">
            {!result && !loading && (
                <div className="max-w-3xl mx-auto flex flex-col items-center text-center space-y-12 py-32">
                    <div className="relative p-12 bg-white rounded-[4rem] shadow-2xl border border-slate-100">
                        <CircleDollarSign size={100} className="text-slate-200" />
                    </div>
                    <div className="space-y-6">
                        <h3 className="text-5xl font-black text-slate-900 tracking-tighter uppercase tracking-widest">Awaiting Analysis</h3>
                        <p className="text-slate-500 text-xl font-medium leading-relaxed max-w-xl mx-auto">
                            Point the crosshair at a commercial node to trigger 3D spatial market intelligence synthesis.
                        </p>
                    </div>
                </div>
            )}

            {loading && (
               <div className="max-w-5xl mx-auto flex flex-col items-center justify-center p-24 text-center bg-white border border-slate-100 rounded-[5rem] shadow-2xl relative overflow-hidden">
                 <div className="relative mb-16 scale-110">
                    <div className="w-48 h-48 border-[16px] border-indigo-50 rounded-full animate-pulse"></div>
                    <div className="absolute inset-0 border-t-[16px] border-indigo-600 rounded-full animate-spin"></div>
                    <div className="absolute inset-0 flex items-center justify-center">
                       <Sparkles className="w-16 h-16 text-indigo-600" />
                    </div>
                 </div>
                 <h3 className="text-4xl font-black text-slate-900 mb-4 uppercase tracking-tighter">Locality Fusion Active</h3>
               </div>
            )}

            {result && (
              <div className="space-y-16 animate-in fade-in slide-in-from-bottom-20 duration-1000">
                <div className="bg-gradient-to-br from-indigo-800 to-violet-950 text-white p-16 rounded-[5rem] shadow-[0_50px_100px_-20px_rgba(79,70,229,0.3)] relative overflow-hidden">
                  <div className="relative z-10 flex flex-col lg:flex-row gap-16 items-start justify-between">
                    <div className="space-y-8">
                        <div className="inline-flex items-center gap-3 px-6 py-2.5 bg-white/10 backdrop-blur-3xl rounded-full text-xs font-black uppercase tracking-[0.4em] border border-white/20">
                            <Shuffle size={14} className="text-indigo-300" /> 3D Spatial Insights
                        </div>
                        <h2 className="text-7xl font-black tracking-tighter leading-none">{result.localityName}</h2>
                        <div className="flex flex-wrap items-center gap-8">
                            <div className="flex items-center gap-3 text-indigo-200 text-sm font-black tracking-widest uppercase">
                                <MapPin size={20} /> {input.coordinates?.lat.toFixed(5)}, {input.coordinates?.lng.toFixed(5)}
                            </div>
                        </div>
                    </div>

                    <div className="flex flex-col gap-6 min-w-[360px] w-full lg:w-auto">
                        <div className="bg-white/10 backdrop-blur-3xl p-10 rounded-[3rem] border border-white/20 shadow-2xl">
                            <div className="text-indigo-300 text-[11px] font-black uppercase mb-3 tracking-[0.3em]">Estimated Avg PCI</div>
                            <div className="text-5xl font-black">{formatCurrency(result.demographics.perCapitaIncome)}</div>
                        </div>
                        <div className="bg-white/10 backdrop-blur-3xl p-10 rounded-[3rem] border border-white/20 shadow-2xl">
                            <div className="text-indigo-300 text-[11px] font-black uppercase mb-3 tracking-[0.3em]">Neighborhood Type</div>
                            <div className="text-4xl font-black">{result.demographics.residentType} Hub</div>
                        </div>
                    </div>
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
                    <MetricCard 
                        title="Daily Footfall" 
                        value={result.metrics.footfallEstimate.daily.toLocaleString()} 
                        Icon={Users}
                        colorClass="bg-white p-10 rounded-[4rem] border-2 border-indigo-50 shadow-xl"
                    />
                    <MetricCard 
                        title="Dominant Vehicles" 
                        value={result.demographics.dominantCarTypes[0] || 'N/A'} 
                        Icon={Car}
                        subtitle={`${result.demographics.socioeconomicTier} Tier Indicator`}
                        colorClass="bg-white p-10 rounded-[4rem] border-2 border-indigo-50 shadow-xl"
                    />
                    <MetricCard 
                        title="Peak Hourly Traffic" 
                        value={result.metrics.footfallEstimate.hourly.toLocaleString()} 
                        Icon={MousePointer2}
                        colorClass="bg-white p-10 rounded-[4rem] border-2 border-indigo-50 shadow-xl"
                    />
                    <MetricCard 
                        title="Retail Density" 
                        value={`x${result.metrics.storeCompetition.reduce((acc, curr) => acc + curr.count, 0)}`} 
                        Icon={Layers}
                        subtitle="Identified Competitors"
                        colorClass="bg-white p-10 rounded-[4rem] border-2 border-indigo-50 shadow-xl"
                    />
                </div>

                <div className="space-y-8">
                  <div className="flex items-center gap-4">
                    <div className="bg-indigo-600 p-2 rounded-xl text-white shadow-lg shadow-indigo-200">
                      <Activity size={20} />
                    </div>
                    <h3 className="text-xl font-black text-slate-900 tracking-tight uppercase tracking-widest">Traffic Landscape</h3>
                  </div>
                  <TrafficLandscape data={result.metrics.footfallEstimate.hourlyDistribution} />
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-3 gap-12">
                    <div className="lg:col-span-2">
                        <RevenueChart projections={result.revenueProjections} />
                    </div>

                    <div className="bg-slate-950 text-white p-12 rounded-[4rem] shadow-3xl relative overflow-hidden flex flex-col justify-between">
                        <div>
                            <h3 className="text-xs font-black text-indigo-500 uppercase tracking-[0.5em] mb-12">Strategic AI Directives</h3>
                            <div className="space-y-8">
                                {result.strategicAdvice.map((advice, i) => (
                                <div key={i} className="flex gap-6 group">
                                    <div className="flex-shrink-0 w-10 h-10 rounded-2xl bg-indigo-600 flex items-center justify-center font-black text-sm text-white shadow-xl shadow-indigo-600/30">
                                    {i + 1}
                                    </div>
                                    <p className="text-slate-400 text-base leading-relaxed font-semibold">
                                    {advice}
                                    </p>
                                </div>
                                ))}
                            </div>
                        </div>
                    </div>
                </div>
              </div>
            )}
        </div>
      </section>

      <footer className="py-20 text-center text-slate-500 text-[10px] font-black uppercase tracking-[0.6em] bg-slate-50">
        <p>© 2024 LocalityMind 3D Spatial Intelligence • Precision Market Analysis</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef, useMemo } from 'react';
import { 
  MapPin, Store, TrendingUp, Users, Car, Search, 
  Loader2, ExternalLink, Sparkles, Layers, 
  CircleDollarSign, ChevronDown, Building2, BoxSelect,
  RotateCcw, Target, MousePointer2, Info,
  Box, Globe, Home, ChevronUp, Check, AlertCircle,
  X, Plus, Briefcase, ShoppingBag, Landmark, Activity,
  Shuffle, Filter, MousePointer, Compass
} from 'lucide-react';
import maplibregl from 'maplibre-gl';
import { StoreInput, AnalysisResult, StoreCategory } from './types';
import { GeminiService } from './services/geminiService';
import { MetricCard } from './components/MetricCard';
import { RevenueChart } from './components/RevenueChart';
import { TrafficLandscape } from './components/TrafficLandscape';

const STORE_CATEGORIES: StoreCategory[] = [
  'Premium Cafe (e.g., Starbucks)',
  'Large Attraction (e.g., Zoo / Theme Park)',
  'Supermarket (e.g., Reliance Fresh / DMart)',
  'Luxury Fashion / Boutique',
  'Pharmacy / Wellness',
  'Fine Dining Restaurant',
  'Workspace / Coworking',
  'Quick Service Restaurant (QSR)'
];

const INITIAL_POS = { lat: 19.0596, lng: 72.8295 }; // Bandra West, Mumbai

// Robust Dark Raster Style to avoid SecurityErrors with Vector/Worker logic
const DARK_RASTER_STYLE: any = {
  "version": 8,
  "sources": {
    "carto-dark": {
      "type": "raster",
      "tiles": [
        "https://a.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}.png",
        "https://b.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}.png",
        "https://c.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}.png",
        "https://d.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}.png"
      ],
      "tileSize": 256,
      "attribution": "&copy; CARTO &copy; OpenStreetMap",
      "maxzoom": 20
    }
  },
  "layers": [
    {
      "id": "carto-dark-layer",
      "type": "raster",
      "source": "carto-dark",
      "minzoom": 0,
      "maxzoom": 22
    }
  ]
};

interface ValidationErrors {
  length?: string;
  breadth?: string;
  floors?: string;
  heightPerFloor?: string;
}

const App: React.FC = () => {
  const mapContainer = useRef<HTMLDivElement>(null);
  const map = useRef<maplibregl.Map | null>(null);
  const [loading, setLoading] = useState(false);
  const [searching, setSearching] = useState(false);
  const [isCategoryOpen, setIsCategoryOpen] = useState(false);
  const categoryRef = useRef<HTMLDivElement>(null);
  const [errors, setErrors] = useState<ValidationErrors>({});

  const [input, setInput] = useState<StoreInput>({
    location: 'Bandra West, Mumbai',
    coordinates: { ...INITIAL_POS },
    category: 'Premium Cafe (e.g., Starbucks)',
    length: 40,
    breadth: 50,
    floors: 1,
    heightPerFloor: 12,
    targetSegment: ['Gen-Z Trendsetters', 'Young Professionals']
  });

  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [competitionFilter, setCompetitionFilter] = useState<string>('All');
  const resultsRef = useRef<HTMLDivElement>(null);

  // Initialize MapLibre
  useEffect(() => {
    if (!mapContainer.current) return;

    const timer = setTimeout(() => {
      try {
        // Force workerCount to 0 to minimize background complexity in sandboxes
        (maplibregl as any).workerCount = 0;

        map.current = new maplibregl.Map({
          container: mapContainer.current!,
          style: DARK_RASTER_STYLE,
          center: [INITIAL_POS.lng, INITIAL_POS.lat],
          zoom: 16,
          pitch: 0, // Raster styles usually don't support 3D pitch/bearing well
          bearing: 0,
          antialias: true,
          attributionControl: false
        });

        map.current.on('move', () => {
          if (!map.current) return;
          const center = map.current.getCenter();
          setInput(prev => ({
            ...prev,
            coordinates: { lat: center.lat, lng: center.lng }
          }));
        });

        map.current.on('error', () => {
          // Swallow internal errors
        });

      } catch (err) {
        console.error('Final MapLibre fallback failed.');
      }
    }, 150);

    return () => {
      clearTimeout(timer);
      map.current?.remove();
    };
  }, []);

  const resetMap = () => {
    if (!map.current) return;
    map.current.flyTo({
      center: [INITIAL_POS.lng, INITIAL_POS.lat],
      zoom: 16,
      duration: 2000
    });
    setErrors({});
    setInput({ 
      location: 'Bandra West, Mumbai',
      coordinates: { ...INITIAL_POS },
      category: 'Premium Cafe (e.g., Starbucks)',
      length: 40,
      breadth: 50,
      floors: 1,
      heightPerFloor: 12,
      targetSegment: ['Gen-Z Trendsetters', 'Young Professionals']
    });
  };

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (categoryRef.current && !categoryRef.current.contains(event.target as Node)) {
        setIsCategoryOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const validate = (name: keyof ValidationErrors, value: number) => {
    let error = '';
    switch (name) {
      case 'length':
      case 'breadth':
        if (value <= 0) error = 'Must be > 0';
        else if (value > 5000) error = 'Max 5000ft';
        break;
      case 'floors':
        if (value < 1) error = 'Min 1 floor';
        else if (value > 163) error = 'Max 163 floors';
        break;
      case 'heightPerFloor':
        if (value < 5) error = 'Min 5ft';
        else if (value > 100) error = 'Max 100ft';
        break;
    }
    setErrors(prev => ({ ...prev, [name]: error }));
    return error === '';
  };

  const handleInputChange = (name: keyof StoreInput, value: any) => {
    setInput(prev => ({ ...prev, [name]: value }));
    if (['length', 'breadth', 'floors', 'heightPerFloor'].includes(name)) {
      validate(name as keyof ValidationErrors, Number(value));
    }
  };

  const handleSearchSync = async () => {
    if (!input.location.trim()) return;
    setSearching(true);
    try {
      const response = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(input.location)}`);
      const data = await response.json();
      if (data && data.length > 0) {
        const lat = parseFloat(data[0].lat);
        const lng = parseFloat(data[0].lon);
        map.current?.flyTo({
          center: [lng, lat],
          zoom: 17,
          essential: true,
          duration: 3000
        });
      }
    } catch (e) {
      console.warn("Geocoding failed.");
    } finally {
      setSearching(false);
    }
  };

  const handleAnalyze = async (e: React.FormEvent) => {
    e.preventDefault();
    const v1 = validate('length', input.length);
    const v2 = validate('breadth', input.breadth);
    const v3 = validate('floors', input.floors);
    const v4 = validate('heightPerFloor', input.heightPerFloor);
    if (!v1 || !v2 || !v3 || !v4) return;

    setLoading(true);
    setResult(null);
    setCompetitionFilter('All');

    setTimeout(() => {
        resultsRef.current?.scrollIntoView({ behavior: 'smooth' });
    }, 100);

    try {
      const data = await GeminiService.analyzeMarket(input);
      setResult(data);
    } catch (err: any) {
      alert("Analysis failed. Spatial intelligence engine encountered an error.");
    } finally {
      setLoading(false);
    }
  };

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('en-IN', {
      style: 'currency',
      currency: result?.revenueProjections.currency || 'INR',
      maximumFractionDigits: 0,
    }).format(val);
  };

  const filteredCompetition = useMemo(() => {
    if (!result) return [];
    if (competitionFilter === 'All') return result.metrics.storeCompetition;
    return result.metrics.storeCompetition.filter(c => c.type === competitionFilter);
  }, [result, competitionFilter]);

  const competitionTypes = useMemo(() => {
    if (!result) return [];
    const types = Array.from(new Set(result.metrics.storeCompetition.map(c => c.type)));
    return ['All', ...types];
  }, [result]);

  return (
    <div className="relative min-h-screen bg-slate-950">
      <section className="relative h-screen w-full overflow-hidden">
        <div ref={mapContainer} className="absolute inset-0 z-0 bg-slate-900" />

        <div className="map-crosshair">
            <div className="crosshair-ring" />
            <div className="crosshair-dot" />
            <div className="absolute -bottom-10 flex flex-col items-center">
               <span className="text-[9px] font-black text-white bg-indigo-600 px-3 py-1 rounded-full uppercase tracking-widest shadow-2xl">
                 Analysis Target
               </span>
               <div className="text-[8px] font-bold text-slate-400 mt-1 drop-shadow-lg">
                 {input.coordinates?.lat.toFixed(5)}, {input.coordinates?.lng.toFixed(5)}
               </div>
            </div>
        </div>

        <div className="absolute top-6 right-6 z-[1001] flex flex-col gap-3">
            <button 
                onClick={resetMap}
                className="p-4 bg-white/90 backdrop-blur-xl rounded-2xl border border-white/40 shadow-2xl flex items-center justify-center gap-3 font-black text-[10px] uppercase tracking-widest text-slate-800 hover:bg-white transition-all"
            >
                <Home size={18} /> Origin
            </button>
        </div>

        <header className="absolute top-6 left-6 z-[1001] pointer-events-none">
            <div className="flex items-center space-x-2 pointer-events-auto bg-white/80 backdrop-blur-2xl px-6 py-4 rounded-2xl border border-white/40 shadow-2xl">
              <div className="bg-indigo-600 p-2.5 rounded-xl shadow-lg shadow-indigo-200">
                <Sparkles className="text-white w-5 h-5" />
              </div>
              <div className="flex flex-col">
                <span className="text-xl font-black bg-clip-text text-transparent bg-gradient-to-r from-indigo-600 to-violet-600 tracking-tight leading-none">
                  LocalityMind
                </span>
                <span className="text-[8px] font-black uppercase tracking-[0.3em] text-slate-400 mt-1">Spatial Recon</span>
              </div>
            </div>
        </header>

        <div className="absolute top-1/2 -translate-y-1/2 left-6 z-[1001] w-full max-w-md pointer-events-none">
            <div className="pointer-events-auto glass-panel p-8 rounded-[3rem] shadow-[0_32px_80px_-20px_rgba(0,0,0,0.4)] space-y-6 border border-white/40">
                <div className="flex items-center justify-between">
                    <h3 className="text-xs font-black text-slate-900 uppercase tracking-[0.2em] flex items-center gap-2">
                        <Building2 className="w-4 h-4 text-indigo-700" />
                        Target Parameters
                    </h3>
                </div>

                <div className="space-y-4">
                    <div className="relative group">
                        <MapPin className="absolute left-4 top-1/2 -translate-y-1/2 text-indigo-800 w-4 h-4" />
                        <input
                            type="text"
                            placeholder="Locality Name..."
                            className="w-full pl-11 pr-12 py-4 bg-white/60 border border-white/80 rounded-2xl focus:ring-2 focus:ring-indigo-600 outline-none text-sm font-black text-slate-900 transition-all placeholder:text-slate-500 shadow-inner"
                            value={input.location}
                            onChange={(e) => handleInputChange('location', e.target.value)}
                            onKeyDown={(e) => e.key === 'Enter' && handleSearchSync()}
                        />
                        <button 
                            onClick={handleSearchSync}
                            disabled={searching}
                            className="absolute right-3 top-1/2 -translate-y-1/2 p-2 hover:bg-indigo-100 rounded-xl transition-colors text-indigo-600 disabled:opacity-50"
                        >
                            {searching ? <Loader2 size={18} className="animate-spin" /> : <Search size={18} />}
                        </button>
                    </div>

                    <div className="relative" ref={categoryRef}>
                        <button
                            type="button"
                            onClick={() => setIsCategoryOpen(!isCategoryOpen)}
                            className="w-full pl-11 pr-10 py-4 bg-white/60 border border-white/80 rounded-2xl text-left focus:ring-2 focus:ring-indigo-600 outline-none text-sm font-black text-slate-900 transition-all cursor-pointer shadow-inner relative"
                        >
                            <Store className="absolute left-4 top-1/2 -translate-y-1/2 text-indigo-800 w-4 h-4" />
                            <span className="block truncate">{input.category}</span>
                            <ChevronDown className={`absolute right-4 top-1/2 -translate-y-1/2 text-slate-900 w-4 h-4 transition-transform duration-300 ${isCategoryOpen ? 'rotate-180' : ''}`} />
                        </button>

                        {isCategoryOpen && (
                            <div className="absolute z-[1002] mt-2 w-full bg-white/95 backdrop-blur-3xl border border-white/60 rounded-3xl shadow-[0_20px_50px_-10px_rgba(0,0,0,0.3)] overflow-hidden animate-in fade-in zoom-in-95 duration-200">
                                <div className="max-h-[260px] overflow-y-auto custom-scrollbar">
                                    {STORE_CATEGORIES.map((cat) => (
                                        <button
                                            key={cat}
                                            type="button"
                                            onClick={() => {
                                                handleInputChange('category', cat);
                                                setIsCategoryOpen(false);
                                            }}
                                            className={`w-full px-6 py-4 text-left text-xs font-black uppercase tracking-widest transition-all flex items-center justify-between group ${input.category === cat ? 'bg-indigo-600 text-white' : 'text-slate-800 hover:bg-indigo-50 hover:text-indigo-700'}`}
                                        >
                                            {cat}
                                            {input.category === cat && <Check size={14} className="text-white" />}
                                        </button>
                                    ))}
                                </div>
                            </div>
                        )}
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                        <div className="relative group">
                            <BoxSelect className={`absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 transition-colors ${errors.length ? 'text-red-500' : 'text-indigo-800'}`} />
                            <input
                                type="number"
                                className={`w-full pl-11 pr-12 py-4 bg-white/60 border rounded-2xl text-xs font-black text-slate-900 focus:ring-2 transition-all shadow-inner ${errors.length ? 'border-red-400 focus:ring-red-400' : 'border-white/80 focus:ring-indigo-600'}`}
                                value={input.length}
                                onChange={(e) => handleInputChange('length', Number(e.target.value))}
                            />
                            <span className="absolute right-4 top-1/2 -translate-y-1/2 text-[10px] font-black text-indigo-800/60 uppercase tracking-tighter">W(FT)</span>
                        </div>
                        <div className="relative group">
                            <BoxSelect className={`absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 transition-colors ${errors.breadth ? 'text-red-500' : 'text-indigo-800'}`} />
                            <input
                                type="number"
                                className={`w-full pl-11 pr-12 py-4 bg-white/60 border rounded-2xl text-xs font-black text-slate-900 focus:ring-2 transition-all shadow-inner ${errors.breadth ? 'border-red-400 focus:ring-red-400' : 'border-white/80 focus:ring-indigo-600'}`}
                                value={input.breadth}
                                onChange={(e) => handleInputChange('breadth', Number(e.target.value))}
                            />
                            <span className="absolute right-4 top-1/2 -translate-y-1/2 text-[10px] font-black text-indigo-800/60 uppercase tracking-tighter">D(FT)</span>
                        </div>
                    </div>

                    <button
                        onClick={handleAnalyze}
                        disabled={loading || Object.values(errors).some(e => e !== '')}
                        className="w-full h-16 bg-indigo-600 hover:bg-indigo-700 text-white rounded-[2rem] font-black text-xs uppercase tracking-[0.3em] flex items-center justify-center gap-4 transition-all disabled:opacity-50 disabled:cursor-not-allowed shadow-2xl shadow-indigo-600/40 active:scale-[0.98]"
                    >
                        {loading ? <Loader2 className="animate-spin" /> : <><TrendingUp size={20} /> Deep Market Scan</>}
                    </button>
                </div>
            </div>
        </div>

        <div className="absolute bottom-8 left-1/2 -translate-x-1/2 z-[1001] flex flex-col items-center gap-2 pointer-events-none">
            <span className="text-[10px] font-black text-white uppercase tracking-[0.4em] drop-shadow-lg opacity-80">View Intelligence</span>
            <ChevronDown className="text-white drop-shadow-lg animate-bounce" />
        </div>
      </section>

      <section ref={resultsRef} className="relative z-[10] bg-slate-50 min-h-screen py-32 px-6 sm:px-12 border-t border-slate-200">
        <div className="max-w-7xl mx-auto">
            {!result && !loading && (
                <div className="max-w-3xl mx-auto flex flex-col items-center text-center space-y-12 py-32">
                    <div className="relative p-12 bg-white rounded-[4rem] shadow-2xl border border-slate-100">
                        <CircleDollarSign size={100} className="text-slate-200" />
                    </div>
                    <div className="space-y-6">
                        <h3 className="text-5xl font-black text-slate-900 tracking-tighter uppercase tracking-widest">Awaiting Analysis</h3>
                        <p className="text-slate-500 text-xl font-medium leading-relaxed max-w-xl mx-auto">
                            Point the crosshair at a commercial node to trigger spatial market intelligence synthesis.
                        </p>
                    </div>
                </div>
            )}

            {loading && (
               <div className="max-w-5xl mx-auto flex flex-col items-center justify-center p-24 text-center bg-white border border-slate-100 rounded-[5rem] shadow-2xl relative overflow-hidden">
                 <div className="relative mb-16 scale-110">
                    <div className="w-48 h-48 border-[16px] border-indigo-50 rounded-full animate-pulse"></div>
                    <div className="absolute inset-0 border-t-[16px] border-indigo-600 rounded-full animate-spin"></div>
                    <div className="absolute inset-0 flex items-center justify-center">
                       <Sparkles className="w-16 h-16 text-indigo-600" />
                    </div>
                 </div>
                 <h3 className="text-4xl font-black text-slate-900 mb-4 uppercase tracking-tighter">Locality Fusion Active</h3>
               </div>
            )}

            {result && (
              <div className="space-y-16 animate-in fade-in slide-in-from-bottom-20 duration-1000">
                <div className="bg-gradient-to-br from-indigo-800 to-violet-950 text-white p-16 rounded-[5rem] shadow-[0_50px_100px_-20px_rgba(79,70,229,0.3)] relative overflow-hidden">
                  <div className="relative z-10 flex flex-col lg:flex-row gap-16 items-start justify-between">
                    <div className="space-y-8">
                        <div className="inline-flex items-center gap-3 px-6 py-2.5 bg-white/10 backdrop-blur-3xl rounded-full text-xs font-black uppercase tracking-[0.4em] border border-white/20">
                            <Shuffle size={14} className="text-indigo-300" /> Spatial Insights
                        </div>
                        <h2 className="text-7xl font-black tracking-tighter leading-none">{result.localityName}</h2>
                        <div className="flex flex-wrap items-center gap-8">
                            <div className="flex items-center gap-3 text-indigo-200 text-sm font-black tracking-widest uppercase">
                                <MapPin size={20} /> {input.coordinates?.lat.toFixed(5)}, {input.coordinates?.lng.toFixed(5)}
                            </div>
                        </div>
                    </div>

                    <div className="flex flex-col gap-6 min-w-[360px] w-full lg:w-auto">
                        <div className="bg-white/10 backdrop-blur-3xl p-10 rounded-[3rem] border border-white/20 shadow-2xl">
                            <div className="text-indigo-300 text-[11px] font-black uppercase mb-3 tracking-[0.3em]">Estimated Avg PCI</div>
                            <div className="text-5xl font-black">{formatCurrency(result.demographics.perCapitaIncome)}</div>
                        </div>
                        <div className="bg-white/10 backdrop-blur-3xl p-10 rounded-[3rem] border border-white/20 shadow-2xl">
                            <div className="text-indigo-300 text-[11px] font-black uppercase mb-3 tracking-[0.3em]">Neighborhood Type</div>
                            <div className="text-4xl font-black">{result.demographics.residentType} Hub</div>
                        </div>
                    </div>
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
                    <MetricCard 
                        title="Daily Footfall" 
                        value={result.metrics.footfallEstimate.daily.toLocaleString()} 
                        Icon={Users}
                        colorClass="bg-white p-10 rounded-[4rem] border-2 border-indigo-50 shadow-xl"
                    />
                    <MetricCard 
                        title="Dominant Vehicles" 
                        value={result.demographics.dominantCarTypes[0] || 'N/A'} 
                        Icon={Car}
                        subtitle={`${result.demographics.socioeconomicTier} Tier Indicator`}
                        colorClass="bg-white p-10 rounded-[4rem] border-2 border-indigo-50 shadow-xl"
                    />
                    <MetricCard 
                        title="Peak Hourly Traffic" 
                        value={result.metrics.footfallEstimate.hourly.toLocaleString()} 
                        Icon={MousePointer2}
                        colorClass="bg-white p-10 rounded-[4rem] border-2 border-indigo-50 shadow-xl"
                    />
                    <MetricCard 
                        title="Retail Density" 
                        value={`x${result.metrics.storeCompetition.reduce((acc, curr) => acc + curr.count, 0)}`} 
                        Icon={Layers}
                        subtitle="Identified Competitors"
                        colorClass="bg-white p-10 rounded-[4rem] border-2 border-indigo-50 shadow-xl"
                    />
                </div>

                <div className="space-y-8">
                  <div className="flex items-center gap-4">
                    <div className="bg-indigo-600 p-2 rounded-xl text-white shadow-lg shadow-indigo-200">
                      <Activity size={20} />
                    </div>
                    <h3 className="text-xl font-black text-slate-900 tracking-tight uppercase tracking-widest">Traffic Landscape</h3>
                  </div>
                  <TrafficLandscape data={result.metrics.footfallEstimate.hourlyDistribution} />
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-3 gap-12">
                    <div className="lg:col-span-2">
                        <RevenueChart projections={result.revenueProjections} />
                    </div>

                    <div className="bg-slate-950 text-white p-12 rounded-[4rem] shadow-3xl relative overflow-hidden flex flex-col justify-between">
                        <div>
                            <h3 className="text-xs font-black text-indigo-500 uppercase tracking-[0.5em] mb-12">Strategic AI Directives</h3>
                            <div className="space-y-8">
                                {result.strategicAdvice.map((advice, i) => (
                                <div key={i} className="flex gap-6 group">
                                    <div className="flex-shrink-0 w-10 h-10 rounded-2xl bg-indigo-600 flex items-center justify-center font-black text-sm text-white shadow-xl shadow-indigo-600/30">
                                    {i + 1}
                                    </div>
                                    <p className="text-slate-400 text-base leading-relaxed font-semibold">
                                    {advice}
                                    </p>
                                </div>
                                ))}
                            </div>
                        </div>
                    </div>
                </div>
              </div>
            )}
        </div>
      </section>

      <footer className="py-20 text-center text-slate-500 text-[10px] font-black uppercase tracking-[0.6em] bg-slate-50">
        <p>© 2024 LocalityMind Spatial Intelligence • Precision Market Analysis</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { 
  MapPin, Users, Sparkles, 
  Loader2, ExternalLink, LayoutGrid,
  CircleDollarSign, Building2,
  Globe, Home, Check, AlertCircle,
  Activity, ShoppingBag, Info, Compass, Target
} from 'lucide-react';
import maplibregl from 'maplibre-gl';
import 'maplibre-gl/dist/maplibre-gl.css';
import { StoreInput, AnalysisResult, StoreCategory } from './types';
import { GeminiService } from './services/geminiService';
import { MetricCard } from './components/MetricCard';
import { RevenueChart } from './components/RevenueChart';
import { TrafficLandscape } from './components/TrafficLandscape';

const STORE_CATEGORIES: StoreCategory[] = [
  'Premium Cafe (e.g., Starbucks)',
  'Large Attraction (e.g., Zoo / Theme Park)',
  'Supermarket (e.g., Reliance Fresh / DMart)',
  'Luxury Fashion / Boutique',
  'Pharmacy / Wellness',
  'Fine Dining Restaurant',
  'Workspace / Coworking',
  'Quick Service Restaurant (QSR)'
];

const INITIAL_POS = { lat: 19.0596, lng: 72.8295 }; // Bandra West, Mumbai

// @google/genai guidelines followed in GeminiService
const App: React.FC = () => {
  const mapContainer = useRef<HTMLDivElement>(null);
  const map = useRef<maplibregl.Map | null>(null);
  const [loading, setLoading] = useState(false);

  const [input, setInput] = useState<StoreInput>({
    location: 'Bandra West, Mumbai',
    coordinates: { ...INITIAL_POS },
    category: 'Premium Cafe (e.g., Starbucks)',
    length: 40,
    breadth: 50,
    floors: 1,
    heightPerFloor: 12,
    targetSegment: ['Gen-Z Trendsetters', 'Young Professionals']
  });

  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  // Initialize MapLibre with recommended sandbox settings
  useEffect(() => {
    if (!mapContainer.current) return;

    /**
     * CRITICAL CONFIGURATION:
     * We set workerCount to 0 to disable background WebWorkers.
     * In sandboxed environments, workers often fail to resolve their origin
     * or access restricted globals. Running on the main thread is far more stable.
     */
    (maplibregl as any).workerCount = 0;

    const mapInstance = new maplibregl.Map({
      container: mapContainer.current!,
      style: 'https://tiles.basemaps.cartocdn.com/gl/dark-matter-gl-style/style.json',
      center: [INITIAL_POS.lng, INITIAL_POS.lat],
      zoom: 16,
      pitch: 45,
      bearing: 0,
      antialias: true,
      attributionControl: false
    });

    map.current = mapInstance;

    return () => {
      mapInstance.remove();
    };
  }, []);

  const handleAnalyze = async () => {
    setLoading(true);
    setError(null);
    try {
      const data = await GeminiService.analyzeMarket(input);
      setResult(data);

      // Update map if location is inferred
      if (map.current) {
        map.current.flyTo({
          center: [INITIAL_POS.lng, INITIAL_POS.lat],
          zoom: 16,
          essential: true
        });
      }
    } catch (err: any) {
      setError(err.message || 'Analysis failed. Please check your network and try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 font-sans text-slate-900">
      {/* Header */}
      <header className="sticky top-0 z-50 bg-white/80 backdrop-blur-md border-b border-slate-100 px-6 py-4 flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-indigo-600 rounded-xl text-white shadow-lg shadow-indigo-100">
            <LayoutGrid size={24} />
          </div>
          <div>
            <h1 className="text-xl font-bold tracking-tight">GeoSynth Market AI</h1>
            <p className="text-xs text-slate-500 font-medium uppercase tracking-wider">Spatial Intelligence Engine</p>
          </div>
        </div>
        <button 
          onClick={handleAnalyze}
          disabled={loading}
          className="bg-slate-900 text-white px-6 py-2.5 rounded-xl font-bold text-sm flex items-center gap-2 hover:bg-slate-800 transition-all disabled:opacity-50"
        >
          {loading ? <Loader2 className="animate-spin" size={18} /> : <Sparkles size={18} />}
          {loading ? 'Synthesizing...' : 'Run Analysis'}
        </button>
      </header>

      <main className="p-6 max-w-[1600px] mx-auto grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Sidebar Controls */}
        <div className="lg:col-span-4 space-y-6">
          <section className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 space-y-6">
            <h2 className="text-sm font-black uppercase tracking-widest text-slate-400 flex items-center gap-2">
              <Compass size={16} /> Parameters
            </h2>

            <div className="space-y-4">
              <div>
                <label className="block text-xs font-bold text-slate-500 mb-2 uppercase">Target Location</label>
                <div className="relative">
                  <MapPin className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                  <input 
                    type="text"
                    value={input.location}
                    onChange={(e) => setInput({...input, location: e.target.value})}
                    className="w-full bg-slate-50 border border-slate-100 rounded-xl py-3 pl-10 pr-4 text-sm font-semibold focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all"
                    placeholder="Enter locality..."
                  />
                </div>
              </div>

              <div>
                <label className="block text-xs font-bold text-slate-500 mb-2 uppercase">Venture Category</label>
                <select 
                  value={input.category}
                  onChange={(e) => setInput({...input, category: e.target.value as StoreCategory})}
                  className="w-full bg-slate-50 border border-slate-100 rounded-xl py-3 px-4 text-sm font-semibold focus:outline-none focus:ring-2 focus:ring-indigo-500 appearance-none cursor-pointer"
                >
                  {STORE_CATEGORIES.map(cat => <option key={cat} value={cat}>{cat}</option>)}
                </select>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-bold text-slate-500 mb-2 uppercase">Length (ft)</label>
                  <input 
                    type="number"
                    value={input.length}
                    onChange={(e) => setInput({...input, length: Number(e.target.value)})}
                    className="w-full bg-slate-50 border border-slate-100 rounded-xl py-3 px-4 text-sm font-semibold focus:outline-none focus:ring-2 focus:ring-indigo-500"
                  />
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-500 mb-2 uppercase">Breadth (ft)</label>
                  <input 
                    type="number"
                    value={input.breadth}
                    onChange={(e) => setInput({...input, breadth: Number(e.target.value)})}
                    className="w-full bg-slate-50 border border-slate-100 rounded-xl py-3 px-4 text-sm font-semibold focus:outline-none focus:ring-2 focus:ring-indigo-500"
                  />
                </div>
              </div>
            </div>
          </section>

          {/* Map Preview */}
          <section className="bg-slate-900 h-[400px] rounded-3xl overflow-hidden relative shadow-2xl border border-slate-800">
            <div ref={mapContainer} className="w-full h-full" />
            <div className="absolute top-4 left-4 bg-slate-900/80 backdrop-blur-md px-3 py-1.5 rounded-lg border border-slate-700/50">
              <span className="text-[10px] font-black text-white uppercase tracking-widest flex items-center gap-2">
                <Globe size={12} className="text-indigo-400" /> Active Layer
              </span>
            </div>
          </section>
        </div>

        {/* Results Area */}
        <div className="lg:col-span-8 space-y-8">
          {loading && (
            <div className="bg-white p-12 rounded-[3rem] border border-slate-100 flex flex-col items-center justify-center text-center h-full min-h-[500px]">
              <div className="relative mb-6">
                <div className="absolute inset-0 bg-indigo-500 blur-2xl opacity-20 animate-pulse" />
                <Loader2 className="w-16 h-16 text-indigo-600 animate-spin relative" />
              </div>
              <h3 className="text-xl font-bold mb-2">Synthesizing Market Data</h3>
              <p className="text-slate-500 max-w-sm text-sm font-medium">
                Mining multi-source spatial data, POIs, and urban socioeconomic proxies...
              </p>
            </div>
          )}

          {error && (
            <div className="bg-red-50 p-6 rounded-2xl border border-red-100 flex items-center gap-4 text-red-700">
              <AlertCircle />
              <p className="font-semibold text-sm">{error}</p>
            </div>
          )}

          {result && !loading && (
            <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
              {/* Top Metrics */}
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                <MetricCard 
                  title="Est. Daily Flow" 
                  value={result.metrics.footfallEstimate.daily.toLocaleString()} 
                  Icon={Users} 
                  subtitle="Pedestrian + Vehicle"
                />
                <MetricCard 
                  title="Income Proxy" 
                  value={`₹${result.demographics.perCapitaIncome.toLocaleString()}`} 
                  Icon={CircleDollarSign} 
                  subtitle={result.demographics.socioeconomicTier}
                />
                <MetricCard 
                  title="Context" 
                  value={result.demographics.residentType} 
                  Icon={Home} 
                  subtitle={result.demographics.populationDensity}
                />
                <MetricCard 
                  title="Local Assets" 
                  value={result.metrics.nearbyPOIs.hotels.luxury + result.metrics.nearbyPOIs.hotels.midTier} 
                  Icon={Building2} 
                  subtitle="Premium Hubs"
                />
              </div>

              {/* Visualization Grid */}
              <div className="grid grid-cols-1 xl:grid-cols-2 gap-8">
                <RevenueChart projections={result.revenueProjections} />
                <TrafficLandscape data={result.metrics.footfallEstimate.hourlyDistribution} />
              </div>

              {/* AI Strategic Roadmap */}
              <section className="bg-white p-10 rounded-[3rem] shadow-sm border border-slate-100">
                <div className="flex items-center gap-4 mb-8">
                  <div className="p-3 bg-indigo-600 rounded-2xl text-white shadow-lg shadow-indigo-100">
                    <Target size={24} />
                  </div>
                  <div>
                    <h3 className="text-xs font-black uppercase tracking-[0.4em] text-slate-400">Analysis Output</h3>
                    <p className="text-slate-900 font-bold">Strategic Recommendations</p>
                  </div>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {result.strategicAdvice.map((advice, i) => (
                    <div key={i} className="flex gap-4 p-5 rounded-2xl bg-slate-50 border border-slate-100 items-start">
                      <div className="mt-1 p-1 bg-white rounded-lg text-indigo-600 shadow-sm">
                        <Check size={14} />
                      </div>
                      <p className="text-sm font-semibold text-slate-700 leading-relaxed">{advice}</p>
                    </div>
                  ))}
                </div>
              </section>

              {/* Context & Grounding */}
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                 <section className="bg-white p-8 rounded-[3rem] shadow-sm border border-slate-100">
                    <h3 className="text-xs font-black uppercase tracking-[0.4em] text-slate-400 mb-6">Market Rivals</h3>
                    <div className="space-y-4">
                      {result.metrics.storeCompetition.map((comp, i) => (
                        <div key={i} className="flex items-center justify-between p-4 rounded-2xl bg-slate-50 border border-slate-100 hover:bg-white hover:shadow-md transition-all cursor-default">
                          <div className="flex items-center gap-4">
                            <div className="p-2 bg-white rounded-xl text-slate-400">
                              <ShoppingBag size={18} />
                            </div>
                            <div>
                              <p className="text-sm font-bold text-slate-900">{comp.type}</p>
                              <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider">{comp.avgPricePoint} • {comp.count} nodes</p>
                            </div>
                          </div>
                          <Info size={16} className="text-slate-300" />
                        </div>
                      ))}
                    </div>
                 </section>

                 <section className="bg-white p-8 rounded-[3rem] shadow-sm border border-slate-100">
                    <h3 className="text-xs font-black uppercase tracking-[0.4em] text-slate-400 mb-6">Evidence Grounding</h3>
                    <div className="space-y-3">
                      {result.groundingSources.map((source, i) => (
                        <a 
                          key={i} 
                          href={source.uri} 
                          target="_blank" 
                          rel="noreferrer"
                          className="flex items-center justify-between p-4 rounded-2xl bg-indigo-50/50 hover:bg-indigo-50 border border-indigo-100/50 transition-all group"
                        >
                          <div className="flex items-center gap-3">
                            <Globe size={16} className="text-indigo-400" />
                            <span className="text-sm font-bold text-indigo-900 truncate max-w-[200px]">{source.title}</span>
                          </div>
                          <ExternalLink size={14} className="text-indigo-300 group-hover:text-indigo-600" />
                        </a>
                      ))}
                    </div>
                 </section>
              </div>
            </div>
          )}

          {!result && !loading && (
            <div className="bg-white/50 border-2 border-dashed border-slate-200 p-20 rounded-[4rem] text-center flex flex-col items-center justify-center min-h-[500px]">
              <div className="w-20 h-20 bg-white rounded-3xl shadow-sm border border-slate-100 flex items-center justify-center mb-6">
                <Activity size={32} className="text-slate-300" />
              </div>
              <h3 className="text-xl font-bold text-slate-400 mb-2">Awaiting Parameters</h3>
              <p className="text-slate-400 max-w-xs mx-auto text-sm font-medium">
                Set the store configuration and target locality on the left to trigger the spatial analysis engine.
              </p>
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

export interface RevenueProjections {
  monthly: number;
  quarterly: number;
  yearly: number;
  currency: string;
}

export interface AreaDemographics {
  perCapitaIncome: number;
  socioeconomicTier: 'High' | 'Upper-Mid' | 'Mid' | 'Lower-Mid' | 'Economic';
  dominantCarTypes: string[];
  populationDensity: string;
  residentType: 'Residential' | 'Corporate' | 'Tourist' | 'Mixed';
}

export interface LocalityMetrics {
  footfallEstimate: {
    hourly: number;
    daily: number;
    peakTimes: string[];
    hourlyDistribution: { hour: number; traffic: number }[];
  };
  nearbyPOIs: {
    schools: number;
    premiumSchools: number;
    placesOfWorship: number;
    hotels: {
      luxury: number;
      midTier: number;
      budget: number;
    };
  };
  tourismProfile: string;
  storeCompetition: {
    type: string;
    avgPricePoint: string;
    count: number;
    description: string;
  }[];
}

export interface AnalysisResult {
  id: string;
  timestamp: number;
  localityName: string;
  demographics: AreaDemographics;
  metrics: LocalityMetrics;
  revenueProjections: RevenueProjections;
  strategicAdvice: string[];
  groundingSources: { title: string; uri: string }[];
  originalInput: StoreInput; // Stored to allow area vs revenue comparisons
}

export type StoreCategory = 
  | 'Premium Cafe (e.g., Starbucks)' 
  | 'Large Attraction (e.g., Zoo / Theme Park)' 
  | 'Supermarket (e.g., Reliance Fresh / DMart)' 
  | 'Luxury Fashion / Boutique' 
  | 'Pharmacy / Wellness' 
  | 'Fine Dining Restaurant' 
  | 'Workspace / Coworking' 
  | 'Quick Service Restaurant (QSR)';

export interface StoreInput {
  location: string;
  coordinates?: { lat: number; lng: number };
  category: StoreCategory;
  length: number; // in ft
  breadth: number; // in ft
  floors: number;
  heightPerFloor: number; // in ft
  targetSegment: string[];
}

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { 
  MapPin, Users, Sparkles, 
  Loader2, ExternalLink, LayoutGrid,
  CircleDollarSign, Building2,
  Globe, Home, Check, AlertCircle,
  Activity, ShoppingBag, Info, Compass, Target,
  History, X, ChevronRight, BarChart3, ArrowRightLeft,
  Trash2, PlusCircle
} from 'lucide-react';
import maplibregl from 'maplibre-gl';
import { StoreInput, AnalysisResult, StoreCategory } from './types';
import { GeminiService } from './services/geminiService';
import { MetricCard } from './components/MetricCard';
import { RevenueChart } from './components/RevenueChart';
import { TrafficLandscape } from './components/TrafficLandscape';

const STORE_CATEGORIES: StoreCategory[] = [
  'Premium Cafe (e.g., Starbucks)',
  'Large Attraction (e.g., Zoo / Theme Park)',
  'Supermarket (e.g., Reliance Fresh / DMart)',
  'Luxury Fashion / Boutique',
  'Pharmacy / Wellness',
  'Fine Dining Restaurant',
  'Workspace / Coworking',
  'Quick Service Restaurant (QSR)'
];

const INITIAL_POS = { lat: 19.0596, lng: 72.8295 };

const App: React.FC = () => {
  const mapContainer = useRef<HTMLDivElement>(null);
  const map = useRef<maplibregl.Map | null>(null);

  // App State
  const [loading, setLoading] = useState(false);
  const [history, setHistory] = useState<AnalysisResult[]>([]);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [compareMode, setCompareMode] = useState(false);
  const [sidebarOpen, setSidebarOpen] = useState(true);

  // Current Analysis State
  const [input, setInput] = useState<StoreInput>({
    location: 'Bandra West, Mumbai',
    coordinates: { ...INITIAL_POS },
    category: 'Premium Cafe (e.g., Starbucks)',
    length: 40,
    breadth: 50,
    floors: 1,
    heightPerFloor: 12,
    targetSegment: ['Gen-Z Trendsetters', 'Young Professionals']
  });

  const [currentResult, setCurrentResult] = useState<AnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  // Initialize Map
  useEffect(() => {
    if (!mapContainer.current) return;
    (maplibregl as any).workerCount = 0;

    const mapInstance = new maplibregl.Map({
      container: mapContainer.current!,
      style: 'https://tiles.basemaps.cartocdn.com/gl/dark-matter-gl-style/style.json',
      center: [INITIAL_POS.lng, INITIAL_POS.lat],
      zoom: 15,
      pitch: 45,
      attributionControl: false
    });

    map.current = mapInstance;
    return () => mapInstance.remove();
  }, []);

  const handleAnalyze = async () => {
    setLoading(true);
    setError(null);
    try {
      const data = await GeminiService.analyzeMarket(input);
      const newResult: AnalysisResult = {
        ...data,
        id: crypto.randomUUID(),
        timestamp: Date.now(),
        originalInput: { ...input }
      };

      setHistory(prev => [newResult, ...prev]);
      setCurrentResult(newResult);
      setCompareMode(false);

      if (map.current) {
        map.current.flyTo({ center: [INITIAL_POS.lng, INITIAL_POS.lat], zoom: 16 });
      }
    } catch (err: any) {
      setError(err.message || 'Analysis failed.');
    } finally {
      setLoading(false);
    }
  };

  const toggleSelectForCompare = (id: string) => {
    setSelectedIds(prev => 
      prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]
    );
  };

  const removeFromHistory = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setHistory(prev => prev.filter(item => item.id !== id));
    setSelectedIds(prev => prev.filter(i => i !== id));
    if (currentResult?.id === id) setCurrentResult(null);
  };

  const comparisonData = useMemo(() => {
    return history.filter(item => selectedIds.includes(item.id));
  }, [history, selectedIds]);

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('en-IN', {
      style: 'currency', currency: 'INR', maximumFractionDigits: 0
    }).format(val);
  };

  return (
    <div className="flex flex-col h-screen bg-[#f8fafc]">
      {/* Top Header */}
      <header className="h-16 bg-white border-b border-slate-200 px-6 flex items-center justify-between z-50">
        <div className="flex items-center gap-4">
          <button 
            onClick={() => setSidebarOpen(!sidebarOpen)}
            className="p-2 hover:bg-slate-100 rounded-lg text-slate-500"
          >
            <History size={20} />
          </button>
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-1.5 rounded-lg text-white">
              <Sparkles size={18} />
            </div>
            <h1 className="font-black text-slate-900 tracking-tight text-lg">LocalityMind</h1>
          </div>
        </div>

        <div className="flex items-center gap-3">
          {selectedIds.length > 0 && (
            <button 
              onClick={() => setCompareMode(!compareMode)}
              className={`flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-bold transition-all ${compareMode ? 'bg-indigo-600 text-white' : 'bg-indigo-50 text-indigo-700 hover:bg-indigo-100'}`}
            >
              <ArrowRightLeft size={16} />
              {compareMode ? 'Exit Comparison' : `Compare (${selectedIds.length})`}
            </button>
          )}
          <button 
            onClick={handleAnalyze}
            disabled={loading}
            className="bg-slate-900 text-white px-5 py-2 rounded-xl text-sm font-bold flex items-center gap-2 hover:bg-slate-800 transition-all disabled:opacity-50"
          >
            {loading ? <Loader2 size={16} className="animate-spin" /> : <Target size={16} />}
            {loading ? 'Processing...' : 'Analyze Market'}
          </button>
        </div>
      </header>

      <div className="flex flex-1 overflow-hidden relative">
        {/* History Sidebar */}
        <aside className={`glass-sidebar w-80 flex flex-col transition-all duration-300 overflow-hidden ${sidebarOpen ? 'translate-x-0' : '-translate-x-full absolute h-full z-40'}`}>
          <div className="p-4 border-b border-slate-100 flex items-center justify-between bg-white/50">
            <span className="text-xs font-black uppercase tracking-widest text-slate-400">Analysis History</span>
          </div>
          <div className="flex-1 overflow-y-auto custom-scrollbar p-2 space-y-1">
            {history.length === 0 ? (
              <div className="p-8 text-center text-slate-400 space-y-2">
                <Info size={24} className="mx-auto opacity-20" />
                <p className="text-xs font-bold">No history yet.</p>
              </div>
            ) : (
              history.map(item => (
                <div 
                  key={item.id}
                  onClick={() => { setCurrentResult(item); setCompareMode(false); }}
                  className={`group relative p-3 rounded-xl cursor-pointer transition-all border ${currentResult?.id === item.id ? 'bg-white border-indigo-200 shadow-sm' : 'border-transparent hover:bg-white hover:border-slate-200'}`}
                >
                  <div className="flex justify-between items-start mb-1">
                    <h4 className="text-sm font-bold text-slate-900 truncate pr-6">{item.localityName}</h4>
                    <button onClick={(e) => removeFromHistory(item.id, e)} className="opacity-0 group-hover:opacity-100 p-1 hover:text-red-500 text-slate-300">
                      <Trash2 size={12} />
                    </button>
                  </div>
                  <p className="text-[10px] font-bold text-slate-400 uppercase">{item.originalInput.category}</p>
                  <div className="mt-2 flex items-center justify-between">
                    <span className="text-xs font-black text-indigo-600">{formatCurrency(item.revenueProjections.monthly)}/mo</span>
                    <button 
                      onClick={(e) => { e.stopPropagation(); toggleSelectForCompare(item.id); }}
                      className={`p-1 rounded-md transition-all ${selectedIds.includes(item.id) ? 'bg-indigo-600 text-white' : 'text-slate-300 hover:text-indigo-600'}`}
                    >
                      <PlusCircle size={14} />
                    </button>
                  </div>
                </div>
              ))
            )}
          </div>
        </aside>

        {/* Main Content Area */}
        <main className="flex-1 overflow-y-auto custom-scrollbar bg-[#f8fafc] p-6 lg:p-8">
          {compareMode ? (
            /* Parallel Comparison View */
            <div className="max-w-7xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
              <div className="flex items-center justify-between">
                <div>
                  <h2 className="text-2xl font-black text-slate-900 tracking-tight">Parallel Comparison</h2>
                  <p className="text-sm text-slate-500 font-medium">Benchmarking {comparisonData.length} localities across core business metrics.</p>
                </div>
                <button onClick={() => setCompareMode(false)} className="p-2 hover:bg-slate-200 rounded-full text-slate-400"><X size={20}/></button>
              </div>

              <div className="bg-white rounded-[2rem] border border-slate-200 shadow-sm overflow-hidden">
                <table className="w-full text-left border-collapse">
                  <thead>
                    <tr className="bg-slate-50">
                      <th className="p-6 text-xs font-black uppercase text-slate-400 border-b border-slate-100">Metric</th>
                      {comparisonData.map(item => (
                        <th key={item.id} className="p-6 text-sm font-black text-slate-900 border-b border-slate-100 min-w-[200px]">
                          {item.localityName}
                        </th>
                      ))}
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100">
                    <tr>
                      <td className="p-6 text-sm font-bold text-slate-500">Revenue (Monthly)</td>
                      {comparisonData.map(item => (
