                      </div>
                      <h3 className="text-xl font-black text-slate-900 mb-2 uppercase tracking-tight">Synthesizing Socioeconomic Data</h3>
                      <p className="text-sm text-slate-400 font-bold max-w-xs uppercase leading-relaxed tracking-widest">Fusing Apple Maps, OSM & Google Data Points...</p>
                    </div>
                  ) : currentResult ? (
                    <div className="space-y-8 animate-in fade-in duration-700">
                      {/* Featured Highlight Card */}
                      <div className="bg-gradient-to-br from-indigo-900 via-indigo-950 to-slate-950 text-white p-12 rounded-[3.5rem] shadow-2xl relative overflow-hidden group">
                        <div className="absolute top-0 right-0 p-12 opacity-5 transition-transform group-hover:scale-110 duration-1000">
                          <BarChart3 size={200} />
                        </div>
                        <div className="relative z-10 space-y-6">
                          <div className="flex items-center gap-3">
                            <span className="px-3 py-1 bg-white/10 rounded-full text-[10px] font-black uppercase tracking-widest border border-white/10">Projected Performance</span>
                          </div>
                          <h2 className="text-6xl font-black tracking-tighter">{currentResult.localityName}</h2>
                          <div className="flex flex-wrap gap-12">
                            <div>
                              <p className="text-[10px] font-black uppercase tracking-widest text-indigo-400 mb-1">Monthly Yield</p>
                              <p className="text-4xl font-black">{formatCurrency(currentResult.revenueProjections.monthly)}</p>
                            </div>
                            <div>
                              <p className="text-[10px] font-black uppercase tracking-widest text-indigo-400 mb-1">Yearly Outlook</p>
                              <p className="text-4xl font-black">{formatCurrency(currentResult.revenueProjections.yearly)}</p>
                            </div>
                          </div>
                        </div>
                      </div>

                      {/* Detail Metrics */}
                      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                        <MetricCard title="Est. Traffic" value={currentResult.metrics.footfallEstimate.daily.toLocaleString()} Icon={Users} subtitle="Daily Flow" />
                        <MetricCard title="Income Proxy" value={`₹${currentResult.demographics.perCapitaIncome.toLocaleString()}`} Icon={CircleDollarSign} subtitle={currentResult.demographics.socioeconomicTier} />
                        <MetricCard title="Vibe Check" value={currentResult.demographics.residentType} Icon={Home} subtitle="Market Context" />
                        <MetricCard title="Competitors" value={currentResult.metrics.storeCompetition.length} Icon={ShoppingBag} subtitle="Direct Matches" />
                      </div>

                      <div className="grid grid-cols-1 xl:grid-cols-2 gap-8">
