                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                          {currentResult.strategicAdvice.map((advice, i) => (
                            <div key={i} className="flex gap-4 p-5 bg-slate-50 rounded-2xl border border-slate-100">
                              <div className="flex-shrink-0 w-8 h-8 rounded-full bg-indigo-600 flex items-center justify-center text-white text-[10px] font-black">{i+1}</div>
                              <p className="text-sm font-bold text-slate-700 leading-relaxed">{advice}</p>
                            </div>
                          ))}
