                    </div>
                  )}
                </div>
              </div>
            </div>
          )}
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { 
  MapPin, Users, Sparkles, 
  Loader2, ExternalLink, LayoutGrid,
  CircleDollarSign, Building2,
  Globe, Home, Check, AlertCircle,
  Activity, ShoppingBag, Info, Compass, Target,
  History, X, ChevronRight, BarChart3, ArrowRightLeft,
  Trash2, PlusCircle
} from 'lucide-react';
import maplibregl from 'maplibre-gl';
import { StoreInput, AnalysisResult, StoreCategory } from './types';
import { GeminiService } from './services/geminiService';
import { MetricCard } from './components/MetricCard';
import { RevenueChart } from './components/RevenueChart';
import { TrafficLandscape } from './components/TrafficLandscape';

const STORE_CATEGORIES: StoreCategory[] = [
  'Premium Cafe (e.g., Starbucks)',
  'Large Attraction (e.g., Zoo / Theme Park)',
  'Supermarket (e.g., Reliance Fresh / DMart)',
  'Luxury Fashion / Boutique',
  'Pharmacy / Wellness',
  'Fine Dining Restaurant',
  'Workspace / Coworking',
  'Quick Service Restaurant (QSR)'
];

const INITIAL_POS = { lat: 19.0596, lng: 72.8295 };

const App: React.FC = () => {
  const mapContainer = useRef<HTMLDivElement>(null);
  const map = useRef<maplibregl.Map | null>(null);

  // App State
  const [loading, setLoading] = useState(false);
  const [history, setHistory] = useState<AnalysisResult[]>([]);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [compareMode, setCompareMode] = useState(false);
  const [sidebarOpen, setSidebarOpen] = useState(true);

  // Current Analysis State
  const [input, setInput] = useState<StoreInput>({
    location: 'Bandra West, Mumbai',
    coordinates: { ...INITIAL_POS },
    category: 'Premium Cafe (e.g., Starbucks)',
    length: 40,
    breadth: 50,
    floors: 1,
    heightPerFloor: 12,
    targetSegment: ['Gen-Z Trendsetters', 'Young Professionals']
  });

  const [currentResult, setCurrentResult] = useState<AnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  // Initialize Map
  useEffect(() => {
    if (!mapContainer.current) return;

    // Disable workers for stability in frames
    (maplibregl as any).workerCount = 0;

    let mapInstance: maplibregl.Map | null = null;

    try {
      mapInstance = new maplibregl.Map({
        container: mapContainer.current!,
        style: 'https://tiles.basemaps.cartocdn.com/gl/dark-matter-gl-style/style.json',
        center: [INITIAL_POS.lng, INITIAL_POS.lat],
        zoom: 14,
        pitch: 45,
        attributionControl: false,
        failIfMajorPerformanceCaveat: false
      });

      mapInstance.on('error', (e) => {
        console.warn('Map Encountered an Error:', e);
      });

      map.current = mapInstance;
    } catch (err) {
      console.error('Fatal MapLibre Init Error:', err);
    }

    return () => {
      if (mapInstance) mapInstance.remove();
    };
  }, []);

  const handleAnalyze = async () => {
    setLoading(true);
    setError(null);
    try {
      const data = await GeminiService.analyzeMarket(input);
      const newResult: AnalysisResult = {
        ...data,
        id: crypto.randomUUID(),
        timestamp: Date.now(),
        originalInput: { ...input }
      };

      setHistory(prev => [newResult, ...prev]);
      setCurrentResult(newResult);
      setCompareMode(false);

      if (map.current) {
        // Find center of coordinates if available, otherwise use initial
        map.current.flyTo({ center: [INITIAL_POS.lng, INITIAL_POS.lat], zoom: 16 });
      }
    } catch (err: any) {
      setError(err.message || 'Analysis failed.');
    } finally {
      setLoading(false);
    }
  };

  const toggleSelectForCompare = (id: string) => {
    setSelectedIds(prev => 
      prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]
    );
  };

  const removeFromHistory = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setHistory(prev => prev.filter(item => item.id !== id));
    setSelectedIds(prev => prev.filter(i => i !== id));
    if (currentResult?.id === id) setCurrentResult(null);
  };

  const comparisonData = useMemo(() => {
    return history.filter(item => selectedIds.includes(item.id));
  }, [history, selectedIds]);

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('en-IN', {
      style: 'currency', currency: 'INR', maximumFractionDigits: 0
    }).format(val);
  };

  return (
    <div className="flex flex-col h-screen bg-[#f8fafc] text-slate-900 overflow-hidden">
      {/* Top Header */}
      <header className="h-16 bg-white border-b border-slate-200 px-6 flex items-center justify-between z-50 flex-shrink-0">
        <div className="flex items-center gap-4">
          <button 
            onClick={() => setSidebarOpen(!sidebarOpen)}
            className="p-2 hover:bg-slate-100 rounded-lg text-slate-500 transition-colors"
            title="Toggle History"
          >
            <History size={20} />
          </button>
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-1.5 rounded-lg text-white shadow-lg shadow-indigo-100">
              <Sparkles size={18} />
            </div>
            <h1 className="font-black text-slate-900 tracking-tight text-lg">LocalityMind</h1>
          </div>
        </div>

        <div className="flex items-center gap-3">
          {selectedIds.length > 0 && (
            <button 
              onClick={() => setCompareMode(!compareMode)}
              className={`flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-bold transition-all ${compareMode ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-200' : 'bg-indigo-50 text-indigo-700 hover:bg-indigo-100'}`}
            >
              <ArrowRightLeft size={16} />
              {compareMode ? 'Exit Comparison' : `Compare (${selectedIds.length})`}
            </button>
          )}
          <button 
            onClick={handleAnalyze}
            disabled={loading}
            className="bg-slate-900 text-white px-5 py-2 rounded-xl text-sm font-bold flex items-center gap-2 hover:bg-slate-800 transition-all disabled:opacity-50 shadow-lg shadow-slate-200"
          >
            {loading ? <Loader2 size={16} className="animate-spin" /> : <Target size={16} />}
            {loading ? 'Synthesizing...' : 'Analyze Market'}
          </button>
        </div>
      </header>

      <div className="flex flex-1 overflow-hidden relative">
        {/* History Sidebar */}
        <aside className={`glass-sidebar w-80 flex flex-col transition-all duration-300 overflow-hidden flex-shrink-0 ${sidebarOpen ? 'translate-x-0' : '-translate-x-full absolute h-full z-40'}`}>
          <div className="p-4 border-b border-slate-100 flex items-center justify-between bg-white/50">
            <span className="text-xs font-black uppercase tracking-widest text-slate-400">Analysis History</span>
          </div>
          <div className="flex-1 overflow-y-auto custom-scrollbar p-2 space-y-1">
            {history.length === 0 ? (
              <div className="p-8 text-center text-slate-400 space-y-2 mt-10">
                <Info size={24} className="mx-auto opacity-20" />
                <p className="text-xs font-bold uppercase tracking-wider">No history recorded.</p>
              </div>
            ) : (
              history.map(item => (
                <div 
                  key={item.id}
                  onClick={() => { setCurrentResult(item); setCompareMode(false); }}
                  className={`group relative p-3 rounded-xl cursor-pointer transition-all border ${currentResult?.id === item.id ? 'bg-white border-indigo-200 shadow-md' : 'border-transparent hover:bg-white hover:border-slate-200'}`}
                >
                  <div className="flex justify-between items-start mb-1">
                    <h4 className="text-sm font-bold text-slate-900 truncate pr-6">{item.localityName}</h4>
                    <button onClick={(e) => removeFromHistory(item.id, e)} className="opacity-0 group-hover:opacity-100 p-1 hover:text-red-500 text-slate-300 transition-opacity">
                      <Trash2 size={12} />
                    </button>
                  </div>
                  <p className="text-[9px] font-black text-slate-400 uppercase tracking-tighter truncate">{item.originalInput.category}</p>
                  <div className="mt-2 flex items-center justify-between">
                    <span className="text-xs font-black text-indigo-600">{formatCurrency(item.revenueProjections.monthly)}/mo</span>
                    <button 
                      onClick={(e) => { e.stopPropagation(); toggleSelectForCompare(item.id); }}
                      className={`p-1 rounded-md transition-all ${selectedIds.includes(item.id) ? 'bg-indigo-600 text-white' : 'text-slate-300 hover:text-indigo-600'}`}
                      title="Select for Comparison"
                    >
                      <PlusCircle size={14} />
                    </button>
                  </div>
                </div>
              ))
            )}
          </div>
        </aside>

        {/* Main Content Area */}
        <main className="flex-1 overflow-y-auto custom-scrollbar bg-[#f8fafc] p-6 lg:p-8">
          {compareMode ? (
            /* Parallel Comparison View */
            <div className="max-w-7xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
              <div className="flex items-center justify-between">
                <div>
                  <h2 className="text-2xl font-black text-slate-900 tracking-tight">Parallel Comparison</h2>
                  <p className="text-sm text-slate-500 font-medium">Benchmarking {comparisonData.length} localities across business KPIs.</p>
                </div>
                <button onClick={() => setCompareMode(false)} className="p-2 hover:bg-slate-200 rounded-full text-slate-400 transition-colors"><X size={20}/></button>
              </div>

              <div className="bg-white rounded-[2rem] border border-slate-200 shadow-sm overflow-x-auto custom-scrollbar">
                <table className="w-full text-left border-collapse min-w-[800px]">
                  <thead>
                    <tr className="bg-slate-50">
                      <th className="p-6 text-xs font-black uppercase text-slate-400 border-b border-slate-100 w-1/4">Metric</th>
                      {comparisonData.map(item => (
                        <th key={item.id} className="p-6 text-sm font-black text-slate-900 border-b border-slate-100">
                          {item.localityName}
                        </th>
                      ))}
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100">
                    <tr>
                      <td className="p-6 text-sm font-bold text-slate-500">Est. Revenue (Monthly)</td>
                      {comparisonData.map(item => (
                        <td key={item.id} className="p-6 text-lg font-black text-indigo-600">{formatCurrency(item.revenueProjections.monthly)}</td>
                      ))}
                    </tr>
                    <tr>
                      <td className="p-6 text-sm font-bold text-slate-500">Est. Revenue (Yearly)</td>
                      {comparisonData.map(item => (
                        <td key={item.id} className="p-6 text-sm font-bold text-slate-900">{formatCurrency(item.revenueProjections.yearly)}</td>
                      ))}
                    </tr>
                    <tr>
                      <td className="p-6 text-sm font-bold text-slate-500">Daily Footfall Flow</td>
                      {comparisonData.map(item => (
                        <td key={item.id} className="p-6 text-sm font-bold text-slate-900">{item.metrics.footfallEstimate.daily.toLocaleString()}</td>
                      ))}
                    </tr>
                    <tr>
                      <td className="p-6 text-sm font-bold text-slate-500">Income Proxy (PCI)</td>
                      {comparisonData.map(item => (
                        <td key={item.id} className="p-6 text-sm font-bold text-slate-900">₹{item.demographics.perCapitaIncome.toLocaleString()}</td>
                      ))}
                    </tr>
                    <tr>
                      <td className="p-6 text-sm font-bold text-slate-500">Store footprint (Input)</td>
                      {comparisonData.map(item => (
                        <td key={item.id} className="p-6 text-sm font-bold text-slate-900">{item.originalInput.length * item.originalInput.breadth} sq ft</td>
                      ))}
                    </tr>
                    <tr>
                      <td className="p-6 text-sm font-bold text-slate-500">Yield per Sq Ft (Annual)</td>
                      {comparisonData.map(item => {
                        const area = item.originalInput.length * item.originalInput.breadth;
                        const density = item.revenueProjections.yearly / area;
                        return <td key={item.id} className="p-6 text-sm font-black text-slate-600">₹{Math.round(density).toLocaleString()}</td>;
                      })}
                    </tr>
                    <tr>
                      <td className="p-6 text-sm font-bold text-slate-500">Locality Profile</td>
                      {comparisonData.map(item => (
                        <td key={item.id} className="p-6">
                          <span className="px-3 py-1 bg-slate-100 rounded-full text-[10px] font-black uppercase text-slate-600 tracking-wider">
                            {item.demographics.residentType}
                          </span>
                        </td>
                      ))}
                    </tr>
                  </tbody>
                </table>
              </div>
            </div>
          ) : (
            /* Single Analysis / Dashboard View */
            <div className="max-w-7xl mx-auto space-y-8 pb-12">
              <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
                {/* Configuration Panel */}
                <div className="lg:col-span-4 space-y-6">
                  <section className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm space-y-6">
                    <h3 className="text-xs font-black uppercase tracking-widest text-slate-400 flex items-center gap-2">
                      <Target size={14} className="text-indigo-600" /> Analysis Input
                    </h3>
                    <div className="space-y-4">
                      <div>
                        <label className="block text-[10px] font-black text-slate-400 mb-2 uppercase tracking-widest">Locality Target</label>
                        <div className="relative">
                          <MapPin className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-300" size={16} />
                          <input 
                            type="text" 
                            value={input.location} 
                            onChange={(e) => setInput({...input, location: e.target.value})}
                            className="w-full bg-slate-50 border border-slate-100 rounded-xl py-3 pl-9 pr-4 text-sm font-bold focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                            placeholder="e.g. Indiranagar, Bangalore"
                          />
                        </div>
