                <div className="lg:col-span-8 space-y-8">
                  {error && (
                    <div className="p-6 bg-red-50 border border-red-100 rounded-2xl flex items-center gap-4 text-red-700 animate-in fade-in duration-300">
                      <AlertCircle size={20} />
                      <p className="text-sm font-bold">{error}</p>
                    </div>
                  )}

                  {loading ? (
                    <div className="h-full min-h-[500px] bg-white rounded-[3rem] border border-slate-200 flex flex-col items-center justify-center p-12 text-center animate-pulse">
                      <div className="relative mb-6">
