                      </div>
                      <h3 className="text-xl font-black text-slate-900 mb-2 uppercase tracking-tight">Synthesizing Socioeconomic Data</h3>
                      <p className="text-[10px] text-slate-400 font-black max-w-xs uppercase leading-relaxed tracking-[0.2em]">Cross-Referencing POIs & Urban Proxies...</p>
                    </div>
                  ) : currentResult ? (
                    <div className="space-y-8 animate-in fade-in duration-700">
                      {/* Featured Highlight Card */}
                      <div className="bg-gradient-to-br from-indigo-900 via-indigo-950 to-slate-950 text-white p-12 rounded-[3.5rem] shadow-2xl relative overflow-hidden group">
                        <div className="absolute top-0 right-0 p-12 opacity-5 transition-transform group-hover:scale-110 duration-1000 pointer-events-none">
                          <BarChart3 size={240} />
                        </div>
                        <div className="relative z-10 space-y-8">
                          <div className="flex items-center gap-3">
                            <span className="px-3 py-1 bg-white/10 rounded-full text-[10px] font-black uppercase tracking-[0.2em] border border-white/10">Primary Forecast</span>
                          </div>
                          <h2 className="text-6xl font-black tracking-tighter leading-none">{currentResult.localityName}</h2>
                          <div className="flex flex-wrap gap-12">
                            <div className="space-y-1">
                              <p className="text-[10px] font-black uppercase tracking-widest text-indigo-400">Monthly Est. Yield</p>
                              <p className="text-5xl font-black">{formatCurrency(currentResult.revenueProjections.monthly)}</p>
                            </div>
                            <div className="space-y-1">
                              <p className="text-[10px] font-black uppercase tracking-widest text-indigo-400">Annual Gross Projection</p>
                              <p className="text-5xl font-black">{formatCurrency(currentResult.revenueProjections.yearly)}</p>
                            </div>
                          </div>
                        </div>
                      </div>

                      {/* Detail Metrics */}
                      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                        <MetricCard title="Est. Traffic" value={currentResult.metrics.footfallEstimate.daily.toLocaleString()} Icon={Users} subtitle="Daily Visitor Flow" />
                        <MetricCard title="Income Proxy" value={`₹${currentResult.demographics.perCapitaIncome.toLocaleString()}`} Icon={CircleDollarSign} subtitle={currentResult.demographics.socioeconomicTier} />
                        <MetricCard title="Market Vibe" value={currentResult.demographics.residentType} Icon={Home} subtitle="Local Demographic" />
                        <MetricCard title="Competitors" value={currentResult.metrics.storeCompetition.length} Icon={ShoppingBag} subtitle="Identified Rivals" />
                      </div>

                      <div className="grid grid-cols-1 xl:grid-cols-2 gap-8">
                        <RevenueChart projections={currentResult.revenueProjections} />
                        <TrafficLandscape data={currentResult.metrics.footfallEstimate.hourlyDistribution} />
                      </div>

                      {/* Strategic Advice */}
                      <section className="bg-white p-10 rounded-[3.5rem] border border-slate-200 shadow-sm relative overflow-hidden">
                        <div className="absolute top-0 right-0 p-8 opacity-5 text-indigo-600">
                          <Compass size={120} />
                        </div>
                        <h3 className="text-xs font-black uppercase tracking-[0.4em] text-slate-400 mb-8 flex items-center gap-3 relative z-10">
                          <Compass size={16} className="text-indigo-600" /> AI Strategic Deployment Roadmap
                        </h3>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 relative z-10">
                          {currentResult.strategicAdvice.map((advice, i) => (
                            <div key={i} className="flex gap-4 p-5 bg-slate-50/50 rounded-3xl border border-slate-100 hover:bg-white hover:shadow-md transition-all">
                              <div className="flex-shrink-0 w-8 h-8 rounded-full bg-indigo-600 flex items-center justify-center text-white text-[10px] font-black shadow-lg shadow-indigo-100">{i+1}</div>
                              <p className="text-sm font-bold text-slate-700 leading-relaxed">{advice}</p>
                            </div>
                          ))}
                        </div>
                      </section>
                    </div>
                  ) : (
                    /* Empty State */
                    <div className="h-full min-h-[600px] border-2 border-dashed border-slate-200 rounded-[4rem] flex flex-col items-center justify-center text-center p-20 animate-in fade-in zoom-in duration-700">
                      <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100 mb-6">
                        <Activity size={48} className="text-slate-300" />
                      </div>
                      <h3 className="text-2xl font-black text-slate-400 mb-2 uppercase tracking-tight">System Ready for Recon</h3>
                      <p className="text-[10px] text-slate-400 font-black max-w-xs uppercase leading-relaxed tracking-[0.2em]">Input a target locality and business specs on the left to initiate the market synthesis.</p>
                    </div>
                  )}
                </div>
              </div>
            </div>
          )}
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { 
  MapPin, Users, Sparkles, 
  Loader2, ExternalLink, LayoutGrid,
  CircleDollarSign, Building2,
  Globe, Home, Check, AlertCircle,
  Activity, ShoppingBag, Info, Compass, Target,
  History, X, ChevronRight, BarChart3, ArrowRightLeft,
  Trash2, PlusCircle, Maximize2
} from 'lucide-react';
import maplibregl from 'maplibre-gl';
import { StoreInput, AnalysisResult, StoreCategory } from './types';
import { GeminiService } from './services/geminiService';
import { MetricCard } from './components/MetricCard';
import { RevenueChart } from './components/RevenueChart';
import { TrafficLandscape } from './components/TrafficLandscape';

const STORE_CATEGORIES: StoreCategory[] = [
  'Premium Cafe (e.g., Starbucks)',
  'Large Attraction (e.g., Zoo / Theme Park)',
  'Supermarket (e.g., Reliance Fresh / DMart)',
  'Luxury Fashion / Boutique',
  'Pharmacy / Wellness',
  'Fine Dining Restaurant',
  'Workspace / Coworking',
  'Quick Service Restaurant (QSR)'
];

const INITIAL_POS = { lat: 19.0596, lng: 72.8295 };

const App: React.FC = () => {
  const mapContainer = useRef<HTMLDivElement>(null);
  const map = useRef<maplibregl.Map | null>(null);

  // App State
  const [loading, setLoading] = useState(false);
  const [history, setHistory] = useState<AnalysisResult[]>([]);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [compareMode, setCompareMode] = useState(false);
  const [sidebarOpen, setSidebarOpen] = useState(true);

  // Current Analysis State
  const [input, setInput] = useState<StoreInput>({
    location: 'Bandra West, Mumbai',
    coordinates: { ...INITIAL_POS },
    category: 'Premium Cafe (e.g., Starbucks)',
    length: 40,
    breadth: 50,
    floors: 1,
    heightPerFloor: 12,
    targetSegment: ['Gen-Z Trendsetters', 'Young Professionals']
  });

  const [currentResult, setCurrentResult] = useState<AnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  // Initialize Map
  useEffect(() => {
    if (!mapContainer.current) return;

    // Disable workers for stability in frames
    (maplibregl as any).workerCount = 0;

    let mapInstance: maplibregl.Map | null = null;

    try {
      mapInstance = new maplibregl.Map({
        container: mapContainer.current!,
        style: 'https://tiles.basemaps.cartocdn.com/gl/dark-matter-gl-style/style.json',
        center: [INITIAL_POS.lng, INITIAL_POS.lat],
        zoom: 14,
        pitch: 45,
        attributionControl: false,
        failIfMajorPerformanceCaveat: false
      });

      mapInstance.on('error', (e) => {
        console.warn('Map Encountered an Error:', e);
      });

      map.current = mapInstance;
    } catch (err) {
      console.error('Fatal MapLibre Init Error:', err);
    }

    return () => {
      if (mapInstance) mapInstance.remove();
    };
  }, []);

  // Update map center when coordinates or location changes (simulated for now)
  useEffect(() => {
    if (map.current && currentResult) {
      // In a real app, we'd geocode the location. Here we just fly back to a center
      map.current.flyTo({ center: [INITIAL_POS.lng, INITIAL_POS.lat], zoom: 16, essential: true });
    }
  }, [currentResult]);

  const handleAnalyze = async () => {
    setLoading(true);
    setError(null);
    try {
      const data = await GeminiService.analyzeMarket(input);
      const newResult: AnalysisResult = {
        ...data,
        id: crypto.randomUUID(),
        timestamp: Date.now(),
        originalInput: { ...input }
      };

      setHistory(prev => [newResult, ...prev]);
      setCurrentResult(newResult);
      setCompareMode(false);
    } catch (err: any) {
      setError(err.message || 'Analysis failed.');
    } finally {
      setLoading(false);
    }
  };

  const toggleSelectForCompare = (id: string) => {
    setSelectedIds(prev => 
      prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]
    );
  };

  const removeFromHistory = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setHistory(prev => prev.filter(item => item.id !== id));
    setSelectedIds(prev => prev.filter(i => i !== id));
    if (currentResult?.id === id) setCurrentResult(null);
  };

  const comparisonData = useMemo(() => {
    return history.filter(item => selectedIds.includes(item.id));
  }, [history, selectedIds]);

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('en-IN', {
      style: 'currency', currency: 'INR', maximumFractionDigits: 0
    }).format(val);
  };

  return (
    <div className="flex flex-col h-screen bg-[#f8fafc] text-slate-900 overflow-hidden">
      {/* Top Header */}
      <header className="h-16 bg-white border-b border-slate-200 px-6 flex items-center justify-between z-50 flex-shrink-0">
        <div className="flex items-center gap-4">
          <button 
            onClick={() => setSidebarOpen(!sidebarOpen)}
            className="p-2 hover:bg-slate-100 rounded-lg text-slate-500 transition-colors"
            title="Toggle History"
          >
            <History size={20} />
          </button>
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-1.5 rounded-lg text-white shadow-lg shadow-indigo-100">
              <Sparkles size={18} />
            </div>
            <h1 className="font-black text-slate-900 tracking-tight text-lg">LocalityMind</h1>
          </div>
        </div>

        <div className="flex items-center gap-3">
          {selectedIds.length > 0 && (
            <button 
              onClick={() => setCompareMode(!compareMode)}
              className={`flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-bold transition-all ${compareMode ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-200' : 'bg-indigo-50 text-indigo-700 hover:bg-indigo-100'}`}
            >
              <ArrowRightLeft size={16} />
              {compareMode ? 'Exit Comparison' : `Compare (${selectedIds.length})`}
            </button>
          )}
          <button 
            onClick={handleAnalyze}
            disabled={loading}
            className="bg-slate-900 text-white px-5 py-2 rounded-xl text-sm font-bold flex items-center gap-2 hover:bg-slate-800 transition-all disabled:opacity-50 shadow-lg shadow-slate-200"
          >
            {loading ? <Loader2 size={16} className="animate-spin" /> : <Target size={16} />}
            {loading ? 'Synthesizing...' : 'Analyze Market'}
          </button>
        </div>
      </header>

      <div className="flex flex-1 overflow-hidden relative">
        {/* History Sidebar */}
        <aside className={`glass-sidebar w-80 flex flex-col transition-all duration-300 overflow-hidden flex-shrink-0 border-r border-slate-100 ${sidebarOpen ? 'translate-x-0 relative' : '-translate-x-full absolute h-full z-40'}`}>
          <div className="p-4 border-b border-slate-100 flex items-center justify-between bg-white/50">
            <span className="text-xs font-black uppercase tracking-widest text-slate-400">Analysis History</span>
          </div>
          <div className="flex-1 overflow-y-auto custom-scrollbar p-2 space-y-1">
            {history.length === 0 ? (
              <div className="p-8 text-center text-slate-400 space-y-2 mt-10">
                <Info size={24} className="mx-auto opacity-20" />
                <p className="text-xs font-bold uppercase tracking-wider">No history recorded.</p>
              </div>
            ) : (
              history.map(item => (
                <div 
                  key={item.id}
                  onClick={() => { setCurrentResult(item); setCompareMode(false); }}
                  className={`group relative p-3 rounded-xl cursor-pointer transition-all border ${currentResult?.id === item.id ? 'bg-white border-indigo-200 shadow-md' : 'border-transparent hover:bg-white hover:border-slate-200'}`}
                >
                  <div className="flex justify-between items-start mb-1">
                    <h4 className="text-sm font-bold text-slate-900 truncate pr-6">{item.localityName}</h4>
                    <button onClick={(e) => removeFromHistory(item.id, e)} className="opacity-0 group-hover:opacity-100 p-1 hover:text-red-500 text-slate-300 transition-opacity">
                      <Trash2 size={12} />
                    </button>
                  </div>
                  <p className="text-[9px] font-black text-slate-400 uppercase tracking-tighter truncate">{item.originalInput.category}</p>
                  <div className="mt-2 flex items-center justify-between">
                    <span className="text-xs font-black text-indigo-600">{formatCurrency(item.revenueProjections.monthly)}/mo</span>
                    <button 
                      onClick={(e) => { e.stopPropagation(); toggleSelectForCompare(item.id); }}
                      className={`p-1 rounded-md transition-all ${selectedIds.includes(item.id) ? 'bg-indigo-600 text-white' : 'text-slate-300 hover:text-indigo-600'}`}
                      title="Select for Comparison"
                    >
                      <PlusCircle size={14} />
                    </button>
                  </div>
                </div>
              ))
            )}
          </div>
        </aside>

        {/* Main Content Area */}
        <main className="flex-1 overflow-y-auto custom-scrollbar bg-[#f8fafc]">
          {compareMode ? (
            /* Parallel Comparison View */
            <div className="p-6 lg:p-10 animate-in fade-in slide-in-from-bottom-4 duration-500">
              <div className="flex items-center justify-between mb-8">
                <div>
                  <h2 className="text-3xl font-black text-slate-900 tracking-tight">Parallel Comparison</h2>
                  <p className="text-sm text-slate-500 font-medium">Benchmarking {comparisonData.length} localities across business KPIs.</p>
                </div>
                <button onClick={() => setCompareMode(false)} className="p-3 hover:bg-slate-200 rounded-full text-slate-400 transition-colors"><X size={24}/></button>
              </div>

              <div className="bg-white rounded-[2.5rem] border border-slate-200 shadow-sm overflow-x-auto custom-scrollbar">
                <table className="w-full text-left border-collapse min-w-[1000px]">
                  <thead>
                    <tr className="bg-slate-50/50">
                      <th className="p-8 text-xs font-black uppercase text-slate-400 border-b border-slate-100 w-[250px]">Metric</th>
                      {comparisonData.map(item => (
                        <th key={item.id} className="p-8 text-base font-black text-slate-900 border-b border-slate-100">
                          {item.localityName}
                        </th>
                      ))}
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100">
                    <tr className="hover:bg-slate-50/30 transition-colors">
                      <td className="p-8 text-sm font-bold text-slate-500">Est. Revenue (Monthly)</td>
                      {comparisonData.map(item => (
                        <td key={item.id} className="p-8 text-xl font-black text-indigo-600">{formatCurrency(item.revenueProjections.monthly)}</td>
                      ))}
                    </tr>
                    <tr className="hover:bg-slate-50/30 transition-colors">
                      <td className="p-8 text-sm font-bold text-slate-500">Est. Revenue (Yearly)</td>
                      {comparisonData.map(item => (
                        <td key={item.id} className="p-8 text-base font-bold text-slate-900">{formatCurrency(item.revenueProjections.yearly)}</td>
                      ))}
                    </tr>
                    <tr className="hover:bg-slate-50/30 transition-colors">
                      <td className="p-8 text-sm font-bold text-slate-500">Daily Footfall Flow</td>
                      {comparisonData.map(item => (
                        <td key={item.id} className="p-8 text-base font-bold text-slate-900">{item.metrics.footfallEstimate.daily.toLocaleString()}</td>
                      ))}
                    </tr>
                    <tr className="hover:bg-slate-50/30 transition-colors">
                      <td className="p-8 text-sm font-bold text-slate-500">Income Proxy (PCI)</td>
                      {comparisonData.map(item => (
                        <td key={item.id} className="p-8 text-base font-bold text-slate-900">₹{item.demographics.perCapitaIncome.toLocaleString()}</td>
                      ))}
                    </tr>
                    <tr className="hover:bg-slate-50/30 transition-colors">
                      <td className="p-8 text-sm font-bold text-slate-500">Store footprint (Input)</td>
                      {comparisonData.map(item => (
                        <td key={item.id} className="p-8 text-base font-bold text-slate-900">{item.originalInput.length * item.originalInput.breadth} sq ft</td>
                      ))}
                    </tr>
                    <tr className="hover:bg-slate-50/30 transition-colors">
                      <td className="p-8 text-sm font-bold text-slate-500">Yield per Sq Ft (Annual)</td>
                      {comparisonData.map(item => {
                        const area = item.originalInput.length * item.originalInput.breadth;
                        const density = item.revenueProjections.yearly / area;
                        return <td key={item.id} className="p-8 text-base font-black text-slate-600">₹{Math.round(density).toLocaleString()}</td>;
                      })}
                    </tr>
                    <tr className="hover:bg-slate-50/30 transition-colors">
                      <td className="p-8 text-sm font-bold text-slate-500">Locality Profile</td>
                      {comparisonData.map(item => (
                        <td key={item.id} className="p-8">
                          <span className="px-4 py-1.5 bg-slate-100 rounded-full text-xs font-black uppercase text-slate-600 tracking-wider">
                            {item.demographics.residentType}
                          </span>
                        </td>
                      ))}
                    </tr>
                  </tbody>
                </table>
              </div>
            </div>
          ) : (
            /* Single Analysis View with MAXIMIZED MAP */
            <div className="flex flex-col animate-in fade-in duration-700">

              {/* MAXIMIZED MAP SECTION */}
              <section className="relative w-full h-[600px] bg-slate-900 border-b border-slate-200 overflow-hidden group">
                <div ref={mapContainer} className="w-full h-full" />

                {/* Floating Map Overlays */}
                <div className="absolute top-6 right-6 pointer-events-none z-10 space-y-3">
                  <div className="bg-slate-950/80 backdrop-blur px-4 py-2 rounded-xl border border-slate-800 text-[10px] font-black text-white uppercase tracking-[0.2em] flex items-center gap-2 shadow-2xl">
                    <Globe size={14} className="text-indigo-400" /> Geospatial Recon Active
                  </div>
                  {currentResult && (
                    <div className="bg-white/90 backdrop-blur px-4 py-3 rounded-xl border border-white text-slate-900 shadow-2xl animate-in slide-in-from-right-4 duration-500">
                      <p className="text-[9px] font-black uppercase text-slate-400 tracking-widest mb-1">Target Identified</p>
                      <p className="text-sm font-black">{currentResult.localityName}</p>
                    </div>
                  )}
                </div>

                {/* Floating Configuration Panel */}
                <div className="absolute top-6 left-6 z-20 w-full max-w-sm pointer-events-none">
                  <div className="pointer-events-auto bg-white/90 backdrop-blur-xl p-8 rounded-[2.5rem] border border-white shadow-[0_20px_50px_rgba(0,0,0,0.15)] space-y-6">
                    <div className="flex items-center justify-between">
                      <h3 className="text-xs font-black uppercase tracking-[0.2em] text-slate-400 flex items-center gap-2">
                        <Target size={14} className="text-indigo-600" /> New Parameter Set
                      </h3>
                      {loading && <Loader2 size={16} className="animate-spin text-indigo-600" />}
                    </div>

                    <div className="space-y-4">
                      <div>
                        <label className="block text-[10px] font-black text-slate-400 mb-2 uppercase tracking-widest">Locality Target</label>
                        <div className="relative">
                          <MapPin className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-300" size={16} />
                          <input 
                            type="text" 
                            value={input.location} 
                            onChange={(e) => setInput({...input, location: e.target.value})}
                            className="w-full bg-slate-50 border border-slate-200 rounded-xl py-3 pl-9 pr-4 text-sm font-bold focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                            placeholder="e.g. Bandra West, Mumbai"
                          />
                        </div>
                      </div>
                      <div className="grid grid-cols-2 gap-4">
                        <div>
                          <label className="block text-[10px] font-black text-slate-400 mb-2 uppercase tracking-widest">Width (ft)</label>
                          <input type="number" value={input.length} onChange={(e) => setInput({...input, length: Number(e.target.value)})} className="w-full bg-slate-50 border border-slate-200 rounded-xl py-3 px-4 text-sm font-bold" />
                        </div>
                        <div>
                          <label className="block text-[10px] font-black text-slate-400 mb-2 uppercase tracking-widest">Depth (ft)</label>
                          <input type="number" value={input.breadth} onChange={(e) => setInput({...input, breadth: Number(e.target.value)})} className="w-full bg-slate-50 border border-slate-200 rounded-xl py-3 px-4 text-sm font-bold" />
                        </div>
                      </div>
                      <div>
                        <label className="block text-[10px] font-black text-slate-400 mb-2 uppercase tracking-widest">Store Format</label>
                        <select value={input.category} onChange={(e) => setInput({...input, category: e.target.value as StoreCategory})} className="w-full bg-slate-50 border border-slate-200 rounded-xl py-3 px-4 text-sm font-bold cursor-pointer appearance-none">
                          {STORE_CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
                        </select>
                      </div>
                      <button 
                        onClick={handleAnalyze}
                        disabled={loading}
                        className="w-full mt-2 bg-indigo-600 text-white py-4 rounded-2xl text-sm font-black uppercase tracking-widest hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100 disabled:opacity-50 flex items-center justify-center gap-2"
                      >
                        {loading ? <Loader2 size={18} className="animate-spin" /> : <Activity size={18} />}
                        Execute analysis
                      </button>
                    </div>
                  </div>
                </div>
              </section>

              {/* RESULTS SECTION BELOW MAP */}
              <div className="p-6 lg:p-10 space-y-12">
                {error && (
                  <div className="max-w-4xl mx-auto p-6 bg-red-50 border border-red-100 rounded-3xl flex items-center gap-4 text-red-700 animate-in fade-in duration-300">
                    <AlertCircle size={24} />
                    <p className="text-sm font-bold">{error}</p>
                  </div>
                )}

                {currentResult ? (
                  <div className="space-y-12 animate-in fade-in slide-in-from-bottom-8 duration-1000">

                    {/* Primary Stats Header */}
                    <div className="flex flex-col lg:flex-row gap-8 items-start justify-between">
                       <div className="space-y-2">
                          <h2 className="text-7xl font-black tracking-tighter text-slate-900 leading-none">{currentResult.localityName}</h2>
                          <div className="flex items-center gap-4">
                             <span className="px-4 py-1.5 bg-indigo-600 text-white rounded-full text-[10px] font-black uppercase tracking-widest">Live Report</span>
                             <span className="text-slate-400 text-sm font-bold flex items-center gap-1 uppercase tracking-widest">
                               <Maximize2 size={14} /> {currentResult.originalInput.length * currentResult.originalInput.breadth} sq ft format
                             </span>
                          </div>
                       </div>
                       <div className="grid grid-cols-2 gap-8 bg-white p-10 rounded-[3rem] border border-slate-200 shadow-sm min-w-[400px]">
                          <div>
                             <p className="text-[10px] font-black uppercase tracking-widest text-indigo-600 mb-1">Monthly Yield</p>
                             <p className="text-4xl font-black text-slate-900">{formatCurrency(currentResult.revenueProjections.monthly)}</p>
                          </div>
                          <div>
                             <p className="text-[10px] font-black uppercase tracking-widest text-indigo-600 mb-1">Annual Forecast</p>
                             <p className="text-4xl font-black text-slate-900">{formatCurrency(currentResult.revenueProjections.yearly)}</p>
                          </div>
                       </div>
                    </div>

                    {/* Quick Metrics Grid */}
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                      <MetricCard title="Visitor Flow" value={currentResult.metrics.footfallEstimate.daily.toLocaleString()} Icon={Users} subtitle="Daily Footfall" />
                      <MetricCard title="Economy Proxy" value={`₹${currentResult.demographics.perCapitaIncome.toLocaleString()}`} Icon={CircleDollarSign} subtitle={currentResult.demographics.socioeconomicTier} />
                      <MetricCard title="Catchment" value={currentResult.demographics.residentType} Icon={Home} subtitle="Market Archetype" />
                      <MetricCard title="Rivals" value={currentResult.metrics.storeCompetition.length} Icon={ShoppingBag} subtitle="Direct Competitors" />
                    </div>

                    {/* Data Visualizations */}
                    <div className="grid grid-cols-1 xl:grid-cols-2 gap-8">
                      <RevenueChart projections={currentResult.revenueProjections} />
                      <TrafficLandscape data={currentResult.metrics.footfallEstimate.hourlyDistribution} />
                    </div>

                    {/* Competition Table */}
                    <section className="bg-white p-12 rounded-[4rem] border border-slate-200 shadow-sm overflow-hidden">
                       <div className="flex items-center justify-between mb-10">
                          <div>
                            <h3 className="text-xs font-black uppercase tracking-[0.4em] text-slate-400 mb-2">Competitive Landscape</h3>
                            <p className="text-slate-500 text-sm font-semibold">Identified market rivals and price points</p>
                          </div>
                          <div className="p-3 bg-slate-50 rounded-2xl text-slate-400">
                             <ShoppingBag size={24} />
                          </div>
                       </div>
                       <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                          {currentResult.metrics.storeCompetition.map((comp, idx) => (
                            <div key={idx} className="p-6 bg-slate-50/50 rounded-3xl border border-slate-100 hover:bg-white hover:shadow-xl hover:border-indigo-100 transition-all group">
                               <p className="text-xs font-black text-indigo-600 uppercase tracking-widest mb-1">{comp.avgPricePoint}</p>
                               <h4 className="text-lg font-black text-slate-900 mb-2 group-hover:text-indigo-600 transition-colors">{comp.type}</h4>
                               <p className="text-xs font-bold text-slate-500 leading-relaxed mb-4">{comp.description}</p>
                               <div className="flex items-center gap-2 text-[10px] font-black text-slate-400 uppercase tracking-wider">
                                  <div className="w-1.5 h-1.5 rounded-full bg-slate-300" /> {comp.count} Local Nodes
                               </div>
                            </div>
                          ))}
                       </div>
                    </section>

                    {/* Strategy Roadmap */}
                    <section className="bg-slate-900 text-white p-16 rounded-[5rem] shadow-2xl relative overflow-hidden">
                      <div className="absolute top-0 right-0 p-12 opacity-5">
                        <Compass size={300} />
                      </div>
                      <div className="relative z-10 max-w-5xl mx-auto">
                        <div className="flex items-center gap-4 mb-12">
                          <div className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center shadow-xl shadow-indigo-900">
                            <Compass size={24} />
                          </div>
                          <div>
                            <p className="text-[10px] font-black uppercase tracking-[0.5em] text-indigo-400">Strategic Intelligence</p>
                            <h3 className="text-3xl font-black tracking-tight">AI Deployment Roadmap</h3>
                          </div>
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                          {currentResult.strategicAdvice.map((advice, i) => (
                            <div key={i} className="flex gap-6 group">
                              <div className="flex-shrink-0 w-10 h-10 rounded-full border border-white/20 flex items-center justify-center text-xs font-black group-hover:bg-indigo-600 group-hover:border-indigo-600 transition-all">{i+1}</div>
                              <p className="text-base font-bold text-slate-300 leading-relaxed group-hover:text-white transition-colors">{advice}</p>
                            </div>
                          ))}
                        </div>
                      </div>
                    </section>
                  </div>
                ) : (
                  /* Expanded Empty State */
                  <div className="min-h-[500px] border-2 border-dashed border-slate-200 rounded-[5rem] flex flex-col items-center justify-center text-center p-20 animate-in fade-in zoom-in duration-1000">
                    <div className="bg-white p-10 rounded-3xl shadow-lg border border-slate-100 mb-8 transform hover:scale-105 transition-transform cursor-default">
                      <Activity size={64} className="text-indigo-600 opacity-20" />
                    </div>
                    <h3 className="text-3xl font-black text-slate-900 mb-3 uppercase tracking-tight leading-none">Intelligence Engine Offline</h3>
                    <p className="text-[11px] text-slate-400 font-black max-w-md uppercase leading-relaxed tracking-[0.3em]">Configure your store format and geographic constraints in the floating recon panel to initiate synthesis.</p>
                  </div>
                )}
              </div>
            </div>
          )}
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { 
  MapPin, Users, Sparkles, 
  Loader2, ExternalLink, LayoutGrid,
  CircleDollarSign, Building2,
  Globe, Home, Check, AlertCircle,
  Activity, ShoppingBag, Info, Compass, Target,
  History, X, ChevronRight, BarChart3, ArrowRightLeft,
  Trash2, PlusCircle, Maximize2, Menu
} from 'lucide-react';
import maplibregl from 'maplibre-gl';
import { StoreInput, AnalysisResult, StoreCategory } from './types';
import { GeminiService } from './services/geminiService';
import { MetricCard } from './components/MetricCard';
import { RevenueChart } from './components/RevenueChart';
import { TrafficLandscape } from './components/TrafficLandscape';

const STORE_CATEGORIES: StoreCategory[] = [
  'Premium Cafe (e.g., Starbucks)',
  'Large Attraction (e.g., Zoo / Theme Park)',
  'Supermarket (e.g., Reliance Fresh / DMart)',
  'Luxury Fashion / Boutique',
  'Pharmacy / Wellness',
  'Fine Dining Restaurant',
  'Workspace / Coworking',
  'Quick Service Restaurant (QSR)'
];

const INITIAL_POS = { lat: 19.0596, lng: 72.8295 };

const App: React.FC = () => {
  const mapContainer = useRef<HTMLDivElement>(null);
  const map = useRef<maplibregl.Map | null>(null);

  // App State
  const [loading, setLoading] = useState(false);
  const [history, setHistory] = useState<AnalysisResult[]>([]);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [compareMode, setCompareMode] = useState(false);
  const [sidebarOpen, setSidebarOpen] = useState(false);

  // Current Analysis State
  const [input, setInput] = useState<StoreInput>({
    location: 'Bandra West, Mumbai',
    coordinates: { ...INITIAL_POS },
    category: 'Premium Cafe (e.g., Starbucks)',
    length: 40,
    breadth: 50,
    floors: 1,
    heightPerFloor: 12,
    targetSegment: ['Gen-Z Trendsetters', 'Young Professionals']
  });

  const [currentResult, setCurrentResult] = useState<AnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  // Initialize Map
  useEffect(() => {
    if (!mapContainer.current) return;

    (maplibregl as any).workerCount = 0;

    let mapInstance: maplibregl.Map | null = null;

    try {
      mapInstance = new maplibregl.Map({
        container: mapContainer.current!,
        style: 'https://tiles.basemaps.cartocdn.com/gl/dark-matter-gl-style/style.json',
        center: [INITIAL_POS.lng, INITIAL_POS.lat],
        zoom: 14,
        pitch: 60,
        bearing: -20,
        attributionControl: false,
        failIfMajorPerformanceCaveat: false
      });

      mapInstance.on('error', (e) => {
        console.warn('Map Encountered an Error:', e);
      });

      map.current = mapInstance;
    } catch (err) {
      console.error('Fatal MapLibre Init Error:', err);
    }

    return () => {
      if (mapInstance) mapInstance.remove();
    };
  }, []);

  useEffect(() => {
    if (map.current && currentResult) {
      map.current.flyTo({ center: [INITIAL_POS.lng, INITIAL_POS.lat], zoom: 16, essential: true });
    }
  }, [currentResult]);

  const handleAnalyze = async () => {
    setLoading(true);
    setError(null);
    try {
      const data = await GeminiService.analyzeMarket(input);
      const newResult: AnalysisResult = {
        ...data,
        id: crypto.randomUUID(),
        timestamp: Date.now(),
        originalInput: { ...input }
      };

      setHistory(prev => [newResult, ...prev]);
      setCurrentResult(newResult);
      setCompareMode(false);
    } catch (err: any) {
      setError(err.message || 'Analysis failed.');
    } finally {
      setLoading(false);
    }
  };

  const toggleSelectForCompare = (id: string) => {
    setSelectedIds(prev => 
      prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]
    );
  };

  const removeFromHistory = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setHistory(prev => prev.filter(item => item.id !== id));
    setSelectedIds(prev => prev.filter(i => i !== id));
    if (currentResult?.id === id) setCurrentResult(null);
  };

  const comparisonData = useMemo(() => {
    return history.filter(item => selectedIds.includes(item.id));
  }, [history, selectedIds]);

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('en-IN', {
      style: 'currency', currency: 'INR', maximumFractionDigits: 0
    }).format(val);
  };

  return (
    <div className="flex flex-col h-screen bg-[#f8fafc] text-slate-900 overflow-hidden relative">
      {/* Top Header */}
      <header className="h-16 bg-white/80 backdrop-blur-md border-b border-slate-200 px-6 flex items-center justify-between z-[60] flex-shrink-0">
        <div className="flex items-center gap-4">
          <button 
            onClick={() => setSidebarOpen(true)}
            className="p-2 hover:bg-slate-100 rounded-lg text-slate-500 transition-colors"
            title="Open History"
          >
            <Menu size={20} />
          </button>
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-1.5 rounded-lg text-white shadow-lg shadow-indigo-100">
              <Sparkles size={18} />
            </div>
            <h1 className="font-black text-slate-900 tracking-tight text-lg">LocalityMind</h1>
          </div>
        </div>

        <div className="flex items-center gap-3">
          {selectedIds.length > 0 && (
            <button 
              onClick={() => setCompareMode(!compareMode)}
              className={`flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-bold transition-all ${compareMode ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-200' : 'bg-indigo-50 text-indigo-700 hover:bg-indigo-100'}`}
            >
              <ArrowRightLeft size={16} />
              {compareMode ? 'Exit Comparison' : `Compare (${selectedIds.length})`}
            </button>
          )}
          <button 
            onClick={handleAnalyze}
            disabled={loading}
            className="bg-slate-900 text-white px-5 py-2 rounded-xl text-sm font-bold flex items-center gap-2 hover:bg-slate-800 transition-all disabled:opacity-50 shadow-lg shadow-slate-200"
          >
            {loading ? <Loader2 size={16} className="animate-spin" /> : <Target size={16} />}
            {loading ? 'Synthesizing...' : 'Analyze Market'}
          </button>
        </div>
      </header>

      {/* Sliding Sidebar Overlay */}
      {sidebarOpen && (
        <div 
          className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-[70] transition-opacity"
          onClick={() => setSidebarOpen(false)}
        />
      )}
      <aside className={`fixed top-0 left-0 h-full w-80 bg-white shadow-2xl z-[80] transform transition-transform duration-300 ease-in-out ${sidebarOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="flex flex-col h-full">
          <div className="p-6 border-b border-slate-100 flex items-center justify-between">
            <span className="text-xs font-black uppercase tracking-widest text-slate-400 flex items-center gap-2">
               <History size={14} /> Analysis History
            </span>
            <button onClick={() => setSidebarOpen(false)} className="p-1.5 hover:bg-slate-100 rounded-lg text-slate-400">
              <X size={18} />
            </button>
          </div>
          <div className="flex-1 overflow-y-auto custom-scrollbar p-4 space-y-3">
            {history.length === 0 ? (
              <div className="p-12 text-center text-slate-400 space-y-3 mt-10">
                <Info size={32} className="mx-auto opacity-20" />
                <p className="text-xs font-black uppercase tracking-widest leading-relaxed">System history is currently empty</p>
              </div>
            ) : (
              history.map(item => (
                <div 
                  key={item.id}
                  onClick={() => { setCurrentResult(item); setCompareMode(false); setSidebarOpen(false); }}
                  className={`group relative p-4 rounded-2xl cursor-pointer transition-all border ${currentResult?.id === item.id ? 'bg-indigo-50/50 border-indigo-200 shadow-sm' : 'border-slate-100 hover:bg-slate-50 hover:border-slate-200'}`}
                >
                  <div className="flex justify-between items-start mb-2">
                    <h4 className="text-sm font-black text-slate-900 truncate pr-6 leading-tight">{item.localityName}</h4>
                    <button onClick={(e) => removeFromHistory(item.id, e)} className="opacity-0 group-hover:opacity-100 p-1 hover:text-red-500 text-slate-300 transition-opacity">
                      <Trash2 size={12} />
                    </button>
                  </div>
                  <p className="text-[9px] font-black text-slate-400 uppercase tracking-tighter truncate">{item.originalInput.category}</p>
                  <div className="mt-3 flex items-center justify-between">
                    <span className="text-xs font-black text-indigo-600">{formatCurrency(item.revenueProjections.monthly)}/mo</span>
                    <button 
                      onClick={(e) => { e.stopPropagation(); toggleSelectForCompare(item.id); }}
                      className={`p-1.5 rounded-lg transition-all ${selectedIds.includes(item.id) ? 'bg-indigo-600 text-white' : 'text-slate-300 hover:text-indigo-600 bg-slate-100'}`}
                      title="Select for Comparison"
                    >
                      <PlusCircle size={14} />
                    </button>
                  </div>
                </div>
              ))
            )}
          </div>
        </div>
      </aside>

      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto custom-scrollbar bg-[#f8fafc]">
        {compareMode ? (
          /* Parallel Comparison View */
          <div className="p-8 lg:p-12 animate-in fade-in slide-in-from-bottom-4 duration-500 max-w-[1600px] mx-auto">
            <div className="flex items-center justify-between mb-10">
              <div>
                <h2 className="text-4xl font-black text-slate-900 tracking-tighter">Market Benchmarking</h2>
                <p className="text-sm text-slate-500 font-medium">Side-by-side performance synthesis of {comparisonData.length} localities.</p>
              </div>
              <button onClick={() => setCompareMode(false)} className="p-4 hover:bg-slate-200 rounded-full text-slate-400 transition-colors"><X size={28}/></button>
            </div>

            <div className="bg-white rounded-[3rem] border border-slate-200 shadow-sm overflow-hidden overflow-x-auto custom-scrollbar">
              <table className="w-full text-left border-collapse min-w-[1200px]">
                <thead>
                  <tr className="bg-slate-50/80 backdrop-blur">
                    <th className="p-10 text-xs font-black uppercase text-slate-400 border-b border-slate-100 w-[300px] tracking-widest">Core Business KPI</th>
                    {comparisonData.map(item => (
                      <th key={item.id} className="p-10 text-lg font-black text-slate-900 border-b border-slate-100">
                        {item.localityName}
                      </th>
                    ))}
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  <tr className="hover:bg-indigo-50/20 transition-colors">
                    <td className="p-10 text-sm font-bold text-slate-500 uppercase tracking-widest">Monthly Est. Revenue</td>
                    {comparisonData.map(item => (
                      <td key={item.id} className="p-10 text-2xl font-black text-indigo-600 leading-none">{formatCurrency(item.revenueProjections.monthly)}</td>
                    ))}
                  </tr>
                  <tr className="hover:bg-slate-50/50 transition-colors">
                    <td className="p-10 text-sm font-bold text-slate-500 uppercase tracking-widest">Annual Gross Forecast</td>
                    {comparisonData.map(item => (
                      <td key={item.id} className="p-10 text-xl font-bold text-slate-900">{formatCurrency(item.revenueProjections.yearly)}</td>
                    ))}
                  </tr>
                  <tr className="hover:bg-slate-50/50 transition-colors">
                    <td className="p-10 text-sm font-bold text-slate-500 uppercase tracking-widest">Daily Footfall Stream</td>
                    {comparisonData.map(item => (
                      <td key={item.id} className="p-10 text-xl font-bold text-slate-900">{item.metrics.footfallEstimate.daily.toLocaleString()}</td>
                    ))}
                  </tr>
                  <tr className="hover:bg-slate-50/50 transition-colors">
                    <td className="p-10 text-sm font-bold text-slate-500 uppercase tracking-widest">PCI Economic Proxy</td>
                    {comparisonData.map(item => (
                      <td key={item.id} className="p-10 text-xl font-bold text-slate-900">₹{item.demographics.perCapitaIncome.toLocaleString()}</td>
                    ))}
                  </tr>
                  <tr className="hover:bg-slate-50/50 transition-colors">
                    <td className="p-10 text-sm font-bold text-slate-500 uppercase tracking-widest">Format Footprint</td>
                    {comparisonData.map(item => (
                      <td key={item.id} className="p-10 text-xl font-bold text-slate-900">{item.originalInput.length * item.originalInput.breadth} sq ft</td>
                    ))}
                  </tr>
                  <tr className="hover:bg-slate-50/50 transition-colors">
                    <td className="p-10 text-sm font-bold text-slate-500 uppercase tracking-widest">Annual Yield Density</td>
                    {comparisonData.map(item => {
                      const area = item.originalInput.length * item.originalInput.breadth;
                      const density = item.revenueProjections.yearly / area;
                      return <td key={item.id} className="p-10 text-xl font-black text-slate-600">₹{Math.round(density).toLocaleString()} / sqft</td>;
                    })}
                  </tr>
                  <tr className="hover:bg-slate-50/50 transition-colors">
                    <td className="p-10 text-sm font-bold text-slate-500 uppercase tracking-widest">Resident Catchment</td>
                    {comparisonData.map(item => (
                      <td key={item.id} className="p-10">
                        <span className="px-5 py-2 bg-slate-100 rounded-full text-xs font-black uppercase text-slate-600 tracking-[0.2em]">
                          {item.demographics.residentType}
                        </span>
                      </td>
                    ))}
                  </tr>
                </tbody>
              </table>
            </div>
          </div>
        ) : (
          /* Single Analysis View with FULL SCREEN MAP */
          <div className="flex flex-col animate-in fade-in duration-700">

            {/* FULL SCREEN MAP SECTION */}
            <section className="relative w-full h-[85vh] bg-slate-900 border-b border-slate-200 overflow-hidden group">
              <div ref={mapContainer} className="w-full h-full" />

              {/* Floating Map Overlays */}
              <div className="absolute top-8 right-8 pointer-events-none z-10 space-y-4">
                <div className="bg-slate-950/70 backdrop-blur-md px-5 py-2.5 rounded-2xl border border-slate-700/50 text-[10px] font-black text-white uppercase tracking-[0.3em] flex items-center gap-3 shadow-2xl">
                  <div className="w-2 h-2 rounded-full bg-indigo-500 animate-pulse" /> FUSED SPATIAL LAYER
                </div>
                {currentResult && (
                  <div className="bg-white/90 backdrop-blur-xl px-6 py-4 rounded-[2rem] border border-white text-slate-900 shadow-2xl animate-in slide-in-from-right-8 duration-700">
                    <p className="text-[10px] font-black uppercase text-indigo-500 tracking-widest mb-1.5">Selected Node</p>
                    <p className="text-xl font-black tracking-tight">{currentResult.localityName}</p>
                    <div className="mt-2 flex items-center gap-2 text-[10px] font-bold text-slate-400">
                       <MapPin size={12} /> {INITIAL_POS.lat.toFixed(4)}, {INITIAL_POS.lng.toFixed(4)}
                    </div>
                  </div>
                )}
              </div>

              {/* TRANSPARENT FLOATING CONFIG PANEL */}
              <div className="absolute inset-y-0 left-0 z-20 w-full max-w-md p-8 pointer-events-none flex flex-col justify-center">
                <div className="pointer-events-auto bg-slate-950/40 backdrop-blur-2xl p-10 rounded-[3.5rem] border border-white/10 shadow-[0_30px_100px_rgba(0,0,0,0.5)] space-y-8 text-white">
                  <div className="flex items-center justify-between">
                    <h3 className="text-[10px] font-black uppercase tracking-[0.4em] text-white/40 flex items-center gap-2">
                      <Target size={14} className="text-indigo-400" /> Intelligence Input
                    </h3>
                    {loading && <Loader2 size={16} className="animate-spin text-indigo-400" />}
                  </div>

                  <div className="space-y-6">
                    <div>
                      <label className="block text-[10px] font-black text-white/30 mb-3 uppercase tracking-widest">Locality Target</label>
                      <div className="relative group/input">
                        <MapPin className="absolute left-4 top-1/2 -translate-y-1/2 text-white/40 group-focus-within/input:text-indigo-400 transition-colors" size={18} />
                        <input 
                          type="text" 
                          value={input.location} 
                          onChange={(e) => setInput({...input, location: e.target.value})}
                          className="w-full bg-white/5 border border-white/10 rounded-2xl py-4 pl-12 pr-6 text-sm font-bold text-white focus:ring-2 focus:ring-indigo-500/50 outline-none transition-all placeholder:text-white/20"
