                      <div>
                        <label className="block text-[10px] font-black text-white/30 mb-3 uppercase tracking-widest">Depth (ft)</label>
                        <input type="number" value={input.breadth} onChange={(e) => setInput({...input, breadth: Number(e.target.value)})} className="w-full bg-white/5 border border-white/10 rounded-2xl py-4 px-6 text-sm font-bold text-white focus:ring-2 focus:ring-indigo-500/50 outline-none" />
                      </div>
                    </div>
                    <div>
                      <label className="block text-[10px] font-black text-white/30 mb-3 uppercase tracking-widest">Business Format</label>
                      <div className="relative">
                        <select value={input.category} onChange={(e) => setInput({...input, category: e.target.value as StoreCategory})} className="w-full bg-white/5 border border-white/10 rounded-2xl py-4 px-6 text-sm font-bold text-white focus:ring-2 focus:ring-indigo-500/50 outline-none cursor-pointer appearance-none">
                          {STORE_CATEGORIES.map(c => <option key={c} value={c} className="bg-slate-900">{c}</option>)}
                        </select>
                        <ChevronRight className="absolute right-6 top-1/2 -translate-y-1/2 rotate-90 text-white/20 pointer-events-none" size={16} />
                      </div>
                    </div>
                    <button 
                      onClick={handleAnalyze}
                      disabled={loading}
                      className="w-full mt-4 bg-indigo-600 text-white py-5 rounded-[2rem] text-xs font-black uppercase tracking-[0.3em] hover:bg-indigo-700 transition-all shadow-2xl shadow-indigo-500/20 disabled:opacity-50 flex items-center justify-center gap-3 active:scale-95"
                    >
                      {loading ? <Loader2 size={20} className="animate-spin" /> : <Activity size={20} />}
                      {loading ? 'Processing System' : 'Synthesize Site'}
                    </button>
                  </div>
                </div>
              </div>

              {/* BOTTOM MAP HUD */}
              <div className="absolute bottom-8 left-1/2 -translate-x-1/2 z-10 hidden md:flex items-center gap-4">
                 <div className="bg-slate-950/80 backdrop-blur-xl border border-white/10 px-6 py-3 rounded-full flex items-center gap-6 shadow-2xl">
                    <div className="flex items-center gap-2">
                       <div className="w-1.5 h-1.5 rounded-full bg-green-500" />
                       <span className="text-[10px] font-black text-white/60 uppercase tracking-widest">OSM Dataset</span>
                    </div>
                    <div className="w-px h-4 bg-white/10" />
                    <div className="flex items-center gap-2">
                       <div className="w-1.5 h-1.5 rounded-full bg-indigo-500" />
                       <span className="text-[10px] font-black text-white/60 uppercase tracking-widest">Socioeconomic Heat</span>
                    </div>
                 </div>
              </div>
            </section>

            {/* RESULTS SECTION */}
            <div className="p-8 lg:p-16 space-y-20 bg-white">
              {error && (
                <div className="max-w-4xl mx-auto p-8 bg-red-50 border border-red-100 rounded-[2.5rem] flex items-center gap-6 text-red-700 animate-in fade-in duration-300 shadow-sm">
                  <div className="p-3 bg-red-100 rounded-2xl">
                    <AlertCircle size={24} />
                  </div>
                  <p className="text-base font-bold">{error}</p>
                </div>
              )}

              {loading ? (
                <div className="h-full min-h-[500px] flex flex-col items-center justify-center p-12 text-center animate-pulse">
                  <div className="relative mb-10">
                    <div className="absolute inset-0 bg-indigo-500 blur-[80px] opacity-10" />
                    <div className="w-24 h-24 bg-white rounded-[2rem] shadow-2xl flex items-center justify-center border border-slate-100 relative overflow-hidden">
                       <Loader2 className="w-10 h-10 text-indigo-600 animate-spin" />
                    </div>
                  </div>
                  <h3 className="text-2xl font-black text-slate-900 mb-3 uppercase tracking-tight">System Recalibrating</h3>
                  <p className="text-[10px] text-slate-400 font-black max-w-xs uppercase leading-relaxed tracking-[0.4em]">Fusing Real-Time Geospatial Streams...</p>
                </div>
              ) : currentResult ? (
                <div className="space-y-24 animate-in fade-in slide-in-from-bottom-12 duration-1000">

                  {/* Primary Stats Header */}
                  <div className="flex flex-col lg:flex-row gap-12 items-end justify-between border-b border-slate-100 pb-16">
                     <div className="space-y-4 max-w-2xl">
                        <div className="flex items-center gap-4">
                           <span className="px-5 py-2 bg-indigo-600 text-white rounded-full text-[10px] font-black uppercase tracking-[0.3em]">Market ID: Identified</span>
                        </div>
                        <h2 className="text-[10rem] font-black tracking-tighter text-slate-900 leading-[0.8] drop-shadow-sm">{currentResult.localityName}</h2>
                        <div className="flex items-center gap-6 mt-6">
                           <span className="text-slate-400 text-sm font-black flex items-center gap-2 uppercase tracking-widest">
                             <Maximize2 size={16} className="text-indigo-400" /> {currentResult.originalInput.length * currentResult.originalInput.breadth} SQ FT PROJECT
                           </span>
                           <div className="w-2 h-2 rounded-full bg-slate-200" />
                           <span className="text-slate-400 text-sm font-black flex items-center gap-2 uppercase tracking-widest">
                             {currentResult.demographics.residentType} PROFILE
                           </span>
                        </div>
                     </div>
                     <div className="grid grid-cols-1 md:grid-cols-2 gap-10 bg-slate-50 p-12 rounded-[4rem] border border-slate-100 shadow-inner w-full lg:w-auto min-w-[500px]">
                        <div className="space-y-2">
                           <p className="text-[10px] font-black uppercase tracking-[0.4em] text-indigo-600">Monthly Projection</p>
                           <p className="text-5xl font-black text-slate-900">{formatCurrency(currentResult.revenueProjections.monthly)}</p>
                        </div>
                        <div className="space-y-2">
                           <p className="text-[10px] font-black uppercase tracking-[0.4em] text-indigo-600">Annual Gross Potential</p>
                           <p className="text-5xl font-black text-slate-900">{formatCurrency(currentResult.revenueProjections.yearly)}</p>
                        </div>
                     </div>
                  </div>

                  {/* Quick Metrics Grid */}
                  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
                    <MetricCard title="Footfall Velocity" value={currentResult.metrics.footfallEstimate.daily.toLocaleString()} Icon={Users} subtitle="Daily Pedestrian Flow" />
                    <MetricCard title="Economy Grade" value={`₹${currentResult.demographics.perCapitaIncome.toLocaleString()}`} Icon={CircleDollarSign} subtitle={currentResult.demographics.socioeconomicTier} />
                    <MetricCard title="Urban Context" value={currentResult.demographics.populationDensity} Icon={Home} subtitle="Residential Density" />
                    <MetricCard title="Market Rivals" value={currentResult.metrics.storeCompetition.length} Icon={ShoppingBag} subtitle="Local Competitors" />
                  </div>

                  {/* Data Visualizations */}
                  <div className="grid grid-cols-1 xl:grid-cols-2 gap-12 items-start">
                    <RevenueChart projections={currentResult.revenueProjections} />
                    <TrafficLandscape data={currentResult.metrics.footfallEstimate.hourlyDistribution} />
                  </div>

                  {/* Competition Landscape */}
                  <section className="space-y-12">
                     <div className="flex items-end justify-between px-2">
                        <div className="space-y-2">
                          <h3 className="text-xs font-black uppercase tracking-[0.5em] text-slate-400">Neighborhood Intel</h3>
                          <p className="text-4xl font-black text-slate-900 tracking-tight">Competitive Landscape</p>
                        </div>
                        <div className="p-4 bg-slate-50 rounded-[2rem] text-slate-400">
                           <ShoppingBag size={32} />
                        </div>
                     </div>
                     <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                        {currentResult.metrics.storeCompetition.map((comp, idx) => (
                          <div key={idx} className="p-10 bg-white rounded-[3.5rem] border border-slate-100 hover:shadow-2xl hover:border-indigo-100 transition-all group relative overflow-hidden">
                             <div className="absolute top-0 right-0 p-8 opacity-[0.03] group-hover:scale-125 transition-transform duration-700">
                                <ShoppingBag size={120} />
                             </div>
                             <p className="text-[10px] font-black text-indigo-600 uppercase tracking-[0.2em] mb-3">{comp.avgPricePoint}</p>
                             <h4 className="text-2xl font-black text-slate-900 mb-4 group-hover:text-indigo-600 transition-colors">{comp.type}</h4>
                             <p className="text-sm font-bold text-slate-500 leading-relaxed mb-8">{comp.description}</p>
                             <div className="flex items-center gap-3">
                                <div className="px-4 py-1.5 bg-slate-50 rounded-full text-[10px] font-black text-slate-400 uppercase tracking-widest">
                                   {comp.count} Nodes Active
                                </div>
                             </div>
                          </div>
                        ))}
                     </div>
                  </section>

                  {/* Strategic Deployment Roadmap */}
                  <section className="bg-slate-950 text-white p-20 rounded-[6rem] shadow-[0_50px_100px_-20px_rgba(0,0,0,0.3)] relative overflow-hidden group">
                    <div className="absolute top-0 right-0 p-20 opacity-5 transition-transform group-hover:rotate-12 duration-1000">
                      <Compass size={400} />
                    </div>
                    <div className="relative z-10 max-w-5xl mx-auto space-y-16">
                      <div className="flex items-center gap-6">
                        <div className="w-16 h-16 bg-indigo-600 rounded-[2rem] flex items-center justify-center shadow-2xl shadow-indigo-500/50">
                          <Compass size={32} />
                        </div>
                        <div>
                          <p className="text-[10px] font-black uppercase tracking-[0.6em] text-indigo-400 mb-1">Strategic AI Module</p>
                          <h3 className="text-5xl font-black tracking-tighter">Strategic Roadmap</h3>
                        </div>
                      </div>
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-16">
                        {currentResult.strategicAdvice.map((advice, i) => (
                          <div key={i} className="flex gap-8 group/item">
                            <div className="flex-shrink-0 w-12 h-12 rounded-2xl border border-white/10 flex items-center justify-center text-sm font-black group-hover/item:bg-indigo-600 group-hover/item:border-indigo-600 transition-all duration-300">{i+1}</div>
                            <p className="text-lg font-bold text-white/70 leading-relaxed group-hover/item:text-white transition-colors">{advice}</p>
                          </div>
                        ))}
                      </div>
                    </div>
                  </section>
                </div>
              ) : (
                /* Empty State */
                <div className="min-h-[600px] border-2 border-dashed border-slate-200 rounded-[5rem] flex flex-col items-center justify-center text-center p-20 animate-in fade-in zoom-in duration-1000">
                  <div className="bg-white p-12 rounded-[2.5rem] shadow-xl border border-slate-100 mb-10 transform hover:scale-105 transition-transform duration-500">
                    <Activity size={80} className="text-indigo-600 opacity-10" />
                  </div>
                  <h3 className="text-5xl font-black text-slate-900 mb-5 uppercase tracking-tighter leading-none">Intelligence Engine Standby</h3>
                  <p className="text-[11px] text-slate-400 font-black max-w-sm uppercase leading-relaxed tracking-[0.4em]">Fulfill the geographic parameters in the floating Recon Panel to initiate the market synthesis pipeline.</p>
                </div>
              )}
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { 
  MapPin, Users, Sparkles, 
  Loader2, ExternalLink, LayoutGrid,
  CircleDollarSign, Building2,
  Globe, Home, Check, AlertCircle,
  Activity, ShoppingBag, Info, Compass, Target,
  History, X, ChevronRight, BarChart3, ArrowRightLeft,
  Trash2, PlusCircle, Maximize2, Menu, GraduationCap, Hotel, Landmark
} from 'lucide-react';
import maplibregl from 'maplibre-gl';
import { StoreInput, AnalysisResult, StoreCategory } from './types';
import { GeminiService } from './services/geminiService';
import { MetricCard } from './components/MetricCard';
import { RevenueChart } from './components/RevenueChart';
import { TrafficLandscape } from './components/TrafficLandscape';

const STORE_CATEGORIES: StoreCategory[] = [
  'Premium Cafe (e.g., Starbucks)',
  'Large Attraction (e.g., Zoo / Theme Park)',
  'Supermarket (e.g., Reliance Fresh / DMart)',
  'Luxury Fashion / Boutique',
  'Pharmacy / Wellness',
  'Fine Dining Restaurant',
  'Workspace / Coworking',
  'Quick Service Restaurant (QSR)'
];

const INITIAL_POS = { lat: 19.0596, lng: 72.8295 };

const App: React.FC = () => {
  const mapContainer = useRef<HTMLDivElement>(null);
  const map = useRef<maplibregl.Map | null>(null);

  // App State
  const [loading, setLoading] = useState(false);
  const [history, setHistory] = useState<AnalysisResult[]>([]);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [compareMode, setCompareMode] = useState(false);
  const [sidebarOpen, setSidebarOpen] = useState(false);

  // Current Analysis State
  const [input, setInput] = useState<StoreInput>({
    location: 'Bandra West, Mumbai',
    coordinates: { ...INITIAL_POS },
    category: 'Premium Cafe (e.g., Starbucks)',
    length: 40,
    breadth: 50,
    floors: 1,
    heightPerFloor: 12,
    targetSegment: ['Gen-Z Trendsetters', 'Young Professionals']
  });

  const [currentResult, setCurrentResult] = useState<AnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  // Helper to generate random clusters around a point
  const generateClusterPoints = (center: { lat: number; lng: number }, count: number, radiusKm: number) => {
    return Array.from({ length: count }).map(() => {
      const r = (Math.random() * radiusKm) / 111.32; // Rough conversion km to degrees
      const theta = Math.random() * 2 * Math.PI;
      return {
        type: 'Feature',
        geometry: {
          type: 'Point',
          coordinates: [
            center.lng + r * Math.cos(theta) / Math.cos(center.lat * Math.PI / 180),
            center.lat + r * Math.sin(theta)
          ]
        },
        properties: {}
      };
    });
  };

  // Update Map POI Visuals
  const updateMapVisuals = (result: AnalysisResult) => {
    if (!map.current) return;

    const center = INITIAL_POS; // In a production app, use geocoded result.coordinates
    const pois = result.metrics.nearbyPOIs;

    // Clear previous POI sources/layers
    ['schools', 'hotels', 'worship'].forEach(id => {
      if (map.current?.getLayer(id)) map.current.removeLayer(id);
      if (map.current?.getSource(id)) map.current.removeSource(id);
    });

    // Add Schools (Cyan)
    map.current.addSource('schools', {
      type: 'geojson',
      data: {
        type: 'FeatureCollection',
        features: generateClusterPoints(center, pois.schools + pois.premiumSchools, 1.2)
      } as any
    });

    map.current.addLayer({
      id: 'schools',
      type: 'circle',
      source: 'schools',
      paint: {
        'circle-radius': ['interpolate', ['linear'], ['zoom'], 12, 4, 16, 8],
        'circle-color': '#06b6d4',
        'circle-opacity': 0.6,
        'circle-stroke-width': 2,
        'circle-stroke-color': '#ffffff'
      }
    });

    // Add Hotels (Gold)
    const hotelCount = pois.hotels.luxury + pois.hotels.midTier + pois.hotels.budget;
    map.current.addSource('hotels', {
      type: 'geojson',
      data: {
        type: 'FeatureCollection',
        features: generateClusterPoints(center, hotelCount, 1.5)
      } as any
    });

    map.current.addLayer({
      id: 'hotels',
      type: 'circle',
      source: 'hotels',
      paint: {
        'circle-radius': ['interpolate', ['linear'], ['zoom'], 12, 5, 16, 10],
        'circle-color': '#f59e0b',
        'circle-opacity': 0.7,
        'circle-stroke-width': 2,
        'circle-stroke-color': '#ffffff'
      }
    });

    // Add Places of Worship (Violet)
    map.current.addSource('worship', {
      type: 'geojson',
      data: {
        type: 'FeatureCollection',
        features: generateClusterPoints(center, pois.placesOfWorship, 1.0)
      } as any
    });

    map.current.addLayer({
      id: 'worship',
      type: 'circle',
      source: 'worship',
      paint: {
        'circle-radius': ['interpolate', ['linear'], ['zoom'], 12, 3, 16, 6],
        'circle-color': '#8b5cf6',
        'circle-opacity': 0.5,
        'circle-stroke-width': 1,
        'circle-stroke-color': '#ffffff'
      }
    });

    map.current.flyTo({ center: [center.lng, center.lat], zoom: 15.5, pitch: 45, essential: true });
  };

  // Initialize Map
  useEffect(() => {
    if (!mapContainer.current) return;

    (maplibregl as any).workerCount = 0;

    let mapInstance: maplibregl.Map | null = null;

    try {
      mapInstance = new maplibregl.Map({
        container: mapContainer.current!,
        style: 'https://tiles.basemaps.cartocdn.com/gl/dark-matter-gl-style/style.json',
        center: [INITIAL_POS.lng, INITIAL_POS.lat],
        zoom: 14,
        pitch: 60,
        bearing: -20,
        attributionControl: false,
        failIfMajorPerformanceCaveat: false
      });

      mapInstance.on('load', () => {
        map.current = mapInstance;
      });

      mapInstance.on('error', (e) => {
        console.warn('Map Encountered an Error:', e);
      });

    } catch (err) {
      console.error('Fatal MapLibre Init Error:', err);
    }

    return () => {
      if (mapInstance) mapInstance.remove();
    };
  }, []);

  useEffect(() => {
    if (map.current && currentResult && map.current.isStyleLoaded()) {
      updateMapVisuals(currentResult);
    }
  }, [currentResult]);

  const handleAnalyze = async () => {
    setLoading(true);
    setError(null);
    try {
      const data = await GeminiService.analyzeMarket(input);
      const newResult: AnalysisResult = {
        ...data,
        id: crypto.randomUUID(),
        timestamp: Date.now(),
        originalInput: { ...input }
      };

      setHistory(prev => [newResult, ...prev]);
      setCurrentResult(newResult);
      setCompareMode(false);
    } catch (err: any) {
      setError(err.message || 'Analysis failed.');
    } finally {
      setLoading(false);
    }
  };

  const toggleSelectForCompare = (id: string) => {
    setSelectedIds(prev => 
      prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]
    );
  };

  const removeFromHistory = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setHistory(prev => prev.filter(item => item.id !== id));
    setSelectedIds(prev => prev.filter(i => i !== id));
    if (currentResult?.id === id) setCurrentResult(null);
  };

  const comparisonData = useMemo(() => {
    return history.filter(item => selectedIds.includes(item.id));
  }, [history, selectedIds]);

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('en-IN', {
      style: 'currency', currency: 'INR', maximumFractionDigits: 0
    }).format(val);
  };

  return (
    <div className="flex flex-col h-screen bg-[#f8fafc] text-slate-900 overflow-hidden relative">
      {/* Top Header */}
      <header className="h-16 bg-white/80 backdrop-blur-md border-b border-slate-200 px-6 flex items-center justify-between z-[60] flex-shrink-0">
        <div className="flex items-center gap-4">
          <button 
            onClick={() => setSidebarOpen(true)}
            className="p-2 hover:bg-slate-100 rounded-lg text-slate-500 transition-colors"
            title="Open History"
          >
            <Menu size={20} />
          </button>
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-1.5 rounded-lg text-white shadow-lg shadow-indigo-100">
              <Sparkles size={18} />
            </div>
            <h1 className="font-black text-slate-900 tracking-tight text-lg">LocalityMind</h1>
          </div>
        </div>

        <div className="flex items-center gap-3">
          {selectedIds.length > 0 && (
            <button 
              onClick={() => setCompareMode(!compareMode)}
              className={`flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-bold transition-all ${compareMode ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-200' : 'bg-indigo-50 text-indigo-700 hover:bg-indigo-100'}`}
            >
              <ArrowRightLeft size={16} />
              {compareMode ? 'Exit Comparison' : `Compare (${selectedIds.length})`}
            </button>
          )}
          <button 
            onClick={handleAnalyze}
            disabled={loading}
            className="bg-slate-900 text-white px-5 py-2 rounded-xl text-sm font-bold flex items-center gap-2 hover:bg-slate-800 transition-all disabled:opacity-50 shadow-lg shadow-slate-200"
          >
            {loading ? <Loader2 size={16} className="animate-spin" /> : <Target size={16} />}
            {loading ? 'Synthesizing...' : 'Analyze Market'}
          </button>
        </div>
      </header>

      {/* Sliding Sidebar Overlay */}
      {sidebarOpen && (
        <div 
          className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-[70] transition-opacity"
          onClick={() => setSidebarOpen(false)}
        />
      )}
      <aside className={`fixed top-0 left-0 h-full w-80 bg-white shadow-2xl z-[80] transform transition-transform duration-300 ease-in-out ${sidebarOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="flex flex-col h-full">
          <div className="p-6 border-b border-slate-100 flex items-center justify-between">
            <span className="text-xs font-black uppercase tracking-widest text-slate-400 flex items-center gap-2">
               <History size={14} /> Analysis History
            </span>
            <button onClick={() => setSidebarOpen(false)} className="p-1.5 hover:bg-slate-100 rounded-lg text-slate-400">
              <X size={18} />
            </button>
          </div>
          <div className="flex-1 overflow-y-auto custom-scrollbar p-4 space-y-3">
            {history.length === 0 ? (
              <div className="p-12 text-center text-slate-400 space-y-3 mt-10">
                <Info size={32} className="mx-auto opacity-20" />
                <p className="text-xs font-black uppercase tracking-widest leading-relaxed">System history is currently empty</p>
              </div>
            ) : (
              history.map(item => (
                <div 
                  key={item.id}
                  onClick={() => { setCurrentResult(item); setCompareMode(false); setSidebarOpen(false); }}
                  className={`group relative p-4 rounded-2xl cursor-pointer transition-all border ${currentResult?.id === item.id ? 'bg-indigo-50/50 border-indigo-200 shadow-sm' : 'border-slate-100 hover:bg-slate-50 hover:border-slate-200'}`}
                >
                  <div className="flex justify-between items-start mb-2">
                    <h4 className="text-sm font-black text-slate-900 truncate pr-6 leading-tight">{item.localityName}</h4>
                    <button onClick={(e) => removeFromHistory(item.id, e)} className="opacity-0 group-hover:opacity-100 p-1 hover:text-red-500 text-slate-300 transition-opacity">
                      <Trash2 size={12} />
                    </button>
                  </div>
                  <p className="text-[9px] font-black text-slate-400 uppercase tracking-tighter truncate">{item.originalInput.category}</p>
                  <div className="mt-3 flex items-center justify-between">
                    <span className="text-xs font-black text-indigo-600">{formatCurrency(item.revenueProjections.monthly)}/mo</span>
