import React, { useMemo } from 'react';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import { Clock, TrendingUp } from 'lucide-react';

interface TrafficLandscapeProps {
  data: { hour: number; traffic: number }[];
}

export const TrafficLandscape: React.FC<TrafficLandscapeProps> = ({ data }) => {
  const formatHour = (hour: number) => {
    if (hour === 0) return '12 AM';
    if (hour < 12) return `${hour} AM`;
    if (hour === 12) return '12 PM';
    return `${hour - 12} PM`;
  };

  const peakHours = useMemo(() => {
    const sorted = [...data].sort((a, b) => b.traffic - a.traffic);
    return sorted.slice(0, 2); // Get top 2 peaks
  }, [data]);

  const maxTraffic = useMemo(() => Math.max(...data.map(d => d.traffic)), [data]);

  const CustomTooltip = ({ active, payload, label }: any) => {
    if (active && payload && payload.length) {
      return (
        <div className="bg-slate-900 border border-slate-700 p-4 rounded-2xl shadow-2xl">
          <p className="text-[10px] font-black uppercase tracking-widest text-indigo-400 mb-1">{formatHour(label)}</p>
          <p className="text-xl font-black text-white">{payload[0].value.toLocaleString()}</p>
          <p className="text-[8px] font-bold text-slate-400 uppercase tracking-wider">Estimated Visitors</p>
        </div>
      );
    }
    return null;
  };

  return (
    <div className="bg-white p-12 rounded-[4rem] shadow-xl border border-slate-100 overflow-hidden relative flex flex-col h-full">
      <div className="flex items-center justify-between mb-8">
        <div>
          <h3 className="text-xs font-black uppercase tracking-[0.4em] text-slate-400 mb-2">Traffic Landscape</h3>
          <p className="text-slate-500 text-sm font-semibold">24-hour pedestrian & vehicle flow distribution</p>
        </div>
        <div className="flex gap-2">
          {peakHours.map((peak, idx) => (
            <div key={idx} className="px-4 py-1.5 bg-indigo-50 rounded-full text-[9px] font-black text-indigo-700 uppercase tracking-widest flex items-center gap-2">
              <TrendingUp size={12} /> {formatHour(peak.hour)}
            </div>
          ))}
        </div>
      </div>

      <div className="h-[250px] w-full mt-4">
        <ResponsiveContainer width="100%" height="100%">
          <AreaChart data={data} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
            <defs>
              <linearGradient id="colorTraffic" x1="0" y1="0" x2="0" y2="1">
                <stop offset="5%" stopColor="#6366f1" stopOpacity={0.8}/>
                <stop offset="95%" stopColor="#6366f1" stopOpacity={0.1}/>
              </linearGradient>
            </defs>
            <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
            <XAxis 
              dataKey="hour" 
              tickFormatter={formatHour}
              axisLine={false}
              tickLine={false}
              tick={{ fill: '#94a3b8', fontSize: 9, fontWeight: 900 }}
              interval={3}
            />
            <YAxis hide />
            <Tooltip content={<CustomTooltip />} />
            <Area 
              type="monotone" 
              dataKey="traffic" 
              stroke="#4f46e5" 
              strokeWidth={4}
              fillOpacity={1} 
              fill="url(#colorTraffic)" 
              animationDuration={2000}
            />
          </AreaChart>
        </ResponsiveContainer>
      </div>

      {/* Heatmap Timeline (YouTube Style Peak Indicators) */}
      <div className="mt-8 space-y-4">
        <div className="flex items-center justify-between">
          <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400 flex items-center gap-2">
            <Clock size={12} className="text-indigo-500" /> Peak Intensity Timeline
          </p>
          <span className="text-[10px] font-black text-slate-400">00:00 — 23:59</span>
        </div>

        <div className="relative h-4 w-full bg-slate-50 rounded-full overflow-hidden flex shadow-inner">
          {data.map((item, idx) => {
            const intensity = item.traffic / maxTraffic;
            return (
              <div 
                key={idx} 
                className="flex-1 transition-all duration-1000"
                style={{ 
                  backgroundColor: '#6366f1',
                  opacity: Math.max(0.1, intensity)
                }}
                title={`${formatHour(item.hour)}: ${item.traffic} traffic`}
              />
            );
          })}
        </div>

        {/* Peak Numerical Callouts */}
        <div className="grid grid-cols-2 gap-4 mt-6">
          {peakHours.map((peak, idx) => (
            <div key={idx} className="p-4 bg-slate-50 rounded-3xl border border-slate-100 flex items-center justify-between group hover:bg-white hover:shadow-lg transition-all">
              <div className="space-y-1">
                <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest">
                  {idx === 0 ? 'Primary Peak' : 'Secondary Peak'}
                </p>
                <p className="text-xl font-black text-slate-900 leading-none">{formatHour(peak.hour)}</p>
              </div>
              <div className="text-right">
                <p className="text-lg font-black text-indigo-600">{(peak.traffic / 1000).toFixed(1)}k</p>
                <p className="text-[8px] font-bold text-slate-400 uppercase">Hourly Est.</p>
              </div>
            </div>
          ))}
        </div>
      </div>

      <div className="flex justify-between mt-6 px-2">
        <span className="text-[8px] font-black text-slate-400 uppercase tracking-widest opacity-50">Late Night</span>
        <span className="text-[8px] font-black text-slate-400 uppercase tracking-widest opacity-50 text-center">Standard Business Hours</span>
        <span className="text-[8px] font-black text-slate-400 uppercase tracking-widest opacity-50 text-right">Night Life</span>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { 
  MapPin, Users, Sparkles, 
  Loader2, ExternalLink, LayoutGrid,
  CircleDollarSign, Building2,
  Globe, Home, Check, AlertCircle,
  Activity, ShoppingBag, Info, Compass, Target,
  History, X, ChevronRight, BarChart3, ArrowRightLeft,
  Trash2, PlusCircle, Maximize2, Menu, GraduationCap, Hotel, Landmark, Navigation
} from 'lucide-react';
import maplibregl from 'maplibre-gl';
import { StoreInput, AnalysisResult, StoreCategory } from './types';
import { GeminiService } from './services/geminiService';
import { MetricCard } from './components/MetricCard';
import { RevenueChart } from './components/RevenueChart';
import { TrafficLandscape } from './components/TrafficLandscape';

const STORE_CATEGORIES: StoreCategory[] = [
  'Premium Cafe (e.g., Starbucks)',
  'Large Attraction (e.g., Zoo / Theme Park)',
  'Supermarket (e.g., Reliance Fresh / DMart)',
  'Luxury Fashion / Boutique',
  'Pharmacy / Wellness',
  'Fine Dining Restaurant',
  'Workspace / Coworking',
  'Quick Service Restaurant (QSR)'
];

const POPULAR_LOCALITIES = [
  'Bandra West, Mumbai',
  'Indiranagar, Bangalore',
  'Hauz Khas, Delhi',
  'Koramangala, Bangalore',
  'Juhu, Mumbai',
  'Powai, Mumbai',
  'Cyber Hub, Gurgaon',
  'Connaught Place, Delhi',
  'Park Street, Kolkata',
  'Banjara Hills, Hyderabad',
  'Koregaon Park, Pune',
  'Anna Nagar, Chennai',
  'MG Road, Bangalore',
  'Colaba, Mumbai',
  'Salt Lake, Kolkata'
];

const INITIAL_POS = { lat: 19.0596, lng: 72.8295 };

const App: React.FC = () => {
  const mapContainer = useRef<HTMLDivElement>(null);
  const map = useRef<maplibregl.Map | null>(null);

  // App State
  const [loading, setLoading] = useState(false);
  const [history, setHistory] = useState<AnalysisResult[]>([]);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [compareMode, setCompareMode] = useState(false);
  const [sidebarOpen, setSidebarOpen] = useState(false);

  // Locality Suggestions State
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);

  // Current Analysis State
  const [input, setInput] = useState<StoreInput>({
    location: 'Bandra West, Mumbai',
    coordinates: { ...INITIAL_POS },
    category: 'Premium Cafe (e.g., Starbucks)',
    length: 40,
    breadth: 50,
    floors: 1,
    heightPerFloor: 12,
    targetSegment: ['Gen-Z Trendsetters', 'Young Professionals']
  });

  const [currentResult, setCurrentResult] = useState<AnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  // Helper to generate random clusters around a point
  const generateClusterPoints = (center: { lat: number; lng: number }, count: number, radiusKm: number) => {
    return Array.from({ length: count }).map(() => {
      const r = (Math.random() * radiusKm) / 111.32; // Rough conversion km to degrees
      const theta = Math.random() * 2 * Math.PI;
      return {
        type: 'Feature',
        geometry: {
          type: 'Point',
          coordinates: [
            center.lng + r * Math.cos(theta) / Math.cos(center.lat * Math.PI / 180),
            center.lat + r * Math.sin(theta)
          ]
        },
        properties: {}
      };
    });
  };

  // Update Map POI Visuals
  const updateMapVisuals = (result: AnalysisResult) => {
    if (!map.current) return;

    const center = INITIAL_POS; 
    const pois = result.metrics.nearbyPOIs;

    ['schools', 'hotels', 'worship'].forEach(id => {
      if (map.current?.getLayer(id)) map.current.removeLayer(id);
      if (map.current?.getSource(id)) map.current.removeSource(id);
    });

    map.current.addSource('schools', {
      type: 'geojson',
      data: {
        type: 'FeatureCollection',
        features: generateClusterPoints(center, pois.schools + pois.premiumSchools, 1.2)
      } as any
    });

    map.current.addLayer({
      id: 'schools',
      type: 'circle',
      source: 'schools',
      paint: {
        'circle-radius': ['interpolate', ['linear'], ['zoom'], 12, 4, 16, 8],
        'circle-color': '#06b6d4',
        'circle-opacity': 0.6,
        'circle-stroke-width': 2,
        'circle-stroke-color': '#ffffff'
      }
    });

    const hotelCount = pois.hotels.luxury + pois.hotels.midTier + pois.hotels.budget;
    map.current.addSource('hotels', {
      type: 'geojson',
      data: {
        type: 'FeatureCollection',
        features: generateClusterPoints(center, hotelCount, 1.5)
      } as any
    });

    map.current.addLayer({
      id: 'hotels',
      type: 'circle',
      source: 'hotels',
      paint: {
        'circle-radius': ['interpolate', ['linear'], ['zoom'], 12, 5, 16, 10],
        'circle-color': '#f59e0b',
        'circle-opacity': 0.7,
        'circle-stroke-width': 2,
        'circle-stroke-color': '#ffffff'
      }
    });

    map.current.addSource('worship', {
      type: 'geojson',
      data: {
        type: 'FeatureCollection',
        features: generateClusterPoints(center, pois.placesOfWorship, 1.0)
      } as any
    });

    map.current.addLayer({
      id: 'worship',
      type: 'circle',
      source: 'worship',
      paint: {
        'circle-radius': ['interpolate', ['linear'], ['zoom'], 12, 3, 16, 6],
        'circle-color': '#8b5cf6',
        'circle-opacity': 0.5,
        'circle-stroke-width': 1,
        'circle-stroke-color': '#ffffff'
      }
    });

    map.current.flyTo({ center: [center.lng, center.lat], zoom: 15.5, pitch: 45, essential: true });
  };

  useEffect(() => {
    if (!mapContainer.current) return;
    (maplibregl as any).workerCount = 0;
    let mapInstance: maplibregl.Map | null = null;
    try {
      mapInstance = new maplibregl.Map({
        container: mapContainer.current!,
        style: 'https://tiles.basemaps.cartocdn.com/gl/dark-matter-gl-style/style.json',
        center: [INITIAL_POS.lng, INITIAL_POS.lat],
        zoom: 14,
        pitch: 60,
        bearing: -20,
        attributionControl: false,
        failIfMajorPerformanceCaveat: false
      });
      mapInstance.on('load', () => {
        map.current = mapInstance;
      });
      mapInstance.on('error', (e) => {
        console.warn('Map Encountered an Error:', e);
      });
    } catch (err) {
      console.error('Fatal MapLibre Init Error:', err);
    }
    return () => {
      if (mapInstance) mapInstance.remove();
    };
  }, []);

  useEffect(() => {
    if (map.current && currentResult && map.current.isStyleLoaded()) {
      updateMapVisuals(currentResult);
    }
  }, [currentResult]);

  const handleLocalityChange = (val: string) => {
    setInput(prev => ({ ...prev, location: val }));
    if (val.trim().length > 0) {
      const filtered = POPULAR_LOCALITIES.filter(l => 
        l.toLowerCase().includes(val.toLowerCase())
      );
      setSuggestions(filtered);
      setShowSuggestions(filtered.length > 0);
    } else {
      setShowSuggestions(false);
    }
  };

  const handleSelectSuggestion = (loc: string) => {
    setInput(prev => ({ ...prev, location: loc }));
    setShowSuggestions(false);
  };

  const handleUseMyLocation = () => {
    if (!navigator.geolocation) {
      setError("Geolocation is not supported by your browser.");
      return;
    }
    navigator.geolocation.getCurrentPosition((pos) => {
      const { latitude, longitude } = pos.coords;
      setInput(prev => ({ 
        ...prev, 
        location: `Detected Site (${latitude.toFixed(4)}, ${longitude.toFixed(4)})`,
        coordinates: { lat: latitude, lng: longitude }
      }));
      if (map.current) {
        map.current.flyTo({ center: [longitude, latitude], zoom: 16 });
      }
    }, (err) => {
      setError("Failed to acquire location. Please check permissions.");
    });
  };

  const handleAnalyze = async () => {
    setLoading(true);
    setError(null);
    setShowSuggestions(false);
    try {
      const data = await GeminiService.analyzeMarket(input);
      const newResult: AnalysisResult = {
        ...data,
        id: crypto.randomUUID(),
        timestamp: Date.now(),
        originalInput: { ...input }
      };

      setHistory(prev => [newResult, ...prev]);
      setCurrentResult(newResult);
      setCompareMode(false);
    } catch (err: any) {
      setError(err.message || 'Analysis failed.');
    } finally {
      setLoading(false);
    }
  };

  const toggleSelectForCompare = (id: string) => {
    setSelectedIds(prev => 
      prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]
    );
  };

  const removeFromHistory = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setHistory(prev => prev.filter(item => item.id !== id));
    setSelectedIds(prev => prev.filter(i => i !== id));
    if (currentResult?.id === id) setCurrentResult(null);
  };

  const comparisonData = useMemo(() => {
    return history.filter(item => selectedIds.includes(item.id));
  }, [history, selectedIds]);

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('en-IN', {
      style: 'currency', currency: 'INR', maximumFractionDigits: 0
    }).format(val);
  };

  return (
    <div className="flex flex-col h-screen bg-[#f8fafc] text-slate-900 overflow-hidden relative" onClick={() => setShowSuggestions(false)}>
      {/* Top Header */}
      <header className="h-16 bg-white/80 backdrop-blur-md border-b border-slate-200 px-6 flex items-center justify-between z-[60] flex-shrink-0">
        <div className="flex items-center gap-4">
          <button 
            onClick={(e) => { e.stopPropagation(); setSidebarOpen(true); }}
            className="p-2 hover:bg-slate-100 rounded-lg text-slate-500 transition-colors"
            title="Open History"
          >
            <Menu size={20} />
          </button>
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-1.5 rounded-lg text-white shadow-lg shadow-indigo-100">
              <Sparkles size={18} />
            </div>
            <h1 className="font-black text-slate-900 tracking-tight text-lg">LocalityMind</h1>
          </div>
        </div>

        <div className="flex items-center gap-3">
          {selectedIds.length > 0 && (
            <button 
              onClick={() => setCompareMode(!compareMode)}
              className={`flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-bold transition-all ${compareMode ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-200' : 'bg-indigo-50 text-indigo-700 hover:bg-indigo-100'}`}
            >
              <ArrowRightLeft size={16} />
              {compareMode ? 'Exit Comparison' : `Compare (${selectedIds.length})`}
            </button>
          )}
          <button 
            onClick={handleAnalyze}
            disabled={loading}
            className="bg-slate-900 text-white px-5 py-2 rounded-xl text-sm font-bold flex items-center gap-2 hover:bg-slate-800 transition-all disabled:opacity-50 shadow-lg shadow-slate-200"
          >
            {loading ? <Loader2 size={16} className="animate-spin" /> : <Target size={16} />}
            {loading ? 'Synthesizing...' : 'Analyze Market'}
          </button>
        </div>
      </header>

      {/* Sliding Sidebar Overlay */}
      {sidebarOpen && (
        <div 
          className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-[70] transition-opacity"
          onClick={() => setSidebarOpen(false)}
        />
      )}
      <aside className={`fixed top-0 left-0 h-full w-80 bg-white shadow-2xl z-[80] transform transition-transform duration-300 ease-in-out ${sidebarOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="flex flex-col h-full">
          <div className="p-6 border-b border-slate-100 flex items-center justify-between">
            <span className="text-xs font-black uppercase tracking-widest text-slate-400 flex items-center gap-2">
               <History size={14} /> Analysis History
            </span>
            <button onClick={() => setSidebarOpen(false)} className="p-1.5 hover:bg-slate-100 rounded-lg text-slate-400">
              <X size={18} />
            </button>
          </div>
          <div className="flex-1 overflow-y-auto custom-scrollbar p-4 space-y-3">
            {history.length === 0 ? (
              <div className="p-12 text-center text-slate-400 space-y-3 mt-10">
                <Info size={32} className="mx-auto opacity-20" />
                <p className="text-xs font-black uppercase tracking-widest leading-relaxed">System history is currently empty</p>
              </div>
            ) : (
              history.map(item => (
                <div 
                  key={item.id}
                  onClick={() => { setCurrentResult(item); setCompareMode(false); setSidebarOpen(false); }}
                  className={`group relative p-4 rounded-2xl cursor-pointer transition-all border ${currentResult?.id === item.id ? 'bg-indigo-50/50 border-indigo-200 shadow-sm' : 'border-slate-100 hover:bg-slate-50 hover:border-slate-200'}`}
                >
                  <div className="flex justify-between items-start mb-2">
                    <h4 className="text-sm font-black text-slate-900 truncate pr-6 leading-tight">{item.localityName}</h4>
                    <button onClick={(e) => removeFromHistory(item.id, e)} className="opacity-0 group-hover:opacity-100 p-1 hover:text-red-500 text-slate-300 transition-opacity">
                      <Trash2 size={12} />
                    </button>
                  </div>
                  <p className="text-[9px] font-black text-slate-400 uppercase tracking-tighter truncate">{item.originalInput.category}</p>
                  <div className="mt-3 flex items-center justify-between">
                    <span className="text-xs font-black text-indigo-600">{formatCurrency(item.revenueProjections.monthly)}/mo</span>
                    <button 
                      onClick={(e) => { e.stopPropagation(); toggleSelectForCompare(item.id); }}
                      className={`p-1.5 rounded-lg transition-all ${selectedIds.includes(item.id) ? 'bg-indigo-600 text-white' : 'text-slate-300 hover:text-indigo-600 bg-slate-100'}`}
                      title="Select for Comparison"
                    >
                      <PlusCircle size={14} />
                    </button>
                  </div>
                </div>
              ))
            )}
          </div>
        </div>
      </aside>

      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto custom-scrollbar bg-[#f8fafc]">
        {compareMode ? (
          <div className="p-8 lg:p-12 animate-in fade-in slide-in-from-bottom-4 duration-500 max-w-[1600px] mx-auto">
            <div className="flex items-center justify-between mb-10">
              <div>
                <h2 className="text-4xl font-black text-slate-900 tracking-tighter">Market Benchmarking</h2>
                <p className="text-sm text-slate-500 font-medium">Side-by-side performance synthesis of {comparisonData.length} localities.</p>
              </div>
              <button onClick={() => setCompareMode(false)} className="p-4 hover:bg-slate-200 rounded-full text-slate-400 transition-colors"><X size={28}/></button>
            </div>
            <div className="bg-white rounded-[3rem] border border-slate-200 shadow-sm overflow-hidden overflow-x-auto custom-scrollbar">
              <table className="w-full text-left border-collapse min-w-[1200px]">
                <thead>
                  <tr className="bg-slate-50/80 backdrop-blur">
                    <th className="p-10 text-xs font-black uppercase text-slate-400 border-b border-slate-100 w-[300px] tracking-widest">Core Business KPI</th>
                    {comparisonData.map(item => (
                      <th key={item.id} className="p-10 text-lg font-black text-slate-900 border-b border-slate-100">
                        {item.localityName}
                      </th>
                    ))}
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  <tr className="hover:bg-indigo-50/20 transition-colors">
                    <td className="p-10 text-sm font-bold text-slate-500 uppercase tracking-widest">Monthly Est. Revenue</td>
                    {comparisonData.map(item => (
                      <td key={item.id} className="p-10 text-2xl font-black text-indigo-600 leading-none">{formatCurrency(item.revenueProjections.monthly)}</td>
                    ))}
                  </tr>
                  <tr className="hover:bg-slate-50/50 transition-colors">
                    <td className="p-10 text-sm font-bold text-slate-500 uppercase tracking-widest">Annual Gross Forecast</td>
                    {comparisonData.map(item => (
                      <td key={item.id} className="p-10 text-xl font-bold text-slate-900">{formatCurrency(item.revenueProjections.yearly)}</td>
                    ))}
                  </tr>
                  <tr className="hover:bg-slate-50/50 transition-colors">
                    <td className="p-10 text-sm font-bold text-slate-500 uppercase tracking-widest">Daily Footfall Stream</td>
                    {comparisonData.map(item => (
                      <td key={item.id} className="p-10 text-xl font-bold text-slate-900">{item.metrics.footfallEstimate.daily.toLocaleString()}</td>
                    ))}
                  </tr>
                  <tr className="hover:bg-slate-50/50 transition-colors">
                    <td className="p-10 text-sm font-bold text-slate-500 uppercase tracking-widest">PCI Economic Proxy</td>
                    {comparisonData.map(item => (
                      <td key={item.id} className="p-10 text-xl font-bold text-slate-900">₹{item.demographics.perCapitaIncome.toLocaleString()}</td>
                    ))}
                  </tr>
                  <tr className="hover:bg-slate-50/50 transition-colors">
                    <td className="p-10 text-sm font-bold text-slate-500 uppercase tracking-widest">Format Footprint</td>
                    {comparisonData.map(item => (
                      <td key={item.id} className="p-10 text-xl font-bold text-slate-900">{item.originalInput.length * item.originalInput.breadth} sq ft</td>
                    ))}
                  </tr>
                  <tr className="hover:bg-slate-50/50 transition-colors">
                    <td className="p-10 text-sm font-bold text-slate-500 uppercase tracking-widest">Annual Yield Density</td>
                    {comparisonData.map(item => {
                      const area = item.originalInput.length * item.originalInput.breadth;
                      const density = item.revenueProjections.yearly / area;
                      return <td key={item.id} className="p-10 text-xl font-black text-slate-600">₹{Math.round(density).toLocaleString()} / sqft</td>;
                    })}
                  </tr>
                  <tr className="hover:bg-slate-50/50 transition-colors">
                    <td className="p-10 text-sm font-bold text-slate-500 uppercase tracking-widest">Resident Catchment</td>
                    {comparisonData.map(item => (
                      <td key={item.id} className="p-10">
                        <span className="px-5 py-2 bg-slate-100 rounded-full text-xs font-black uppercase text-slate-600 tracking-[0.2em]">
                          {item.demographics.residentType}
                        </span>
                      </td>
                    ))}
                  </tr>
                </tbody>
              </table>
            </div>
          </div>
        ) : (
          <div className="flex flex-col animate-in fade-in duration-700">
            <section className="relative w-full h-[85vh] bg-slate-900 border-b border-slate-200 overflow-hidden group">
              <div ref={mapContainer} className="w-full h-full" />
              <div className="absolute top-8 right-8 pointer-events-none z-10 space-y-4">
                <div className="bg-slate-950/70 backdrop-blur-md px-5 py-2.5 rounded-2xl border border-slate-700/50 text-[10px] font-black text-white uppercase tracking-[0.3em] flex items-center gap-3 shadow-2xl">
                  <div className="w-2 h-2 rounded-full bg-indigo-500 animate-pulse" /> FUSED SPATIAL LAYER
                </div>
                {currentResult && (
                  <div className="bg-white/90 backdrop-blur-xl px-6 py-4 rounded-[2rem] border border-white text-slate-900 shadow-2xl animate-in slide-in-from-right-8 duration-700">
                    <p className="text-[10px] font-black uppercase text-indigo-500 tracking-widest mb-1.5">Selected Node</p>
                    <p className="text-xl font-black tracking-tight">{currentResult.localityName}</p>
                    <div className="mt-2 flex items-center gap-2 text-[10px] font-bold text-slate-400">
                       <MapPin size={12} /> {INITIAL_POS.lat.toFixed(4)}, {INITIAL_POS.lng.toFixed(4)}
                    </div>
                  </div>
                )}
                {currentResult && (
                  <div className="bg-slate-950/80 backdrop-blur-xl p-4 rounded-2xl border border-white/10 text-white shadow-2xl animate-in slide-in-from-right-8 duration-1000">
                    <p className="text-[8px] font-black uppercase tracking-[0.3em] text-white/40 mb-3">Live POI Density</p>
                    <div className="space-y-2">
                       <div className="flex items-center gap-3">
                          <div className="w-2 h-2 rounded-full bg-cyan-500" />
                          <span className="text-[10px] font-black uppercase tracking-wider">Schools ({currentResult.metrics.nearbyPOIs.schools + currentResult.metrics.nearbyPOIs.premiumSchools})</span>
                       </div>
                       <div className="flex items-center gap-3">
                          <div className="w-2 h-2 rounded-full bg-amber-500" />
                          <span className="text-[10px] font-black uppercase tracking-wider">Hotels ({currentResult.metrics.nearbyPOIs.hotels.luxury + currentResult.metrics.nearbyPOIs.hotels.midTier + currentResult.metrics.nearbyPOIs.hotels.budget})</span>
                       </div>
                       <div className="flex items-center gap-3">
                          <div className="w-2 h-2 rounded-full bg-violet-500" />
                          <span className="text-[10px] font-black uppercase tracking-wider">Culture ({currentResult.metrics.nearbyPOIs.placesOfWorship})</span>
                       </div>
                    </div>
                  </div>
