import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { StoreInput, AnalysisResult } from "../types";

export class GeminiService {
  private static getAi() {
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  static async analyzeMarket(input: StoreInput): Promise<AnalysisResult> {
    const ai = this.getAi();
    const storeFootprint = input.length * input.breadth;
    const totalArea = storeFootprint * input.floors;

    // Construct extra detail string for prompt context
    const extraContext = input.extraDetails 
      ? Object.entries(input.extraDetails).map(([k, v]) => `${k}: ${v}`).join(', ')
      : 'Standard operation';

    // 1. Spatial Reconnaissance
    const mapsResponse = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Perform a site reconnaissance for ${input.location}. 
      Identify:
      - Proximity to high-density hubs (transit, education, commerce).
      - Competitor density for a ${input.category} with ${input.floors} levels.
      - Cultural landscape (POIs like temples, malls, parks).
      - Socioeconomic context of surrounding neighborhoods.`,
      config: {
        tools: [{ googleSearch: {} }],
      },
    });

    const mapsSources = (mapsResponse.candidates?.[0]?.groundingMetadata?.groundingChunks || [])
      .filter(chunk => chunk.web || chunk.maps)
      .map(chunk => ({
        title: (chunk.web?.title || chunk.maps?.title || 'Map Node'),
        uri: (chunk.web?.uri || chunk.maps?.uri || '')
      }));

    // 2. High-Fidelity Synthesis
    const proResponse = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: `Generate a high-precision market feasibility report.
      LOCATION: ${input.location}
      BUSINESS: ${input.category}
      SITE ARCHITECTURE: ${input.floors} levels, ${totalArea} total sq ft (${storeFootprint} footprint).
      STRATEGIC VARIABLES: ${extraContext}

      CONTEXTUAL DATA:
      ${mapsResponse.text}

      CRITICAL REVENUE LOGIC:
      - Calculate "Efficiency per Level": Multi-level stores often have diminishing footfall on higher floors unless destination-driven.
      - Revenue should scale based on ${input.category} norms for a ${totalArea} sq ft space in this specific socioeconomic tier.
      - Pedestrian footfall distribution must reflect local peak hours identified in the spatial recon.

      Respond in JSON:
      {
        "localityName": string,
        "demographics": { "perCapitaIncome": number, "socioeconomicTier": "High" | "Upper-Mid" | "Mid" | "Lower-Mid" | "Economic", "dominantCarTypes": string[], "populationDensity": string, "residentType": "Residential" | "Corporate" | "Tourist" | "Mixed" },
        "metrics": { 
          "footfallEstimate": { 
            "hourly": number, "daily": number, "peakTimes": string[],
            "hourlyDistribution": [ { "hour": number, "traffic": number } ]
          },
          "nearbyPOIs": { "schools": number, "premiumSchools": number, "placesOfWorship": number, "hotels": { "luxury": number, "midTier": number, "budget": number } },
          "tourismProfile": string,
          "storeCompetition": [ { "type": string, "avgPricePoint": string, "count": number, "description": string } ]
        },
        "revenueProjections": { "monthly": number, "quarterly": number, "yearly": number, "currency": "INR" },
        "strategicAdvice": string[]
      }`,
      config: {
        thinkingConfig: { thinkingBudget: 32768 },
        responseMimeType: "application/json",
      },
    });

    try {
      const result: AnalysisResult = JSON.parse(proResponse.text || "{}");
      return {
        ...result,
        groundingSources: mapsSources.filter((v, i, a) => a.findIndex(t => t.uri === v.uri) === i)
      };
    } catch (e) {
      throw new Error("Feasibility synthesis engine failed to resolve.");
    }
  }
}

