        <div className="flex items-center gap-4">
          <button onClick={(e) => { e.stopPropagation(); setSidebarOpen(true); }} className="p-2.5 hover:bg-slate-100 rounded-xl text-slate-500 transition-all">
            <Menu size={20} />
          </button>
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-2 rounded-xl text-white shadow-lg shadow-indigo-200">
              <Sparkles size={18} />
            </div>
            <h1 className="font-black text-slate-900 tracking-tight text-xl">LocalityMind</h1>
          </div>
        </div>
        <div className="flex items-center gap-3">
          {selectedIds.length > 0 && (
            <button onClick={() => setCompareMode(!compareMode)} className={`flex items-center gap-2 px-5 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${compareMode ? 'bg-indigo-600 text-white' : 'bg-indigo-50 text-indigo-700 hover:bg-indigo-100'}`}>
              <ArrowRightLeft size={16} /> {compareMode ? 'Dashboard' : `Compare (${selectedIds.length})`}
            </button>
          )}
          <button onClick={handleAnalyze} disabled={loading} className="bg-slate-950 text-white px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest flex items-center gap-2 hover:bg-slate-800 transition-all disabled:opacity-50">
            {loading ? <Loader2 size={16} className="animate-spin" /> : <Target size={16} />}
            Analyze Site
          </button>
        </div>
      </header>

      {/* Sidebar */}
      {sidebarOpen && <div className="fixed inset-0 bg-slate-950/40 backdrop-blur-sm z-[70]" onClick={() => setSidebarOpen(false)} />}
      <aside className={`fixed top-0 left-0 h-full w-85 bg-white shadow-2xl z-[80] transform transition-transform duration-500 ${sidebarOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="flex flex-col h-full p-8">
            <div className="flex items-center justify-between mb-10">
                <span className="text-xs font-black uppercase tracking-[0.2em] text-slate-400">Market History</span>
                <button onClick={() => setSidebarOpen(false)}><X size={20}/></button>
            </div>
            <div className="space-y-4 flex-1 overflow-y-auto custom-scrollbar">
                {history.map(item => (
                    <div key={item.id} onClick={() => { setCurrentResult(item); setSidebarOpen(false); }} className="p-4 rounded-3xl border border-slate-100 hover:bg-slate-50 cursor-pointer transition-all">
                        <p className="text-sm font-black truncate">{item.localityName}</p>
                        <p className="text-[10px] font-bold text-slate-400 uppercase mt-1">{item.originalInput.category}</p>
                    </div>
