      </aside>

      <main className="flex-1 overflow-y-auto custom-scrollbar bg-white">
        <div className="flex flex-col">
            <section className="relative w-full h-[95vh] bg-slate-950 overflow-hidden">
              <div ref={mapContainer} className="w-full h-full" />

              {/* 3D Map Control Bar */}
              <div className="absolute bottom-10 right-10 z-30 flex flex-col gap-4 pointer-events-auto">
