                              <Layers size={20} className="text-indigo-600" /> {currentResult.originalInput.floors} Store Levels
                           </div>
                           <div className="flex items-center gap-3 text-slate-400 font-black text-xs uppercase tracking-widest">
                              <Maximize2 size={20} className="text-indigo-600" /> {currentResult.originalInput.length * currentResult.originalInput.breadth * currentResult.originalInput.floors} SQ FT
                           </div>
