                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-10">
                    <MetricCard title="Footfall Stream" value={currentResult.metrics.footfallEstimate.daily.toLocaleString()} Icon={Users} subtitle="Visitors/Day" />
                    <MetricCard title="Economy Proxy" value={`₹${currentResult.demographics.perCapitaIncome.toLocaleString()}`} Icon={CircleDollarSign} subtitle={currentResult.demographics.socioeconomicTier} />
                    <MetricCard title="Market Density" value={currentResult.demographics.populationDensity} Icon={Building2} subtitle="Built Context" />
                    <MetricCard title="Direct Rivals" value={currentResult.metrics.storeCompetition.length} Icon={ShoppingBag} subtitle="Active Entities" />
                  </div>

                  <div className="grid grid-cols-1 xl:grid-cols-2 gap-16">
                    <RevenueChart projections={currentResult.revenueProjections} />
                    <TrafficLandscape data={currentResult.metrics.footfallEstimate.hourlyDistribution} />
                  </div>
                </div>
              ) : (
                <div className="min-h-[600px] border-4 border-dashed border-slate-100 rounded-[6rem] flex flex-col items-center justify-center text-center p-20">
                  <Activity size={80} className="text-indigo-600 opacity-20 mb-8" />
                  <h3 className="text-4xl font-black text-slate-950 mb-4 uppercase tracking-tighter">Locality Awaiting Input</h3>
                  <p className="text-xs text-slate-400 font-black uppercase tracking-[0.4em]">Calibrate the Recon Panel to initiate synthesis.</p>
                </div>
              )}
            </div>
        </div>
      </main>
    </div>
  );
};

export default App;

