const INITIAL_POS = { lat: 19.0596, lng: 72.8295 };

const App: React.FC = () => {
  const mapContainer = useRef<HTMLDivElement>(null);
  const map = useRef<maplibregl.Map | null>(null);
  const mainScrollRef = useRef<HTMLElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);
  const searchTimeout = useRef<number | null>(null);

  // App UI State
  const [loading, setLoading] = useState(false);
  const [history, setHistory] = useState<AnalysisResult[]>([]);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [compareMode, setCompareMode] = useState(false);
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [userLocation, setUserLocation] = useState<{ lat: number; lng: number } | null>(null);
  const [isPanelExpanded, setIsPanelExpanded] = useState(false);

  // Map 3D State
  const [is3D, setIs3D] = useState(true);
  const [pitch, setPitch] = useState(60);
  const [bearing, setBearing] = useState(-20);

  // Locality Search State
  const [suggestions, setSuggestions] = useState<any[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [isSearchingLocality, setIsSearchingLocality] = useState(false);
  const [activeIndex, setActiveIndex] = useState(-1);

  // Current Form State
  const [input, setInput] = useState<StoreInput>({
    location: '',
    coordinates: { ...INITIAL_POS },
    category: 'Premium Cafe (e.g., Starbucks)',
    length: 40,
    breadth: 50,
    floors: 1,
    heightPerFloor: 12,
    targetSegment: ['Gen-Z Trendsetters', 'Young Professionals'],
    extraDetails: {}
  });

  const [currentResult, setCurrentResult] = useState<AnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  // Haversine formula for distance sorting
  const getDistance = (lat1: number, lon1: number, lat2: number, lon2: number) => {
    const R = 6371; // km
    const dLat = (lat2 - lat1) * Math.PI / 180;
    const dLon = (lon2 - lon1) * Math.PI / 180;
    const a = Math.sin(dLat / 2) * Math.sin(dLat / 2) +
              Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) *
              Math.sin(dLon / 2) * Math.sin(dLon / 2);
    const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
    return R * c;
  };

  // Initial Geolocation logic
  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition((pos) => {
        const coords = { lat: pos.coords.latitude, lng: pos.coords.longitude };
        setUserLocation(coords);
        if (map.current) {
          map.current.flyTo({ center: [coords.lng, coords.lat], zoom: 12 });
        }
      }, () => console.log("Location access denied, defaulting to Mumbai hub."));
    }
  }, []);

  // Map Initialization
  useEffect(() => {
    if (!mapContainer.current) return;
    (maplibregl as any).workerCount = 0;
    const mapInstance = new maplibregl.Map({
      container: mapContainer.current!,
      style: 'https://tiles.basemaps.cartocdn.com/gl/dark-matter-gl-style/style.json',
      center: [INITIAL_POS.lng, INITIAL_POS.lat],
      zoom: 14,
      pitch: 60,
      bearing: -20,
      attributionControl: false,
    });

    mapInstance.on('load', () => {
      map.current = mapInstance;

      // Add 3D building extrusion
      if (mapInstance.getSource('openmaptiles')) {
        mapInstance.addLayer({
          'id': '3d-buildings',
          'source': 'openmaptiles',
          'source-layer': 'building',
          'type': 'fill-extrusion',
          'minzoom': 15,
          'paint': {
            'fill-extrusion-color': '#4f46e5',
            'fill-extrusion-height': ['get', 'render_height'],
            'fill-extrusion-base': ['get', 'render_min_height'],
            'fill-extrusion-opacity': 0.6
          }
        });
      }
    });

    mapInstance.on('rotate', () => setBearing(mapInstance.getBearing()));
    mapInstance.on('pitch', () => setPitch(mapInstance.getPitch()));

    return () => mapInstance?.remove();
  }, []);

  const toggle3D = () => {
    if (!map.current) return;
    const next3D = !is3D;
    setIs3D(next3D);
    const targetPitch = next3D ? 60 : 0;
    map.current.easeTo({ pitch: targetPitch, duration: 800 });
    setPitch(targetPitch);
  };

  const handlePitchChange = (val: number) => {
    if (!map.current) return;
    setPitch(val);
    map.current.setPitch(val);
    if (val > 0) setIs3D(true);
    else setIs3D(false);
  };

  const handleBearingChange = (val: number) => {
    if (!map.current) return;
    setBearing(val);
    map.current.setBearing(val);
  };

  const resetCamera = () => {
    if (!map.current) return;
    map.current.easeTo({ pitch: 0, bearing: 0, duration: 1000 });
    setPitch(0);
    setBearing(0);
    setIs3D(false);
  };

  const handleLocalityChange = (val: string) => {
    setInput(prev => ({ ...prev, location: val }));
    setShowSuggestions(true);
    setActiveIndex(-1);

    if (val.trim().length > 1) {
      if (searchTimeout.current) window.clearTimeout(searchTimeout.current);
      setIsSearchingLocality(true);
      searchTimeout.current = window.setTimeout(async () => {
        try {
          const response = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(val)}&countrycodes=in&limit=10`);
          const data = await response.json();
          let results = data.map((item: any) => ({
            name: item.display_name,
            lat: parseFloat(item.lat),
            lng: parseFloat(item.lon)
          }));

          if (userLocation) {
            results = results.sort((a: any, b: any) => {
              const distA = getDistance(userLocation.lat, userLocation.lng, a.lat, a.lng);
              const distB = getDistance(userLocation.lat, userLocation.lng, b.lat, b.lng);
              return distA - distB;
            });
          }

          setSuggestions(results);
        } catch (err) {
          setSuggestions([]);
        } finally {
          setIsSearchingLocality(false);
        }
      }, 400);
    } else {
      setSuggestions([]);
      setShowSuggestions(false);
    }
  };

  const handleSelectLocality = (loc: any) => {
    setInput(p => ({ 
      ...p, 
      location: loc.name, 
      coordinates: { lat: loc.lat, lng: loc.lng } 
    }));
    setShowSuggestions(false);
    setIsPanelExpanded(false);
    if (map.current) {
      map.current.flyTo({ center: [loc.lng, loc.lat], zoom: 15.8, pitch: pitch || 60, duration: 2000 });
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (!showSuggestions) return;
    if (e.key === 'ArrowDown') setActiveIndex(prev => (prev < suggestions.length - 1 ? prev + 1 : prev));
    else if (e.key === 'ArrowUp') setActiveIndex(prev => (prev > 0 ? prev - 1 : prev));
    else if (e.key === 'Enter') activeIndex >= 0 && handleSelectLocality(suggestions[activeIndex]);
    else if (e.key === 'Escape') {
      setShowSuggestions(false);
      setIsPanelExpanded(false);
    }
  };

  const handleAnalyze = async () => {
    setLoading(true);
    setError(null);
    setIsPanelExpanded(false);
    try {
      const data = await GeminiService.analyzeMarket(input);
      const newResult: AnalysisResult = {
        ...data,
        id: crypto.randomUUID(),
        timestamp: Date.now(),
        originalInput: { ...input }
      };
      setHistory(prev => [newResult, ...prev]);
      setCurrentResult(newResult);
      setCompareMode(false);
      setTimeout(() => {
        scrollToResults();
      }, 500);
    } catch (err: any) {
      setError(err.message || 'Analysis failed.');
    } finally {
      setLoading(false);
    }
  };

  const scrollToResults = () => {
    document.getElementById('results-view')?.scrollIntoView({ behavior: 'smooth', block: 'start' });
  };

  const updateExtraDetail = (key: string, value: any) => {
    setInput(prev => ({
      ...prev,
      extraDetails: { ...prev.extraDetails, [key]: value }
    }));
  };

  return (
    <div className="flex flex-col h-screen bg-[#f8fafc] text-slate-900 overflow-hidden relative" onClick={() => { setShowSuggestions(false); setIsPanelExpanded(false); }}>
      {/* Header */}
      <header className="h-16 bg-white/90 backdrop-blur-xl border-b border-slate-200 px-6 flex items-center justify-between z-[60] flex-shrink-0 sticky top-0">
        <div className="flex items-center gap-4">
          <button onClick={(e) => { e.stopPropagation(); setSidebarOpen(true); }} className="p-2.5 hover:bg-slate-100 rounded-xl text-slate-500 transition-all">
            <Menu size={20} />
          </button>
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-2 rounded-xl text-white shadow-lg shadow-indigo-200">
              <Sparkles size={18} />
            </div>
            <h1 className="font-black text-slate-900 tracking-tight text-xl">LocalityMind</h1>
          </div>
        </div>
        <div className="flex items-center gap-3">
          {selectedIds.length > 0 && (
            <button onClick={() => setCompareMode(!compareMode)} className={`flex items-center gap-2 px-5 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${compareMode ? 'bg-indigo-600 text-white' : 'bg-indigo-50 text-indigo-700 hover:bg-indigo-100'}`}>
              <ArrowRightLeft size={16} /> {compareMode ? 'Dashboard' : `Compare (${selectedIds.length})`}
            </button>
          )}
          <button onClick={handleAnalyze} disabled={loading} className="bg-slate-950 text-white px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest flex items-center gap-2 hover:bg-slate-800 transition-all disabled:opacity-50 shadow-xl shadow-slate-200/50">
            {loading ? <Loader2 size={16} className="animate-spin" /> : <Target size={16} />}
            Analyze Site
          </button>
        </div>
      </header>

      {/* Sidebar */}
      {sidebarOpen && <div className="fixed inset-0 bg-slate-950/40 backdrop-blur-sm z-[70]" onClick={() => setSidebarOpen(false)} />}
      <aside className={`fixed top-0 left-0 h-full w-85 bg-white shadow-2xl z-[80] transform transition-transform duration-500 ${sidebarOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="flex flex-col h-full p-8">
            <div className="flex items-center justify-between mb-10">
                <span className="text-xs font-black uppercase tracking-[0.2em] text-slate-400">Market History</span>
                <button onClick={() => setSidebarOpen(false)}><X size={20}/></button>
            </div>
            <div className="space-y-4 flex-1 overflow-y-auto custom-scrollbar">
                {history.map(item => (
                    <div key={item.id} onClick={() => { setCurrentResult(item); setSidebarOpen(false); }} className="p-4 rounded-3xl border border-slate-100 hover:bg-slate-50 cursor-pointer transition-all">
                        <p className="text-sm font-black truncate">{item.localityName}</p>
                        <p className="text-[10px] font-bold text-slate-400 uppercase mt-1">{item.originalInput.category}</p>
                    </div>
                ))}
                {history.length === 0 && (
                  <div className="py-20 text-center opacity-20">
                    <History size={48} className="mx-auto mb-4" />
                    <p className="text-[10px] font-black uppercase tracking-widest">No site records found</p>
                  </div>
                )}
            </div>
        </div>
      </aside>

      <main ref={mainScrollRef} className="flex-1 overflow-y-auto custom-scrollbar bg-white scroll-smooth">
        <div className="flex flex-col min-h-full">
            <section className="relative w-full h-[calc(100vh-64px)] bg-slate-950 overflow-hidden flex-shrink-0">
              <div ref={mapContainer} className="w-full h-full" />

              {/* Perspective Controls (Bottom Right) */}
              <div className="absolute bottom-12 right-12 z-30 flex flex-col gap-4 pointer-events-auto">
                <div className="bg-slate-950/80 backdrop-blur-3xl border border-white/10 p-6 rounded-[2.5rem] shadow-[0_20px_50px_rgba(0,0,0,0.5)] space-y-6 w-64 text-white">
                  <div className="flex items-center justify-between">
                    <span className="text-[10px] font-black uppercase tracking-widest text-white/40">Spatial Perspective</span>
                    <button onClick={resetCamera} className="p-2 hover:bg-white/10 rounded-xl text-white/60 transition-all" title="Reset Camera">
                      <RotateCcw size={14} />
                    </button>
                  </div>

                  <div className="space-y-4">
                    <button 
                      onClick={toggle3D}
                      className={`w-full py-4 rounded-2xl flex items-center justify-center gap-3 transition-all border font-black text-[10px] uppercase tracking-widest ${is3D ? 'bg-indigo-600 border-indigo-400 text-white shadow-[0_0_20px_rgba(79,70,229,0.3)]' : 'bg-white/5 border-white/10 text-white/40'}`}
                    >
                      <Box size={14} /> {is3D ? '3D Active' : 'Enable 3D'}
                    </button>

                    <div className="space-y-2">
                      <div className="flex justify-between items-center text-[9px] font-black text-white/30 uppercase tracking-widest px-1">
                        <span>Tilt</span>
                        <span className="text-indigo-400">{Math.round(pitch)}°</span>
                      </div>
                      <input 
                        type="range" min="0" max="85" step="1" 
                        value={pitch} 
                        onChange={(e) => handlePitchChange(Number(e.target.value))}
                        className="w-full accent-indigo-500 h-1 bg-white/10 rounded-lg appearance-none cursor-pointer"
                      />
                    </div>

                    <div className="space-y-2">
                      <div className="flex justify-between items-center text-[9px] font-black text-white/30 uppercase tracking-widest px-1">
                        <span>Rotation</span>
                        <span className="text-indigo-400">{Math.round(bearing)}°</span>
                      </div>
                      <input 
                        type="range" min="-180" max="180" step="1" 
                        value={bearing} 
                        onChange={(e) => handleBearingChange(Number(e.target.value))}
                        className="w-full accent-indigo-500 h-1 bg-white/10 rounded-lg appearance-none cursor-pointer"
                      />
                    </div>
                  </div>
                </div>
              </div>

              {/* Dynamic Recon Panel (Left) */}
              <div className="absolute inset-y-0 left-0 z-40 w-full max-w-5xl p-10 flex flex-col justify-center pointer-events-none">
                <div 
                  className={`pointer-events-auto bg-slate-950/70 backdrop-blur-3xl p-12 rounded-[4rem] border border-white/10 shadow-[0_40px_100px_rgba(0,0,0,0.6)] space-y-10 text-white transition-all duration-700 ease-in-out overflow-hidden ${isPanelExpanded ? 'w-[700px]' : 'w-[500px]'}`}
                >
                  <div className="flex items-center justify-between border-b border-white/10 pb-6">
                    <h3 className="text-[10px] font-black uppercase tracking-[0.5em] text-white/40 flex items-center gap-3">
                      <Target size={14} className="text-indigo-400" /> Site Recon Panel
                    </h3>
                    {(isSearchingLocality || loading) && <Loader2 size={16} className="animate-spin text-indigo-400" />}
                  </div>

                  <div className="space-y-8 max-h-[60vh] overflow-y-auto custom-scrollbar pr-4">
                    {/* Location Input with Dynamic Width Expansion */}
                    <div className="relative">
                      <label className="block text-[10px] font-black text-white/30 mb-4 uppercase tracking-[0.2em] flex items-center justify-between">
                        Target Locality
                        {userLocation && <span className="text-[8px] text-indigo-400 animate-pulse tracking-widest">PROXIMITY SYNCED</span>}
                      </label>
                      <div className="relative group/input">
                        <Search className="absolute left-6 top-1/2 -translate-y-1/2 text-white/20" size={20} />
                        <input 
                          type="text" 
                          value={input.location} 
                          onChange={(e) => handleLocalityChange(e.target.value)}
                          onKeyDown={handleKeyDown}
                          onFocus={(e) => { e.stopPropagation(); setIsPanelExpanded(true); if (input.location.length > 1) setShowSuggestions(true); }}
                          onClick={(e) => e.stopPropagation()}
                          className="w-full bg-white/5 border border-white/10 rounded-[2rem] py-5 pl-16 pr-6 text-sm font-bold text-white outline-none focus:bg-white/10 transition-all placeholder:text-white/10"
                          placeholder="Search for a locality..."
                        />
                      </div>

                      {/* Search Suggestions */}
                      {showSuggestions && (
                        <div className="absolute top-full left-0 right-0 mt-3 bg-slate-900/98 backdrop-blur-3xl border border-white/10 rounded-[2.5rem] overflow-hidden shadow-[0_30px_60px_rgba(0,0,0,0.6)] z-50 animate-in fade-in zoom-in-95 duration-300">
                          <div className="p-4 max-h-[300px] overflow-y-auto custom-scrollbar">
                            <p className="text-[8px] font-black text-white/20 uppercase tracking-[0.3em] px-4 mb-2">Refining Global Context Nodes</p>
                            {suggestions.map((loc, i) => (
                              <button 
                                key={i} 
                                onClick={(e) => { e.stopPropagation(); handleSelectLocality(loc); }} 
                                onMouseEnter={() => setActiveIndex(i)} 
                                className={`w-full text-left p-5 rounded-3xl flex items-center gap-5 transition-all group/sugg ${activeIndex === i ? 'bg-indigo-600 text-white' : 'text-white/40 hover:text-white/70'}`}
                              >
                                <MapPin size={14} className={activeIndex === i ? 'text-white' : 'text-white/20'} />
                                <div className="overflow-hidden flex-1">
                                  <span className="text-xs font-black block truncate leading-tight">{loc.name}</span>
                                  <span className="text-[8px] font-bold opacity-40 uppercase mt-1">Geospatial Coordinate Validated</span>
                                </div>
                              </button>
                            ))}
                            {suggestions.length === 0 && !isSearchingLocality && (
                              <div className="p-8 text-center text-[10px] font-black text-white/20 uppercase">No results in this radius</div>
                            )}
                          </div>
                        </div>
                      )}
                    </div>

                    {/* Architectural Specs */}
                    <div className="grid grid-cols-3 gap-6">
                       <div className="space-y-3">
                          <label className="block text-[10px] font-black text-white/30 uppercase tracking-widest px-1">Width (ft)</label>
                          <input type="number" value={input.length} onChange={(e) => setInput(p => ({...p, length: Number(e.target.value)}))} className="w-full bg-white/5 border border-white/10 rounded-2xl py-4 px-5 text-sm font-black text-white outline-none focus:bg-white/10 transition-colors" />
                       </div>
                       <div className="space-y-3">
                          <label className="block text-[10px] font-black text-white/30 uppercase tracking-widest px-1">Depth (ft)</label>
                          <input type="number" value={input.breadth} onChange={(e) => setInput(p => ({...p, breadth: Number(e.target.value)}))} className="w-full bg-white/5 border border-white/10 rounded-2xl py-4 px-5 text-sm font-black text-white outline-none focus:bg-white/10 transition-colors" />
                       </div>
                       <div className="space-y-3">
                          <label className="block text-[10px] font-black text-white/30 uppercase tracking-widest px-1">Levels</label>
                          <input type="number" min="1" max="10" value={input.floors} onChange={(e) => setInput(p => ({...p, floors: Number(e.target.value)}))} className="w-full bg-white/5 border border-white/10 rounded-2xl py-4 px-5 text-sm font-black text-white outline-none focus:bg-white/10 transition-colors" />
                       </div>
                    </div>

                    {/* Business Parameters */}
                    <div className="space-y-6 bg-white/5 p-8 rounded-[3rem] border border-white/5">
                      <div className="relative">
                        <label className="block text-[10px] font-black text-white/30 mb-4 uppercase tracking-widest flex items-center gap-2">
                           <Settings2 size={12} className="text-indigo-400" /> Business Archetype
                        </label>
                        <select 
                          value={input.category} 
                          onFocus={() => setIsPanelExpanded(true)}
                          onChange={(e) => setInput(p => ({...p, category: e.target.value as StoreCategory, extraDetails: {}}))} 
                          className="w-full bg-white/5 border border-white/10 rounded-[2rem] py-5 px-6 text-sm font-black text-white appearance-none cursor-pointer outline-none focus:bg-white/10 transition-all"
                        >
                          {STORE_CATEGORIES.map(c => <option key={c} value={c} className="bg-slate-900">{c}</option>)}
                        </select>
                        <ChevronRight size={18} className="absolute right-6 top-[62%] -translate-y-1/2 rotate-90 text-white/20 pointer-events-none" />
                      </div>

                      <div className="space-y-6 animate-in fade-in slide-in-from-top-4">
                        <p className="text-[9px] font-black text-indigo-400 uppercase tracking-[0.4em]">Strategic Variables</p>
                        <div className="grid grid-cols-1 gap-4">
                          {CATEGORY_QUESTIONS[input.category].map((q) => (
                            <div key={q.key} className="flex items-center justify-between bg-white/5 px-6 py-4 rounded-3xl border border-white/5 group hover:bg-white/10 transition-all">
                              <span className="text-[10px] font-bold text-white/50 group-hover:text-white transition-colors">{q.label}</span>
                              {q.type === 'toggle' ? (
                                <button 
                                  onClick={(e) => { e.stopPropagation(); updateExtraDetail(q.key, !input.extraDetails?.[q.key]); }}
                                  className={`w-12 h-6 rounded-full transition-all relative ${input.extraDetails?.[q.key] ? 'bg-indigo-600' : 'bg-white/20'}`}
                                >
                                  <div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-all ${input.extraDetails?.[q.key] ? 'left-7' : 'left-1'}`} />
                                </button>
                              ) : (
                                <select 
                                  value={(input.extraDetails?.[q.key] as string) || ''}
                                  onChange={(e) => updateExtraDetail(q.key, e.target.value)}
                                  className="bg-transparent text-[10px] font-black text-indigo-400 outline-none cursor-pointer"
                                >
                                  <option value="">Select...</option>
                                  {q.options?.map(opt => <option key={opt} value={opt} className="bg-slate-900">{opt}</option>)}
                                </select>
                              )}
                            </div>
                          ))}
                        </div>
                      </div>
                    </div>

                    <button 
                      onClick={(e) => { e.stopPropagation(); handleAnalyze(); }}
                      disabled={loading || !input.location}
                      className="w-full bg-indigo-600 text-white py-6 rounded-[2.5rem] text-xs font-black uppercase tracking-[0.5em] hover:bg-indigo-700 transition-all shadow-2xl shadow-indigo-500/30 disabled:opacity-50 active:scale-95 group/btn"
                    >
                      {loading ? (
                        <div className="flex items-center justify-center gap-4">
                          <Loader2 size={20} className="animate-spin" />
                          <span>Processing Intelligence</span>
                        </div>
                      ) : (
                        <div className="flex items-center justify-center gap-4">
                          <Target size={20} />
                          <span>Synchronize Market Report</span>
                        </div>
                      )}
                    </button>
                  </div>
                </div>
              </div>

              {/* Dynamic Scroll Indicator (Arrow) */}
              <div className="absolute bottom-10 left-1/2 -translate-x-1/2 z-50 flex flex-col items-center gap-2 pointer-events-auto">
                <button 
                  onClick={scrollToResults}
                  className={`flex flex-col items-center gap-2 transition-all duration-700 ${currentResult ? 'opacity-100 translate-y-0 scale-100' : 'opacity-0 translate-y-10 scale-90 pointer-events-none'}`}
                >
                  <span className="text-[9px] font-black text-white/40 uppercase tracking-[0.5em] mb-2">Analysis Available</span>
                  <div className="w-12 h-12 rounded-full bg-white/10 backdrop-blur-xl border border-white/20 flex items-center justify-center text-white hover:bg-white/20 hover:scale-110 transition-all animate-bounce shadow-2xl">
                    <ChevronDown size={24} />
                  </div>
                </button>
              </div>

              {/* Status Indicator (Top Right) */}
              <div className="absolute top-10 right-10 z-10">
                 <div className="bg-slate-950/80 backdrop-blur-xl border border-white/10 px-6 py-3 rounded-2xl flex items-center gap-3 shadow-2xl text-[10px] font-black text-white uppercase tracking-[0.3em]">
                    <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse shadow-[0_0_10px_rgba(34,197,94,0.6)]" /> System: Nominal
                 </div>
              </div>
            </section>

            {/* Analysis Results View */}
            <div id="results-view" className="bg-white min-h-screen relative z-30 shadow-[0_-40px_100px_rgba(0,0,0,0.1)] rounded-t-[5rem]">
              <div className="p-10 lg:p-24 space-y-32">
                {currentResult ? (
                  <div className="space-y-32 animate-in fade-in slide-in-from-bottom-20 duration-1000">
                    <div className="flex flex-col lg:flex-row gap-16 items-end justify-between border-b border-slate-100 pb-24">
                       <div className="space-y-8 max-w-4xl">
                          <div className="flex items-center gap-4">
                            <span className="px-6 py-2.5 bg-slate-950 text-white rounded-full text-[10px] font-black uppercase tracking-[0.4em]">Strategic Synthesis Complete</span>
                            <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest">{new Date(currentResult.timestamp).toLocaleTimeString()}</span>
                          </div>
                          <h2 className="text-[10rem] font-black tracking-tighter text-slate-950 leading-[0.75] mb-8">{currentResult.localityName.split(',')[0]}</h2>
                          <div className="flex flex-wrap items-center gap-10">
                             <div className="flex items-center gap-4 text-slate-400 font-black text-xs uppercase tracking-widest bg-slate-50 px-6 py-3 rounded-2xl border border-slate-100">
                                <Layers size={18} className="text-indigo-600" /> {currentResult.originalInput.floors} Store Levels
                             </div>
                             <div className="flex items-center gap-4 text-slate-400 font-black text-xs uppercase tracking-widest bg-slate-50 px-6 py-3 rounded-2xl border border-slate-100">
                                <Maximize2 size={18} className="text-indigo-600" /> {currentResult.originalInput.length * currentResult.originalInput.breadth * currentResult.originalInput.floors} SQ FT Area
                             </div>
                          </div>
                       </div>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-12">
                      <MetricCard title="Footfall Velocity" value={currentResult.metrics.footfallEstimate.daily.toLocaleString()} Icon={Users} subtitle="Verified Daily Visitors" />
                      <MetricCard title="Affluence Index" value={`₹${currentResult.demographics.perCapitaIncome.toLocaleString()}`} Icon={CircleDollarSign} subtitle={currentResult.demographics.socioeconomicTier} />
                      <MetricCard title="Spatial Context" value={currentResult.demographics.populationDensity} Icon={Building2} subtitle="Network Density" />
