                               </div>
                               <span className="text-xl font-black text-indigo-600">{currentResult.metrics.nearbyPOIs.hotels.luxury + currentResult.metrics.nearbyPOIs.hotels.midTier}</span>
                            </div>
                            <div className="flex items-center justify-between p-6 bg-slate-50 rounded-2xl border border-slate-100">
                               <div className="flex items-center gap-4">
                                  <Landmark className="text-indigo-600" />
                                  <span className="text-sm font-black text-slate-900 uppercase">Culture Hubs</span>
                               </div>
                               <span className="text-xl font-black text-indigo-600">{currentResult.metrics.nearbyPOIs.placesOfWorship}</span>
                            </div>
                         </div>
                      </div>
                    </div>
                  </div>
                ) : (
                  <div className="min-h-[80vh] flex flex-col items-center justify-center text-center p-20 opacity-30 animate-pulse">
                    <Activity size={100} className="text-indigo-600 mb-8" />
                    <h3 className="text-5xl font-black text-slate-900 mb-4 tracking-tighter">Locality Processor Idle</h3>
                    <p className="text-xs text-slate-500 font-black uppercase tracking-[0.5em]">Awaiting synchronization via Site Recon Panel</p>
                  </div>
                )}
              </div>
            </div>
        </div>
      </main>
    </div>
  );
};

export default App;

