                        <ChevronRight size={18} className="absolute right-6 top-[62%] -translate-y-1/2 rotate-90 text-white/20 pointer-events-none" />
                      </div>
                      <div className="space-y-6">
                        <div className="grid grid-cols-1 gap-4">
                          {CATEGORY_QUESTIONS[input.category].map((q) => (
                            <div key={q.key} className="flex items-center justify-between bg-white/5 px-6 py-4 rounded-3xl border border-white/5">
                              <span className="text-[10px] font-bold text-white/50">{q.label}</span>
                              {q.type === 'toggle' ? (
                                <button 
                                  onClick={(e) => { e.stopPropagation(); updateExtraDetail(q.key, !input.extraDetails?.[q.key]); }}
                                  className={`w-12 h-6 rounded-full transition-all relative ${input.extraDetails?.[q.key] ? 'bg-indigo-600' : 'bg-white/20'}`}
                                >
                                  <div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-all ${input.extraDetails?.[q.key] ? 'left-7' : 'left-1'}`} />
                                </button>
                              ) : (
                                <select 
                                  value={(input.extraDetails?.[q.key] as string) || ''}
                                  onChange={(e) => updateExtraDetail(q.key, e.target.value)}
