    { label: 'Event Hall Included', key: 'hasEventSpace', type: 'toggle' }
  ],
  'Quick Service Restaurant (QSR)': [
    { label: 'Cloud Kitchen Model', key: 'isCloudKitchen', type: 'toggle' },
    { label: 'Seating Available', key: 'hasSeating', type: 'toggle' }
  ]
};

const INITIAL_POS = { lat: 19.0596, lng: 72.8295 };

const App: React.FC = () => {
  const mapContainer = useRef<HTMLDivElement>(null);
  const map = useRef<maplibregl.Map | null>(null);
  const mainScrollRef = useRef<HTMLElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);
  const searchTimeout = useRef<number | null>(null);

  const [loading, setLoading] = useState(false);
  const [history, setHistory] = useState<AnalysisResult[]>([]);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [compareMode, setCompareMode] = useState(false);
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [userLocation, setUserLocation] = useState<{ lat: number; lng: number } | null>(null);
  const [isPanelExpanded, setIsPanelExpanded] = useState(false);

  const [is3D, setIs3D] = useState(true);
  const [pitch, setPitch] = useState(60);
  const [bearing, setBearing] = useState(-20);

  const [suggestions, setSuggestions] = useState<any[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [isSearchingLocality, setIsSearchingLocality] = useState(false);
  const [activeIndex, setActiveIndex] = useState(-1);

  const [input, setInput] = useState<StoreInput>({
    location: '',
    coordinates: { ...INITIAL_POS },
    category: 'Premium Cafe (e.g., Starbucks)',
    length: 40,
    breadth: 50,
    floors: 1,
    heightPerFloor: 12,
    targetSegment: ['Gen-Z Trendsetters', 'Young Professionals'],
    extraDetails: {}
  });

  const [currentResult, setCurrentResult] = useState<AnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  const getDistance = (lat1: number, lon1: number, lat2: number, lon2: number) => {
    const R = 6371;
    const dLat = (lat2 - lat1) * Math.PI / 180;
    const dLon = (lon2 - lon1) * Math.PI / 180;
    const a = Math.sin(dLat / 2) * Math.sin(dLat / 2) +
              Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) *
              Math.sin(dLon / 2) * Math.sin(dLon / 2);
    const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
    return R * c;
  };

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition((pos) => {
        const coords = { lat: pos.coords.latitude, lng: pos.coords.longitude };
        setUserLocation(coords);
        if (map.current) {
          map.current.flyTo({ center: [coords.lng, coords.lat], zoom: 12 });
        }
      }, () => console.log("Location access denied."));
    }
  }, []);

  useEffect(() => {
    if (!mapContainer.current) return;
    (maplibregl as any).workerCount = 0;
    const mapInstance = new maplibregl.Map({
      container: mapContainer.current!,
      style: 'https://tiles.basemaps.cartocdn.com/gl/dark-matter-gl-style/style.json',
      center: [INITIAL_POS.lng, INITIAL_POS.lat],
      zoom: 14,
      pitch: 60,
      bearing: -20,
      attributionControl: false,
    });
    mapInstance.on('load', () => {
      map.current = mapInstance;
      if (mapInstance.getSource('openmaptiles')) {
        mapInstance.addLayer({
          'id': '3d-buildings',
          'source': 'openmaptiles',
          'source-layer': 'building',
          'type': 'fill-extrusion',
          'minzoom': 15,
          'paint': {
            'fill-extrusion-color': '#4f46e5',
            'fill-extrusion-height': ['get', 'render_height'],
            'fill-extrusion-base': ['get', 'render_min_height'],
            'fill-extrusion-opacity': 0.6
          }
        });
      }
    });
    mapInstance.on('rotate', () => setBearing(mapInstance.getBearing()));
    mapInstance.on('pitch', () => setPitch(mapInstance.getPitch()));
    return () => mapInstance?.remove();
  }, []);

  // Fix: Added handleKeyDown to handle locality selection with keyboard
  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'ArrowDown') {
      setActiveIndex(prev => Math.min(prev + 1, suggestions.length - 1));
    } else if (e.key === 'ArrowUp') {
      setActiveIndex(prev => Math.max(prev - 1, 0));
    } else if (e.key === 'Enter' && activeIndex >= 0) {
      handleSelectLocality(suggestions[activeIndex]);
    }
  };

  // Fix: Added camera control handlers
  const resetCamera = () => {
    setPitch(60);
    setBearing(-20);
    if (map.current) {
      map.current.setPitch(60);
      map.current.setBearing(-20);
    }
  };

  const toggle3D = () => setIs3D(!is3D);

  const handlePitchChange = (val: number) => {
    setPitch(val);
    if (map.current) map.current.setPitch(val);
  };

  const handleBearingChange = (val: number) => {
    setBearing(val);
    if (map.current) map.current.setBearing(val);
  };

  // Fix: Added updateExtraDetail for managing category-specific details
  const updateExtraDetail = (key: string, value: any) => {
    setInput(prev => ({
      ...prev,
      extraDetails: { ...prev.extraDetails, [key]: value }
    }));
  };

  const handleLocalityChange = (val: string) => {
    setInput(prev => ({ ...prev, location: val }));
    setShowSuggestions(true);
    setActiveIndex(-1);
    if (val.trim().length > 1) {
      if (searchTimeout.current) window.clearTimeout(searchTimeout.current);
      setIsSearchingLocality(true);
      searchTimeout.current = window.setTimeout(async () => {
        try {
          const response = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(val)}&countrycodes=in&limit=10`);
          const data = await response.json();
          let results = data.map((item: any) => ({
            name: item.display_name,
            lat: parseFloat(item.lat),
            lng: parseFloat(item.lon)
          }));
          if (userLocation) {
            results = results.sort((a: any, b: any) => {
              const distA = getDistance(userLocation.lat, userLocation.lng, a.lat, a.lng);
              const distB = getDistance(userLocation.lat, userLocation.lng, b.lat, b.lng);
              return distA - distB;
            });
          }
          setSuggestions(results);
        } catch (err) {
          setSuggestions([]);
        } finally {
          setIsSearchingLocality(false);
        }
      }, 400);
    } else {
      setSuggestions([]);
      setShowSuggestions(false);
    }
  };

  const handleSelectLocality = (loc: any) => {
    setInput(p => ({ 
      ...p, 
      location: loc.name, 
      coordinates: { lat: loc.lat, lng: loc.lng } 
    }));
    setShowSuggestions(false);
    setIsPanelExpanded(false);
    if (map.current) {
      map.current.flyTo({ center: [loc.lng, loc.lat], zoom: 15.8, pitch: pitch || 60, duration: 2000 });
    }
  };

  const toggleComparisonItem = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setSelectedIds(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
  };

  const deleteHistoryItem = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setHistory(prev => prev.filter(item => item.id !== id));
    setSelectedIds(prev => prev.filter(i => i !== id));
    if (currentResult?.id === id) setCurrentResult(null);
  };

  const handleAnalyze = async () => {
    setLoading(true);
    setError(null);
    setIsPanelExpanded(false);
    try {
      const data = await GeminiService.analyzeMarket(input);
      const newResult: AnalysisResult = {
        ...data,
        id: crypto.randomUUID(),
        timestamp: Date.now(),
        originalInput: { ...input }
      };
      setHistory(prev => [newResult, ...prev]);
      setCurrentResult(newResult);
      setCompareMode(false);
      setTimeout(() => scrollToResults(), 500);
    } catch (err: any) {
      setError(err.message || 'Analysis failed.');
    } finally {
      setLoading(false);
    }
  };

  const scrollToResults = () => {
    document.getElementById('results-view')?.scrollIntoView({ behavior: 'smooth', block: 'start' });
  };

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('en-IN', {
      style: 'currency', currency: 'INR', maximumFractionDigits: 0
    }).format(val);
  };

  return (
    <div className="flex flex-col h-screen bg-slate-950 text-slate-900 overflow-hidden relative" onClick={() => { setShowSuggestions(false); setIsPanelExpanded(false); }}>
      {/* Header */}
      <header className="h-16 bg-white/95 backdrop-blur-xl border-b border-slate-200 px-6 flex items-center justify-between z-[60] flex-shrink-0 sticky top-0">
        <div className="flex items-center gap-4">
          <button onClick={(e) => { e.stopPropagation(); setSidebarOpen(true); }} className="p-2.5 hover:bg-slate-100 rounded-xl text-slate-500 transition-all">
            <Menu size={20} />
          </button>
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-2 rounded-xl text-white shadow-lg shadow-indigo-200">
              <Sparkles size={18} />
            </div>
            <h1 className="font-black text-slate-900 tracking-tight text-xl">LocalityMind</h1>
          </div>
        </div>
        <div className="flex items-center gap-3">
          {selectedIds.length > 0 && (
            <button 
              onClick={() => setCompareMode(!compareMode)} 
              className={`flex items-center gap-2 px-5 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${compareMode ? 'bg-indigo-600 text-white' : 'bg-indigo-50 text-indigo-700 hover:bg-indigo-100'}`}
            >
              <ArrowRightLeft size={16} /> 
              {compareMode ? 'Exit Comparison' : `Compare Results (${selectedIds.length})`}
            </button>
          )}
          <button onClick={handleAnalyze} disabled={loading} className="bg-slate-950 text-white px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest flex items-center gap-2 hover:bg-slate-800 transition-all disabled:opacity-50">
            {loading ? <Loader2 size={16} className="animate-spin" /> : <Target size={16} />}
            Analyze
          </button>
        </div>
      </header>

      {/* Re-implemented Power Sidebar */}
      {sidebarOpen && <div className="fixed inset-0 bg-slate-950/40 backdrop-blur-sm z-[70]" onClick={() => setSidebarOpen(false)} />}
      <aside className={`fixed top-0 left-0 h-full w-96 bg-white shadow-2xl z-[80] transform transition-transform duration-500 flex flex-col ${sidebarOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="p-8 border-b border-slate-100 flex items-center justify-between">
            <div className="flex items-center gap-2">
              <History size={16} className="text-indigo-600" />
              <span className="text-xs font-black uppercase tracking-[0.2em] text-slate-900">Synthesis Log</span>
            </div>
            <button onClick={() => setSidebarOpen(false)} className="p-2 hover:bg-slate-100 rounded-xl text-slate-400">
              <X size={20} />
            </button>
        </div>
        <div className="flex-1 overflow-y-auto custom-scrollbar p-6 space-y-4">
            {history.map(item => (
                <div 
                  key={item.id} 
                  onClick={() => { setCurrentResult(item); setSidebarOpen(false); setCompareMode(false); }} 
                  className={`group relative p-5 rounded-[2rem] border transition-all cursor-pointer ${currentResult?.id === item.id ? 'bg-indigo-50/50 border-indigo-200' : 'border-slate-100 hover:bg-slate-50'}`}
                >
                    <div className="flex justify-between items-start mb-1">
                        <h4 className="text-sm font-black text-slate-900 truncate pr-16">{item.localityName}</h4>
                        <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity absolute top-4 right-4">
                           <button 
                             onClick={(e) => toggleComparisonItem(item.id, e)}
                             className={`p-2 rounded-xl transition-all ${selectedIds.includes(item.id) ? 'bg-indigo-600 text-white shadow-lg' : 'bg-white text-slate-300 hover:text-indigo-600 border border-slate-100'}`}
                           >
                             {selectedIds.includes(item.id) ? <Check size={14} /> : <PlusCircle size={14} />}
                           </button>
                           <button 
                             onClick={(e) => deleteHistoryItem(item.id, e)}
                             className="p-2 bg-white text-slate-300 hover:text-red-500 rounded-xl border border-slate-100 transition-all"
                           >
                             <Trash2 size={14} />
                           </button>
                        </div>
                    </div>
                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{item.originalInput.category}</p>
                    <div className="mt-4 flex items-center justify-between">
                       <span className="text-[10px] font-black text-indigo-600">{formatCurrency(item.revenueProjections.monthly)}/mo</span>
                       <span className="text-[8px] font-bold text-slate-300 uppercase">{new Date(item.timestamp).toLocaleDateString()}</span>
                    </div>
                </div>
            ))}
            {history.length === 0 && (
              <div className="py-20 text-center opacity-20">
                <History size={48} className="mx-auto mb-4" />
                <p className="text-[10px] font-black uppercase tracking-widest">Awaiting spatial inputs</p>
              </div>
            )}
        </div>
      </aside>

      <main ref={mainScrollRef} className="flex-1 overflow-y-auto custom-scrollbar bg-white scroll-smooth">
        {compareMode ? (
          <div className="min-h-screen p-10 lg:p-24 bg-white animate-in fade-in slide-in-from-bottom-10 duration-700">
             <div className="flex items-end justify-between mb-16 border-b border-slate-100 pb-16">
                <div>
                   <h2 className="text-7xl font-black tracking-tighter text-slate-950 mb-4">Market Synthesis Matrix</h2>
                   <p className="text-slate-500 font-bold uppercase tracking-widest text-xs">Cross-Locality Revenue & Traffic Correlation</p>
                </div>
                <button onClick={() => setCompareMode(false)} className="p-4 bg-slate-100 hover:bg-slate-200 rounded-full text-slate-950"><X size={32}/></button>
             </div>

             <div className="bg-white rounded-[4rem] border border-slate-100 shadow-2xl overflow-hidden overflow-x-auto custom-scrollbar">
                <table className="w-full text-left border-collapse min-w-[1200px]">
                   <thead>
                      <tr className="bg-slate-50/50">
                         <th className="p-12 text-[10px] font-black uppercase text-slate-400 border-b border-slate-100 tracking-[0.3em]">Metric Layer</th>
                         {history.filter(i => selectedIds.includes(i.id)).map(item => (
                            <th key={item.id} className="p-12 text-2xl font-black text-slate-950 border-b border-slate-100">
                               {item.localityName.split(',')[0]}
                               <div className="text-[10px] text-indigo-600 mt-2 uppercase tracking-widest">{item.originalInput.category}</div>
                            </th>
                         ))}
                      </tr>
                   </thead>
                   <tbody className="divide-y divide-slate-100">
                      <tr>
                         <td className="p-12 text-xs font-black uppercase text-slate-500 tracking-widest">Monthly Revenue</td>
                         {history.filter(i => selectedIds.includes(i.id)).map(item => (
                            <td key={item.id} className="p-12 text-3xl font-black text-indigo-600">{formatCurrency(item.revenueProjections.monthly)}</td>
                         ))}
                      </tr>
                      <tr>
                         <td className="p-12 text-xs font-black uppercase text-slate-500 tracking-widest">Daily Footfall</td>
                         {history.filter(i => selectedIds.includes(i.id)).map(item => (
                            <td key={item.id} className="p-12 text-2xl font-black text-slate-900">{item.metrics.footfallEstimate.daily.toLocaleString()}</td>
                         ))}
                      </tr>
                      <tr>
                         <td className="p-12 text-xs font-black uppercase text-slate-500 tracking-widest">Economy Tier</td>
                         {history.filter(i => selectedIds.includes(i.id)).map(item => (
                            <td key={item.id} className="p-12 text-xl font-black text-slate-600">{item.demographics.socioeconomicTier}</td>
                         ))}
                      </tr>
                   </tbody>
                </table>
             </div>
          </div>
        ) : (
          <div className="flex flex-col">
            {/* Map Section */}
            <section className="relative w-full h-[calc(100vh-64px)] bg-slate-950 overflow-hidden flex-shrink-0">
              <div ref={mapContainer} className="w-full h-full" />

              {/* 3D Controls */}
              <div className="absolute bottom-12 right-12 z-30 flex flex-col gap-4 pointer-events-auto">
                <div className="bg-slate-950/80 backdrop-blur-3xl border border-white/10 p-6 rounded-[2.5rem] shadow-2xl space-y-6 w-64 text-white">
                  <div className="flex items-center justify-between">
                    <span className="text-[10px] font-black uppercase tracking-widest text-white/40">Spatial Perspective</span>
                    <button onClick={resetCamera} className="p-2 hover:bg-white/10 rounded-xl text-white/60 transition-all"><RotateCcw size={14} /></button>
                  </div>
                  <div className="space-y-4">
                    <button 
                      onClick={toggle3D}
                      className={`w-full py-4 rounded-2xl flex items-center justify-center gap-3 transition-all border font-black text-[10px] uppercase tracking-widest ${is3D ? 'bg-indigo-600 border-indigo-400 text-white' : 'bg-white/5 border-white/10 text-white/40'}`}
                    >
                      <Box size={14} /> {is3D ? '3D Active' : 'Enable 3D'}
                    </button>
                    <div className="space-y-2">
                      <div className="flex justify-between text-[9px] font-black text-white/30 uppercase tracking-widest"><span>Tilt</span><span className="text-indigo-400">{Math.round(pitch)}°</span></div>
                      <input type="range" min="0" max="85" value={pitch} onChange={(e) => handlePitchChange(Number(e.target.value))} className="w-full h-1 bg-white/10 rounded-lg appearance-none cursor-pointer accent-indigo-500" />
                    </div>
                    <div className="space-y-2">
                      <div className="flex justify-between text-[9px] font-black text-white/30 uppercase tracking-widest"><span>Rotation</span><span className="text-indigo-400">{Math.round(bearing)}°</span></div>
                      <input type="range" min="-180" max="180" value={bearing} onChange={(e) => handleBearingChange(Number(e.target.value))} className="w-full h-1 bg-white/10 rounded-lg appearance-none cursor-pointer accent-indigo-500" />
                    </div>
                  </div>
                </div>
              </div>

              {/* Dynamic Recon Panel */}
              <div className="absolute inset-y-0 left-0 z-40 w-full max-w-5xl p-10 flex flex-col justify-center pointer-events-none">
                <div 
                  className={`pointer-events-auto bg-slate-950/70 backdrop-blur-3xl p-12 rounded-[4rem] border border-white/10 shadow-2xl space-y-10 text-white transition-all duration-700 ease-in-out overflow-hidden ${isPanelExpanded ? 'w-[750px]' : 'w-[500px]'}`}
                >
                  <div className="flex items-center justify-between border-b border-white/10 pb-6">
                    <h3 className="text-[10px] font-black uppercase tracking-[0.5em] text-white/40 flex items-center gap-3">
                      <Target size={14} className="text-indigo-400" /> Site Recon Panel
                    </h3>
                    {(isSearchingLocality || loading) && <Loader2 size={16} className="animate-spin text-indigo-400" />}
                  </div>

                  <div className="space-y-8 max-h-[60vh] overflow-y-auto custom-scrollbar pr-4">
                    <div className="relative">
                      <label className="block text-[10px] font-black text-white/30 mb-4 uppercase tracking-[0.2em] flex items-center justify-between">Target Locality {userLocation && <span className="text-[8px] text-indigo-400 animate-pulse">PROXIMITY ENABLED</span>}</label>
                      <div className="relative group/input">
                        <Search className="absolute left-6 top-1/2 -translate-y-1/2 text-white/20" size={20} />
                        <input 
                          type="text" 
                          value={input.location} 
                          onChange={(e) => handleLocalityChange(e.target.value)}
                          onKeyDown={handleKeyDown}
                          onFocus={() => { setIsPanelExpanded(true); if (input.location.length > 1) setShowSuggestions(true); }}
                          onClick={(e) => e.stopPropagation()}
                          className="w-full bg-white/5 border border-white/10 rounded-[2rem] py-5 pl-16 pr-6 text-sm font-bold text-white outline-none focus:bg-white/10 transition-all placeholder:text-white/10"
                          placeholder="Search (e.g. Valsad, Surat, Mumbai)..."
                        />
                      </div>
                      {showSuggestions && (
                        <div className="absolute top-full left-0 right-0 mt-3 bg-slate-900/98 backdrop-blur-3xl border border-white/10 rounded-[2.5rem] overflow-hidden shadow-2xl z-50">
                          <div className="p-4 max-h-[300px] overflow-y-auto custom-scrollbar">
                            {suggestions.map((loc, i) => (
                              <button key={i} onClick={(e) => { e.stopPropagation(); handleSelectLocality(loc); }} onMouseEnter={() => setActiveIndex(i)} className={`w-full text-left p-5 rounded-3xl flex items-center gap-5 transition-all ${activeIndex === i ? 'bg-indigo-600 text-white shadow-xl' : 'text-white/40 hover:text-white/70'}`}>
                                <MapPin size={14} />
                                <div className="overflow-hidden flex-1">
                                  <span className="text-xs font-black block truncate">{loc.name}</span>
                                </div>
                              </button>
                            ))}
                          </div>
                        </div>
                      )}
                    </div>

                    <div className="grid grid-cols-3 gap-6">
                       <div className="space-y-3">
                          <label className="block text-[10px] font-black text-white/30 uppercase tracking-widest">Width (ft)</label>
                          <input type="number" value={input.length} onChange={(e) => setInput(p => ({...p, length: Number(e.target.value)}))} className="w-full bg-white/5 border border-white/10 rounded-2xl py-4 px-5 text-sm font-black text-white outline-none focus:bg-white/10" />
                       </div>
                       <div className="space-y-3">
                          <label className="block text-[10px] font-black text-white/30 uppercase tracking-widest">Depth (ft)</label>
                          <input type="number" value={input.breadth} onChange={(e) => setInput(p => ({...p, breadth: Number(e.target.value)}))} className="w-full bg-white/5 border border-white/10 rounded-2xl py-4 px-5 text-sm font-black text-white outline-none focus:bg-white/10" />
                       </div>
                       <div className="space-y-3">
                          <label className="block text-[10px] font-black text-white/30 uppercase tracking-widest">Levels</label>
                          <input type="number" min="1" max="10" value={input.floors} onChange={(e) => setInput(p => ({...p, floors: Number(e.target.value)}))} className="w-full bg-white/5 border border-white/10 rounded-2xl py-4 px-5 text-sm font-black text-white outline-none focus:bg-white/10" />
                       </div>
                    </div>

                    <div className="space-y-6 bg-white/5 p-8 rounded-[3rem] border border-white/5">
                      <div className="relative">
                        <label className="block text-[10px] font-black text-white/30 mb-4 uppercase tracking-widest flex items-center gap-2"><Settings2 size={12} className="text-indigo-400" /> Business Archetype</label>
                        <select 
                          value={input.category} 
                          onFocus={() => setIsPanelExpanded(true)}
                          onChange={(e) => setInput(p => ({...p, category: e.target.value as StoreCategory, extraDetails: {}}))} 
                          className="w-full bg-white/5 border border-white/10 rounded-[2rem] py-5 px-6 text-sm font-black text-white appearance-none cursor-pointer outline-none focus:bg-white/10"
                        >
                          {STORE_CATEGORIES.map(c => <option key={c} value={c} className="bg-slate-900">{c}</option>)}
                        </select>
                        <ChevronRight size={18} className="absolute right-6 top-[62%] -translate-y-1/2 rotate-90 text-white/20 pointer-events-none" />
                      </div>
                      <div className="space-y-6">
                        <div className="grid grid-cols-1 gap-4">
                          {CATEGORY_QUESTIONS[input.category].map((q) => (
                            <div key={q.key} className="flex items-center justify-between bg-white/5 px-6 py-4 rounded-3xl border border-white/5">
                              <span className="text-[10px] font-bold text-white/50">{q.label}</span>
                              {q.type === 'toggle' ? (
                                <button 
                                  onClick={(e) => { e.stopPropagation(); updateExtraDetail(q.key, !input.extraDetails?.[q.key]); }}
                                  className={`w-12 h-6 rounded-full transition-all relative ${input.extraDetails?.[q.key] ? 'bg-indigo-600' : 'bg-white/20'}`}
                                >
                                  <div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-all ${input.extraDetails?.[q.key] ? 'left-7' : 'left-1'}`} />
                                </button>
                              ) : (
                                <select 
                                  value={(input.extraDetails?.[q.key] as string) || ''}
                                  onChange={(e) => updateExtraDetail(q.key, e.target.value)}
                                  className="bg-transparent text-[10px] font-black text-indigo-400 outline-none"
                                >
                                  <option value="">Select...</option>
                                  {q.options?.map(opt => <option key={opt} value={opt} className="bg-slate-900">{opt}</option>)}
                                </select>
                              )}
                            </div>
                          ))}
                        </div>
                      </div>
                    </div>

                    <button 
                      onClick={handleAnalyze} 
                      disabled={loading || !input.location}
                      className="w-full bg-indigo-600 text-white py-6 rounded-[2.5rem] text-xs font-black uppercase tracking-[0.5em] hover:bg-indigo-700 transition-all shadow-2xl shadow-indigo-500/30 disabled:opacity-50"
                    >
                      {loading ? 'Synthesizing...' : 'Run Feasibility Sync'}
                    </button>
                  </div>
                </div>
              </div>

              <div className="absolute bottom-10 left-1/2 -translate-x-1/2 z-50 flex flex-col items-center gap-2 pointer-events-auto">
                <button 
                  onClick={scrollToResults}
                  className={`flex flex-col items-center gap-2 transition-all duration-700 ${currentResult ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-10 pointer-events-none'}`}
                >
                  <span className="text-[9px] font-black text-white/40 uppercase tracking-[0.5em] mb-2">Synthesis Available</span>
                  <div className="w-12 h-12 rounded-full bg-white/10 backdrop-blur-xl border border-white/20 flex items-center justify-center text-white hover:bg-white/20 hover:scale-110 transition-all animate-bounce shadow-2xl">
                    <ChevronDown size={24} />
                  </div>
                </button>
              </div>
            </section>

            {/* Results Section - sits below the map */}
            <div id="results-view" className="bg-white min-h-screen relative z-30 shadow-[0_-40px_100px_rgba(0,0,0,0.1)] rounded-t-[5rem]">
              <div className="p-10 lg:p-24 space-y-32">
                {currentResult ? (
                  <div className="space-y-32 animate-in fade-in slide-in-from-bottom-20 duration-1000">
                    <div className="flex flex-col lg:flex-row gap-16 items-end justify-between border-b border-slate-100 pb-24">
                       <div className="space-y-8 max-w-4xl">
                          <div className="flex items-center gap-4">
                            <span className="px-6 py-2.5 bg-slate-950 text-white rounded-full text-[10px] font-black uppercase tracking-[0.4em]">Report Generated</span>
                            <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest">{new Date(currentResult.timestamp).toLocaleTimeString()}</span>
                          </div>
                          <h2 className="text-[10rem] font-black tracking-tighter text-slate-950 leading-[0.75] mb-8">{currentResult.localityName.split(',')[0]}</h2>
                          <div className="flex flex-wrap items-center gap-10">
                             <div className="flex items-center gap-4 text-slate-400 font-black text-xs uppercase tracking-widest bg-slate-50 px-6 py-3 rounded-2xl border border-slate-100"><Layers size={18} className="text-indigo-600" /> {currentResult.originalInput.floors} Levels</div>
                             <div className="flex items-center gap-4 text-slate-400 font-black text-xs uppercase tracking-widest bg-slate-50 px-6 py-3 rounded-2xl border border-slate-100"><Maximize2 size={18} className="text-indigo-600" /> {currentResult.originalInput.length * currentResult.originalInput.breadth * currentResult.originalInput.floors} SQ FT</div>
                          </div>
                       </div>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-12">
                      <MetricCard title="Footfall Stream" value={currentResult.metrics.footfallEstimate.daily.toLocaleString()} Icon={Users} subtitle="Daily Flow" />
                      <MetricCard title="Affluence Index" value={`₹${currentResult.demographics.perCapitaIncome.toLocaleString()}`} Icon={CircleDollarSign} subtitle={currentResult.demographics.socioeconomicTier} />
                      <MetricCard title="Market Density" value={currentResult.demographics.populationDensity} Icon={Building2} subtitle="Built Context" />
                      <MetricCard title="Competition" value={currentResult.metrics.storeCompetition.length} Icon={ShoppingBag} subtitle="Direct Rivals" />
                    </div>

                    <div className="grid grid-cols-1 xl:grid-cols-2 gap-20">
                      <RevenueChart projections={currentResult.revenueProjections} />
                      <TrafficLandscape data={currentResult.metrics.footfallEstimate.hourlyDistribution} />
                    </div>

                    {/* Fix: Added grounding sources list as required by @google/genai guidelines */}
                    {currentResult.groundingSources.length > 0 && (
                      <div className="space-y-8">
                        <h3 className="text-xs font-black uppercase tracking-[0.4em] text-slate-400">Grounding Sources & Citations</h3>
                        <div className="flex flex-wrap gap-4">
                          {currentResult.groundingSources.map((source, idx) => (
                            <a 
                              key={idx} 
                              href={source.uri} 
                              target="_blank" 
                              rel="noopener noreferrer" 
                              className="flex items-center gap-3 px-6 py-3 bg-slate-50 border border-slate-100 rounded-2xl text-[10px] font-black text-slate-600 uppercase tracking-widest hover:bg-white hover:shadow-lg transition-all"
                            >
                              <ExternalLink size={14} className="text-indigo-600" />
                              {source.title}
                            </a>
                          ))}
                        </div>
                      </div>
                    )}
                  </div>
                ) : (
                  <div className="min-h-[80vh] flex flex-col items-center justify-center text-center p-20 opacity-30">
                    <Activity size={100} className="text-indigo-600 mb-8" />
                    <h3 className="text-5xl font-black text-slate-900 mb-4 tracking-tighter">Locality Processor Idle</h3>
                    <p className="text-xs text-slate-500 font-black uppercase tracking-[0.5em]">Calibrate Recon Panel to initiate synthesis</p>
                  </div>
                )}
              </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

export interface RevenueProjections {
  monthly: number;
  quarterly: number;
  yearly: number;
  currency: string;
}

export interface AreaDemographics {
  perCapitaIncome: number;
  socioeconomicTier: 'High' | 'Upper-Mid' | 'Mid' | 'Lower-Mid' | 'Economic';
  dominantCarTypes: string[];
  populationDensity: string;
  residentType: 'Residential' | 'Corporate' | 'Tourist' | 'Mixed';
}

export interface LocalityMetrics {
  footfallEstimate: {
    hourly: number;
    daily: number;
    peakTimes: string[];
    hourlyDistribution: { hour: number; traffic: number }[];
  };
  nearbyPOIs: {
    schools: number;
    premiumSchools: number;
    placesOfWorship: number;
    hotels: {
      luxury: number;
      midTier: number;
      budget: number;
    };
  };
  tourismProfile: string;
  storeCompetition: {
    type: string;
    avgPricePoint: string;
    count: number;
    description: string;
  }[];
}

export interface AnalysisResult {
  id: string;
  timestamp: number;
  localityName: string;
  demographics: AreaDemographics;
  metrics: LocalityMetrics;
  revenueProjections: RevenueProjections;
  strategicAdvice: string[];
  groundingSources: { title: string; uri: string }[];
  originalInput: StoreInput; 
}

export type PricingTier = 'Budget' | 'Mid-Range' | 'Premium' | 'Luxury';

export type StoreCategory = 
  | 'Premium Cafe (e.g., Starbucks)' 
  | 'Large Attraction (e.g., Zoo / Theme Park)' 
  | 'Supermarket (e.g., Reliance Fresh / DMart)' 
  | 'Luxury Fashion / Boutique' 
  | 'Pharmacy / Wellness' 
  | 'Fine Dining Restaurant' 
  | 'Workspace / Coworking' 
  | 'Quick Service Restaurant (QSR)'
  | 'Custom / Other';

export interface StoreInput {
  location: string;
  coordinates?: { lat: number; lng: number };
  category: StoreCategory;
  businessName?: string;
  businessDescription?: string; // Long-tail description
  pricingTier: PricingTier;
  skuCount: number; // Scale indicator
  avgOrderValue?: number;
  length: number; 
  breadth: number; 
  floors: number;
  heightPerFloor: number; 
  targetSegment: string[];
  extraDetails?: Record<string, string | boolean>;
}

import React, { useState, useEffect, useRef, useMemo, useCallback } from 'react';
import { 
  MapPin, Users, Sparkles, 
  Loader2, ExternalLink, LayoutGrid,
  CircleDollarSign, Building2,
  Globe, Home, Check, AlertCircle,
  Activity, ShoppingBag, Info, Compass, Target,
  History, X, ChevronRight, BarChart3, ArrowRightLeft,
  Trash2, PlusCircle, Maximize2, Menu, GraduationCap, Hotel, Landmark, Navigation, Search, Layers, Settings2, Box, RotateCcw, ChevronDown, 
  Coffee, Utensils, Zap, Briefcase, Pill, ShoppingCart, Ticket, Shirt, MoreHorizontal, IndianRupee, Hash
} from 'lucide-react';
import maplibregl from 'maplibre-gl';
import { StoreInput, AnalysisResult, StoreCategory, PricingTier } from './types';
import { GeminiService } from './services/geminiService';
import { MetricCard } from './components/MetricCard';
import { RevenueChart } from './components/RevenueChart';
import { TrafficLandscape } from './components/TrafficLandscape';

// Granular Archetypes for the Smart Search
const SMART_ARCHETYPES = [
  { label: 'Artisanal Specialty Coffee House', category: 'Premium Cafe (e.g., Starbucks)' as StoreCategory, tier: 'Premium' as PricingTier, icon: Coffee },
  { label: 'Budget Neighborhood Tea Stall / Tapri', category: 'Quick Service Restaurant (QSR)' as StoreCategory, tier: 'Budget' as PricingTier, icon: Coffee },
  { label: 'Mid-Tier Family Multi-Cuisine Restaurant', category: 'Fine Dining Restaurant' as StoreCategory, tier: 'Mid-Range' as PricingTier, icon: Utensils },
  { label: 'High-End Luxury Vegan Bistro', category: 'Fine Dining Restaurant' as StoreCategory, tier: 'Luxury' as PricingTier, icon: Utensils },
  { label: 'Discount Grocery Warehouse', category: 'Supermarket (e.g., Reliance Fresh / DMart)' as StoreCategory, tier: 'Budget' as PricingTier, icon: ShoppingCart },
  { label: 'Organic Premium Deli & Gourmet Store', category: 'Supermarket (e.g., Reliance Fresh / DMart)' as StoreCategory, tier: 'Premium' as PricingTier, icon: ShoppingCart },
  { label: 'Generic Local Pharmacy', category: 'Pharmacy / Wellness' as StoreCategory, tier: 'Mid-Range' as PricingTier, icon: Pill },
  { label: 'Premium Holistic Wellness Center', category: 'Pharmacy / Wellness' as StoreCategory, tier: 'Premium' as PricingTier, icon: Pill },
  { label: 'Artisanal Boutique Fashion Label', category: 'Luxury Fashion / Boutique' as StoreCategory, tier: 'Luxury' as PricingTier, icon: Shirt },
  { label: 'Corporate Tech Coworking Hub', category: 'Workspace / Coworking' as StoreCategory, tier: 'Premium' as PricingTier, icon: Briefcase },
  { label: 'Childrens Theme Park / Play Zone', category: 'Large Attraction (e.g., Zoo / Theme Park)' as StoreCategory, tier: 'Mid-Range' as PricingTier, icon: Ticket },
  { label: 'Fast Food Burger Joint', category: 'Quick Service Restaurant (QSR)' as StoreCategory, tier: 'Mid-Range' as PricingTier, icon: Zap },
];

const INITIAL_POS = { lat: 19.0596, lng: 72.8295 };

const App: React.FC = () => {
  const mapContainer = useRef<HTMLDivElement>(null);
  const map = useRef<maplibregl.Map | null>(null);
  const mainScrollRef = useRef<HTMLElement>(null);
  const searchTimeout = useRef<number | null>(null);

  const [loading, setLoading] = useState(false);
  const [history, setHistory] = useState<AnalysisResult[]>([]);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [compareMode, setCompareMode] = useState(false);
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [userLocation, setUserLocation] = useState<{ lat: number; lng: number } | null>(null);
  const [isPanelExpanded, setIsPanelExpanded] = useState(false);

  const [is3D, setIs3D] = useState(true);
  const [pitch, setPitch] = useState(60);
  const [bearing, setBearing] = useState(-20);

  // Locality Search State
  const [suggestions, setSuggestions] = useState<any[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [isSearchingLocality, setIsSearchingLocality] = useState(false);
  const [activeIndex, setActiveIndex] = useState(-1);

  // Business Archetype Search State
  const [archetypeQuery, setArchetypeQuery] = useState('');
  const [showArchetypeSuggestions, setShowArchetypeSuggestions] = useState(false);

  const [input, setInput] = useState<StoreInput>({
    location: '',
    coordinates: { ...INITIAL_POS },
    category: 'Premium Cafe (e.g., Starbucks)',
    pricingTier: 'Mid-Range',
    skuCount: 50,
    length: 40,
    breadth: 50,
    floors: 1,
    heightPerFloor: 12,
    targetSegment: ['Gen-Z Trendsetters', 'Young Professionals'],
    extraDetails: {}
  });

  const [currentResult, setCurrentResult] = useState<AnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  const getDistance = (lat1: number, lon1: number, lat2: number, lon2: number) => {
    const R = 6371;
    const dLat = (lat2 - lat1) * Math.PI / 180;
    const dLon = (lon2 - lon1) * Math.PI / 180;
    const a = Math.sin(dLat / 2) * Math.sin(dLat / 2) +
              Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) *
              Math.sin(dLon / 2) * Math.sin(dLon / 2);
    const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
    return R * c;
  };

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition((pos) => {
        const coords = { lat: pos.coords.latitude, lng: pos.coords.longitude };
        setUserLocation(coords);
        if (map.current) {
          map.current.flyTo({ center: [coords.lng, coords.lat], zoom: 12 });
        }
      }, () => console.log("Location access denied."));
    }
  }, []);

  useEffect(() => {
    if (!mapContainer.current) return;
    (maplibregl as any).workerCount = 0;
    const mapInstance = new maplibregl.Map({
      container: mapContainer.current!,
      style: 'https://tiles.basemaps.cartocdn.com/gl/dark-matter-gl-style/style.json',
      center: [INITIAL_POS.lng, INITIAL_POS.lat],
      zoom: 14,
      pitch: 60,
      bearing: -20,
      attributionControl: false,
    });
    mapInstance.on('load', () => {
      map.current = mapInstance;
      if (mapInstance.getSource('openmaptiles')) {
        mapInstance.addLayer({
          'id': '3d-buildings',
          'source': 'openmaptiles',
          'source-layer': 'building',
          'type': 'fill-extrusion',
          'minzoom': 15,
          'paint': {
            'fill-extrusion-color': '#4f46e5',
            'fill-extrusion-height': ['get', 'render_height'],
            'fill-extrusion-base': ['get', 'render_min_height'],
            'fill-extrusion-opacity': 0.6
          }
        });
      }
    });
    mapInstance.on('rotate', () => setBearing(mapInstance.getBearing()));
    mapInstance.on('pitch', () => setPitch(mapInstance.getPitch()));
    return () => mapInstance?.remove();
  }, []);

  const handleLocalityChange = (val: string) => {
    setInput(prev => ({ ...prev, location: val }));
    setShowSuggestions(true);
    setActiveIndex(-1);
    if (val.trim().length > 1) {
      if (searchTimeout.current) window.clearTimeout(searchTimeout.current);
      setIsSearchingLocality(true);
      searchTimeout.current = window.setTimeout(async () => {
        try {
          const response = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(val)}&countrycodes=in&limit=10`);
          const data = await response.json();
          let results = data.map((item: any) => ({
            name: item.display_name,
            lat: parseFloat(item.lat),
            lng: parseFloat(item.lon)
          }));
          if (userLocation) {
            results = results.sort((a: any, b: any) => {
              const distA = getDistance(userLocation.lat, userLocation.lng, a.lat, a.lng);
              const distB = getDistance(userLocation.lat, userLocation.lng, b.lat, b.lng);
              return distA - distB;
            });
          }
          setSuggestions(results);
        } catch (err) {
          setSuggestions([]);
        } finally {
          setIsSearchingLocality(false);
        }
      }, 400);
    } else {
      setSuggestions([]);
      setShowSuggestions(false);
    }
  };

  const archetypeSuggestions = useMemo(() => {
    if (!archetypeQuery) return SMART_ARCHETYPES.slice(0, 5);
    return SMART_ARCHETYPES.filter(a => 
      a.label.toLowerCase().includes(archetypeQuery.toLowerCase())
    );
  }, [archetypeQuery]);

  const handleSelectLocality = (loc: any) => {
    setInput(p => ({ ...p, location: loc.name, coordinates: { lat: loc.lat, lng: loc.lng } }));
    setShowSuggestions(false);
    setIsPanelExpanded(false);
    if (map.current) map.current.flyTo({ center: [loc.lng, loc.lat], zoom: 15.8, duration: 2000 });
  };

  const handleSelectArchetype = (a: typeof SMART_ARCHETYPES[0]) => {
    setInput(p => ({ 
      ...p, 
      category: a.category, 
      pricingTier: a.tier,
      businessDescription: a.label
    }));
    setArchetypeQuery(a.label);
    setShowArchetypeSuggestions(false);
  };

  const handleAnalyze = async () => {
    setLoading(true);
    setError(null);
    setIsPanelExpanded(false);
    try {
      const data = await GeminiService.analyzeMarket({
        ...input,
        businessDescription: input.businessDescription || archetypeQuery
      });
      const newResult: AnalysisResult = {
        ...data,
        id: crypto.randomUUID(),
        timestamp: Date.now(),
        originalInput: { ...input }
      };
      setHistory(prev => [newResult, ...prev]);
      setCurrentResult(newResult);
      setCompareMode(false);
      setTimeout(() => scrollToResults(), 500);
    } catch (err: any) {
      setError(err.message || 'Analysis failed.');
    } finally {
      setLoading(false);
    }
  };

  const resetCamera = () => {
    setPitch(60); setBearing(-20);
    if (map.current) { map.current.setPitch(60); map.current.setBearing(-20); }
  };
  const toggle3D = () => setIs3D(!is3D);
  const handlePitchChange = (val: number) => { setPitch(val); if (map.current) map.current.setPitch(val); };
  const handleBearingChange = (val: number) => { setBearing(val); if (map.current) map.current.setBearing(val); };

  const scrollToResults = () => {
    document.getElementById('results-view')?.scrollIntoView({ behavior: 'smooth', block: 'start' });
  };

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('en-IN', { style: 'currency', currency: 'INR', maximumFractionDigits: 0 }).format(val);
  };

  return (
    <div className="flex flex-col h-screen bg-slate-950 text-slate-900 overflow-hidden relative" onClick={() => { setShowSuggestions(false); setIsPanelExpanded(false); setShowArchetypeSuggestions(false); }}>
      <header className="h-16 bg-white/95 backdrop-blur-xl border-b border-slate-200 px-6 flex items-center justify-between z-[60] flex-shrink-0 sticky top-0">
        <div className="flex items-center gap-4">
          <button onClick={(e) => { e.stopPropagation(); setSidebarOpen(true); }} className="p-2.5 hover:bg-slate-100 rounded-xl text-slate-500 transition-all"><Menu size={20} /></button>
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-2 rounded-xl text-white shadow-lg shadow-indigo-200"><Sparkles size={18} /></div>
            <h1 className="font-black text-slate-900 tracking-tight text-xl">LocalityMind</h1>
          </div>
        </div>
        <div className="flex items-center gap-3">
          {selectedIds.length > 0 && (
            <button onClick={() => setCompareMode(!compareMode)} className={`flex items-center gap-2 px-5 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${compareMode ? 'bg-indigo-600 text-white' : 'bg-indigo-50 text-indigo-700 hover:bg-indigo-100'}`}>
              <ArrowRightLeft size={16} /> {compareMode ? 'Exit' : `Compare (${selectedIds.length})`}
            </button>
          )}
          <button onClick={handleAnalyze} disabled={loading} className="bg-slate-950 text-white px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest flex items-center gap-2 hover:bg-slate-800 transition-all">
            {loading ? <Loader2 size={16} className="animate-spin" /> : <Target size={16} />} Analyze
          </button>
        </div>
      </header>

      {sidebarOpen && <div className="fixed inset-0 bg-slate-950/40 backdrop-blur-sm z-[70]" onClick={() => setSidebarOpen(false)} />}
      <aside className={`fixed top-0 left-0 h-full w-96 bg-white shadow-2xl z-[80] transform transition-transform duration-500 flex flex-col ${sidebarOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="p-8 border-b border-slate-100 flex items-center justify-between">
            <span className="text-xs font-black uppercase tracking-[0.2em] text-slate-900">Synthesis Log</span>
            <button onClick={() => setSidebarOpen(false)} className="p-2 hover:bg-slate-100 rounded-xl text-slate-400"><X size={20} /></button>
        </div>
        <div className="flex-1 overflow-y-auto custom-scrollbar p-6 space-y-4">
            {history.map(item => (
                <div key={item.id} onClick={() => { setCurrentResult(item); setSidebarOpen(false); setCompareMode(false); }} className={`p-5 rounded-[2rem] border transition-all cursor-pointer ${currentResult?.id === item.id ? 'bg-indigo-50/50 border-indigo-200' : 'border-slate-100 hover:bg-slate-50'}`}>
                    <h4 className="text-sm font-black text-slate-900 truncate mb-1">{item.localityName}</h4>
                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{item.originalInput.businessDescription || item.originalInput.category}</p>
                    <div className="mt-4 flex items-center justify-between text-[10px] font-black">
                       <span className="text-indigo-600">{formatCurrency(item.revenueProjections.monthly)}/mo</span>
                       <span className="text-slate-300 uppercase">{new Date(item.timestamp).toLocaleDateString()}</span>
                    </div>
                </div>
            ))}
        </div>
      </aside>

      <main ref={mainScrollRef} className="flex-1 overflow-y-auto custom-scrollbar bg-white scroll-smooth">
        {!compareMode ? (
          <div className="flex flex-col">
            <section className="relative w-full h-[calc(100vh-64px)] bg-slate-950 overflow-hidden flex-shrink-0">
              <div ref={mapContainer} className="w-full h-full" />

              {/* 3D Map Perspective Hub */}
              <div className="absolute bottom-12 right-12 z-30 pointer-events-auto">
                <div className="bg-slate-950/90 backdrop-blur-3xl border border-white/10 p-6 rounded-[2.5rem] shadow-2xl space-y-6 w-64 text-white">
                  <div className="flex items-center justify-between">
                    <span className="text-[10px] font-black uppercase tracking-widest text-white/40">Spatial Matrix</span>
                    <button onClick={resetCamera} className="p-2 hover:bg-white/10 rounded-xl text-white/60 transition-all"><RotateCcw size={14} /></button>
                  </div>
                  <div className="space-y-4">
                    <button onClick={toggle3D} className={`w-full py-4 rounded-2xl flex items-center justify-center gap-3 transition-all border font-black text-[10px] uppercase tracking-widest ${is3D ? 'bg-indigo-600 border-indigo-400 text-white' : 'bg-white/5 border-white/10 text-white/40'}`}>
                      <Box size={14} /> {is3D ? '3D Node Active' : 'Engage 3D'}
                    </button>
                    <div className="space-y-2">
                      <div className="flex justify-between text-[9px] font-black text-white/30 uppercase tracking-widest"><span>Tilt</span><span className="text-indigo-400">{Math.round(pitch)}°</span></div>
                      <input type="range" min="0" max="85" value={pitch} onChange={(e) => handlePitchChange(Number(e.target.value))} className="w-full h-1 bg-white/10 rounded-lg appearance-none cursor-pointer accent-indigo-500" />
                    </div>
                  </div>
                </div>
              </div>

              {/* Enhanced Recon Panel */}
              <div className="absolute inset-y-0 left-0 z-40 w-full max-w-5xl p-10 flex flex-col justify-center pointer-events-none">
                <div className={`pointer-events-auto bg-slate-950/80 backdrop-blur-3xl p-12 rounded-[4rem] border border-white/10 shadow-2xl space-y-10 text-white transition-all duration-700 ease-in-out overflow-hidden ${isPanelExpanded ? 'w-[800px]' : 'w-[550px]'}`}>
                  <div className="flex items-center justify-between border-b border-white/10 pb-6">
                    <h3 className="text-[10px] font-black uppercase tracking-[0.5em] text-white/40 flex items-center gap-3"><Target size={14} className="text-indigo-400" /> Site Recon Panel</h3>
                    {(isSearchingLocality || loading) && <Loader2 size={16} className="animate-spin text-indigo-400" />}
                  </div>

                  <div className="space-y-8 max-h-[60vh] overflow-y-auto custom-scrollbar pr-4">
                    {/* Geolocation Input */}
                    <div className="relative">
                      <label className="block text-[10px] font-black text-white/30 mb-4 uppercase tracking-[0.2em] flex items-center justify-between">Target Locality {userLocation && <span className="text-[8px] text-indigo-400 animate-pulse tracking-widest">PROXIMITY SYNC</span>}</label>
                      <div className="relative group">
                        <Search className="absolute left-6 top-1/2 -translate-y-1/2 text-white/20" size={20} />
                        <input 
                          type="text" 
                          value={input.location} 
                          onChange={(e) => handleLocalityChange(e.target.value)}
                          onFocus={() => { setIsPanelExpanded(true); if (input.location.length > 1) setShowSuggestions(true); }}
                          onClick={(e) => e.stopPropagation()}
                          className="w-full bg-white/5 border border-white/10 rounded-[2rem] py-5 pl-16 pr-6 text-sm font-bold text-white outline-none focus:bg-white/10 transition-all"
                          placeholder="Search for a locality (e.g. Bandra, Surat)..."
                        />
                      </div>
                      {showSuggestions && (
                        <div className="absolute top-full left-0 right-0 mt-3 bg-slate-900 border border-white/10 rounded-[2.5rem] overflow-hidden shadow-2xl z-50">
                          <div className="p-4 max-h-[300px] overflow-y-auto custom-scrollbar">
                            {suggestions.map((loc, i) => (
                              <button key={i} onClick={(e) => { e.stopPropagation(); handleSelectLocality(loc); }} className="w-full text-left p-5 rounded-3xl flex items-center gap-5 transition-all hover:bg-indigo-600/20 text-white/40 hover:text-white">
                                <MapPin size={14} /> <span className="text-xs font-black block truncate">{loc.name}</span>
                              </button>
                            ))}
                          </div>
                        </div>
                      )}
                    </div>

                    {/* Smart Archetype Search */}
                    <div className="relative">
                      <label className="block text-[10px] font-black text-white/30 mb-4 uppercase tracking-[0.2em]">Business Model Archetype</label>
                      <div className="relative group">
                        <ShoppingBag className="absolute left-6 top-1/2 -translate-y-1/2 text-white/20" size={20} />
                        <input 
                          type="text" 
                          value={archetypeQuery} 
                          onChange={(e) => { setArchetypeQuery(e.target.value); setShowArchetypeSuggestions(true); }}
                          onFocus={() => { setIsPanelExpanded(true); setShowArchetypeSuggestions(true); }}
                          onClick={(e) => e.stopPropagation()}
                          className="w-full bg-white/5 border border-white/10 rounded-[2rem] py-5 pl-16 pr-6 text-sm font-bold text-white outline-none focus:bg-white/10 transition-all"
                          placeholder="Type model (e.g. Artisanal Cafe, Budget Supermarket)..."
                        />
                      </div>
                      {showArchetypeSuggestions && (
                        <div className="absolute top-full left-0 right-0 mt-3 bg-slate-900 border border-white/10 rounded-[2.5rem] overflow-hidden shadow-2xl z-50">
                          <div className="p-4 max-h-[350px] overflow-y-auto custom-scrollbar">
                            <p className="text-[8px] font-black text-white/20 uppercase tracking-[0.3em] px-4 mb-2">Refining Keyword Clusters</p>
                            {archetypeSuggestions.map((a, i) => (
                              <button key={i} onClick={(e) => { e.stopPropagation(); handleSelectArchetype(a); }} className="w-full text-left p-5 rounded-3xl flex items-center gap-5 transition-all hover:bg-indigo-600 text-white/50 hover:text-white group">
                                <a.icon size={16} className="text-white/20 group-hover:text-white/50" />
                                <div className="flex-1">
                                  <span className="text-xs font-black block truncate">{a.label}</span>
                                  <span className="text-[8px] font-bold opacity-40 uppercase tracking-widest">{a.category} • {a.tier}</span>
                                </div>
                              </button>
                            ))}
                            {archetypeSuggestions.length === 0 && (
                              <div className="p-8 text-center">
                                <p className="text-xs font-black text-white">Custom Entity: "{archetypeQuery}"</p>
                                <p className="text-[8px] font-bold text-indigo-400 uppercase mt-2">Model will infer spatial footprint based on description</p>
                              </div>
                            )}
                          </div>
                        </div>
                      )}
                    </div>

                    {/* Pricing Tier & Scale Controls */}
                    <div className="space-y-8 bg-white/5 p-8 rounded-[3rem] border border-white/5">
                      <div className="space-y-4">
                        <label className="block text-[10px] font-black text-white/30 uppercase tracking-widest flex items-center gap-2"><IndianRupee size={12} className="text-indigo-400" /> Pricing Matrix</label>
                        <div className="grid grid-cols-4 gap-3">
                          {(['Budget', 'Mid-Range', 'Premium', 'Luxury'] as PricingTier[]).map(t => (
                            <button 
                              key={t}
                              onClick={(e) => { e.stopPropagation(); setInput(p => ({ ...p, pricingTier: t })); }}
                              className={`py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest border transition-all ${input.pricingTier === t ? 'bg-indigo-600 border-indigo-400 text-white shadow-lg' : 'bg-white/5 border-white/10 text-white/20 hover:text-white/40'}`}
                            >
                              {t}
                            </button>
                          ))}
                        </div>
                      </div>

                      <div className="space-y-4">
                        <div className="flex justify-between items-center px-1">
                          <label className="text-[10px] font-black text-white/30 uppercase tracking-widest flex items-center gap-2"><Hash size={12} className="text-indigo-400" /> Inventory Scale (SKU Count)</label>
                          <span className="text-xs font-black text-indigo-400">{input.skuCount} Items</span>
                        </div>
                        <input 
                          type="range" min="1" max="1000" step="5" value={input.skuCount} 
                          onChange={(e) => setInput(p => ({ ...p, skuCount: Number(e.target.value) }))}
                          className="w-full h-1 bg-white/10 rounded-lg appearance-none cursor-pointer accent-indigo-500"
                        />
                      </div>

                      <div className="grid grid-cols-3 gap-6 pt-4 border-t border-white/5">
                         <div className="space-y-3">
                            <label className="block text-[10px] font-black text-white/30 uppercase tracking-widest">Width (ft)</label>
                            <input type="number" value={input.length} onChange={(e) => setInput(p => ({...p, length: Number(e.target.value)}))} className="w-full bg-white/5 border border-white/10 rounded-2xl py-4 px-5 text-sm font-black text-white outline-none" />
                         </div>
                         <div className="space-y-3">
                            <label className="block text-[10px] font-black text-white/30 uppercase tracking-widest">Depth (ft)</label>
                            <input type="number" value={input.breadth} onChange={(e) => setInput(p => ({...p, breadth: Number(e.target.value)}))} className="w-full bg-white/5 border border-white/10 rounded-2xl py-4 px-5 text-sm font-black text-white outline-none" />
                         </div>
                         <div className="space-y-3">
                            <label className="block text-[10px] font-black text-white/30 uppercase tracking-widest">Floors</label>
                            <input type="number" min="1" max="10" value={input.floors} onChange={(e) => setInput(p => ({...p, floors: Number(e.target.value)}))} className="w-full bg-white/5 border border-white/10 rounded-2xl py-4 px-5 text-sm font-black text-white outline-none" />
                         </div>
                      </div>
                    </div>

                    <button 
                      onClick={handleAnalyze} 
                      disabled={loading || !input.location}
                      className="w-full bg-indigo-600 text-white py-7 rounded-[2.5rem] text-xs font-black uppercase tracking-[0.6em] hover:bg-indigo-700 transition-all shadow-2xl shadow-indigo-500/20 active:scale-[0.98]"
                    >
                      {loading ? 'Synthesizing...' : 'Generate High-Fidelity Sync'}
                    </button>
                  </div>
                </div>
              </div>

              {/* Scroll To Results Indicator */}
              <div className="absolute bottom-10 left-1/2 -translate-x-1/2 z-50 flex flex-col items-center gap-2 pointer-events-auto">
                <button 
                  onClick={scrollToResults}
                  className={`flex flex-col items-center gap-2 transition-all duration-700 ${currentResult ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-10 pointer-events-none'}`}
                >
                  <span className="text-[9px] font-black text-white/40 uppercase tracking-[0.5em] mb-2">Analysis Synchronized</span>
                  <div className="w-12 h-12 rounded-full bg-white/10 backdrop-blur-xl border border-white/20 flex items-center justify-center text-white hover:bg-white/20 hover:scale-110 transition-all animate-bounce shadow-2xl"><ChevronDown size={24} /></div>
