                      </div>
                      {showSuggestions && (
                        <div className="absolute top-full left-0 right-0 mt-3 bg-slate-900 border border-white/10 rounded-[2.5rem] overflow-hidden shadow-2xl z-50">
                          <div className="p-4 max-h-[300px] overflow-y-auto custom-scrollbar">
                            {suggestions.map((loc, i) => (
                              <button key={i} onClick={(e) => { e.stopPropagation(); handleSelectLocality(loc); }} className="w-full text-left p-5 rounded-3xl flex items-center gap-5 transition-all hover:bg-indigo-600/20 text-white/40 hover:text-white">
                                <MapPin size={14} /> <span className="text-xs font-black block truncate">{loc.name}</span>
                              </button>
                            ))}
                          </div>
                        </div>
