export const CompetitionPanel: React.FC<CompetitionPanelProps> = ({ competition }) => {
  const [activeFilter, setActiveFilter] = useState<string>('All');

  // Extract unique types from the data to build the filter bar
  const uniqueTypes = useMemo(() => {
    const types = new Set(competition.map(c => c.type));
    return ['All', ...Array.from(types)];
  }, [competition]);

  // Filter the competition list based on user selection
  const filteredCompetition = useMemo(() => {
    if (activeFilter === 'All') return competition;
    return competition.filter(c => c.type === activeFilter);
  }, [competition, activeFilter]);

  return (
    <div className="bg-white p-12 rounded-[4rem] shadow-xl border border-slate-100 flex flex-col h-full space-y-10 animate-in fade-in slide-in-from-bottom-10 duration-1000">
      <div className="flex flex-col xl:flex-row xl:items-end justify-between gap-8">
        <div>
          <h3 className="text-xs font-black uppercase tracking-[0.4em] text-slate-400 mb-2 flex items-center gap-3">
            <Filter size={14} className="text-indigo-400" /> Competitive Landscape
          </h3>
          <p className="text-slate-500 text-sm font-semibold">Granular analysis of active rivals in the micro-market</p>
        </div>

        {/* Modern Pill Filter Bar */}
        <div className="flex flex-wrap gap-2">
          {uniqueTypes.map(type => (
            <button
              key={type}
              onClick={() => setActiveFilter(type)}
              className={`px-6 py-2.5 rounded-full text-[9px] font-black uppercase tracking-widest transition-all border ${
                activeFilter === type 
                ? 'bg-indigo-600 border-indigo-400 text-white shadow-lg shadow-indigo-200' 
                : 'bg-slate-50 border-slate-200 text-slate-400 hover:bg-slate-100'
              }`}
            >
              {type}
            </button>
          ))}
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 2xl:grid-cols-3 gap-8">
        {filteredCompetition.map((item, idx) => (
          <div key={idx} className="group p-8 rounded-[3rem] border border-slate-100 bg-slate-50/50 hover:bg-white hover:shadow-2xl transition-all duration-500">
            <div className="flex justify-between items-start mb-8">
              <div className="p-4 bg-white rounded-[1.5rem] border border-slate-100 text-indigo-600 shadow-sm group-hover:scale-110 transition-transform duration-500">
                <ShoppingBag size={24} />
              </div>
              <div className="flex flex-col items-end">
                <span className="px-5 py-2 bg-indigo-50 text-indigo-700 text-[9px] font-black uppercase tracking-widest rounded-full border border-indigo-100">
                  {item.count} Active Units
                </span>
              </div>
            </div>

            <h4 className="text-xl font-black text-slate-900 mb-3 tracking-tight">{item.type}</h4>
            <p className="text-xs text-slate-500 font-medium leading-relaxed mb-10 h-12 overflow-hidden line-clamp-3">
              {item.description}
            </p>

            <div className="flex items-center justify-between pt-8 border-t border-slate-100/50">
               <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Avg Price Point</span>
               <span className="text-sm font-black text-slate-900 group-hover:text-indigo-600 transition-colors">
                 {item.avgPricePoint}
               </span>
            </div>
          </div>
        ))}

        {filteredCompetition.length === 0 && (
          <div className="col-span-full py-32 text-center opacity-20 flex flex-col items-center">
            <Info size={60} className="mb-6" />
            <h4 className="text-xl font-black uppercase tracking-widest">No matching rivals found</h4>
            <p className="text-xs font-bold mt-2">Try clearing your filters to see the full landscape</p>
          </div>
        )}
      </div>
    </div>
  );
};

